/**
 * Delete a volume/issue (unassigns papers first)
 */
export async function deleteVolumeIssue(id: number): Promise<ActionResponse> {
    try {
        return await db.transaction(async (tx) => {
            // 1. Unassign all papers
            await tx.delete(publications).where(eq(publications.issueId, id));
            await tx.update(submissions)
                .set({ issueId: null, status: 'accepted' })
                .where(eq(submissions.issueId, id));

            // 2. Delete issue
            await tx.delete(volumesIssues).where(eq(volumesIssues.id, id));

            return { success: true };
        });
    } catch (error: any) {
        return { success: false, error: "Failed to delete: " + error.message };
    } finally {
        revalidatePath('/admin/publications');
    }
}

"use server";

import { razorpay } from "@/lib/razorpay";
import crypto from "crypto";
import { db } from "@/lib/db";
import { payments, submissions, settings, userProfiles, users, submissionVersions } from "@/db/schema";
import { eq, desc } from "drizzle-orm";
import { revalidatePath } from "next/cache";
import { sendEmail, emailTemplates } from "@/lib/mail";

type CreateOrderResponse =
    | { success: true; order: { id: string; amount: number; currency: string; key: string | undefined } }
    | { success: false; error: string };

export async function createRazorpayOrder(submissionId: number, paperId: string): Promise<CreateOrderResponse> {
    try {
        // 1. Fetch APC amount from settings
        const settingsRows = await db.select()
            .from(settings)
            .where(eq(settings.settingKey, "apc_inr"))
            .limit(1);
        
        const amountInINR = settingsRows[0]?.settingValue || '2500';
        const amount = parseInt(amountInINR) * 100; // Razorpay expects amount in paise

        // 2. Create Razorpay order
        const options = {
            amount: amount,
            currency: "INR",
            receipt: `receipt_${paperId}_${Date.now()}`,
            notes: {
                submission_id: submissionId,
                paper_id: paperId
            }
        };

        const order = await razorpay.orders.create(options);

        // 3. Create/Update payment record in DB with the Razorpay order ID
        const existingPayments = await db.select()
            .from(payments)
            .where(eq(payments.submissionId, submissionId))
            .limit(1);
 
        if (existingPayments.length > 0) {
            await db.update(payments)
                .set({ 
                    transactionId: order.id, 
                    currency: 'INR', 
                    amount: amountInINR 
                })
                .where(eq(payments.submissionId, submissionId));
        } else {
            await db.insert(payments).values({
                submissionId: submissionId,
                amount: amountInINR,
                currency: 'INR',
                status: 'pending',
                transactionId: order.id
            });
        }

        return {
            success: true,
            order: {
                id: order.id,
                amount: order.amount as number,
                currency: order.currency,
                key: process.env.RAZORPAY_KEY_ID
            }
        };
    } catch (error: any) {
        console.error("Create Razorpay Order Error:", error);
        return { success: false, error: "Failed to create payment order: " + error.message };
    }
}

export async function verifyRazorpayPayment(data: {
    razorpay_order_id: string;
    razorpay_payment_id: string;
    razorpay_signature: string;
    submissionId: number;
}) {
    try {
        const { razorpay_order_id, razorpay_payment_id, razorpay_signature, submissionId } = data;

        // 1. Verify Signature
        const secret = process.env.RAZORPAY_KEY_SECRET || '';
        const generated_signature = crypto
            .createHmac("sha256", secret)
            .update(razorpay_order_id + "|" + razorpay_payment_id)
            .digest("hex");

        if (generated_signature !== razorpay_signature) {
            return { success: false, error: "Invalid payment signature" };
        }

        // 2. Update Payment Status in DB
        await db.update(payments)
            .set({ 
                status: 'paid', 
                transactionId: razorpay_payment_id, 
                paidAt: new Date() 
            })
            .where(eq(payments.submissionId, submissionId));
 
        // 3. Update Submission Status
        await db.update(submissions)
            .set({ status: 'payment_pending' }) // Should be accepted or payment_pending? Flow says payment_pending -> paid -> published
            .where(eq(submissions.id, submissionId));

        // 4. Notify Author
        try {
            const subData = await db.select({
                authorName: userProfiles.fullName,
                authorEmail: users.email,
                title: submissionVersions.title,
                paperId: submissions.paperId
            })
            .from(submissions)
            .innerJoin(users, eq(submissions.correspondingAuthorId, users.id))
            .innerJoin(userProfiles, eq(users.id, userProfiles.userId))
            .innerJoin(submissionVersions, eq(submissions.id, submissionVersions.submissionId))
            .where(eq(submissions.id, submissionId))
            .orderBy(desc(submissionVersions.versionNumber))
            .limit(1);

            const sub = subData[0];
            if (sub) {
                const template = emailTemplates.paymentVerified(sub.authorName, sub.title, sub.paperId);
                await sendEmail({
                    to: sub.authorEmail,
                    subject: template.subject,
                    html: template.html
                });
            }
        } catch (emailErr) {
            console.error("Failed to send payment verification email:", emailErr);
        }

        revalidatePath('/track');
        revalidatePath('/admin');
        revalidatePath('/reviewer');
        revalidatePath('/editor');

        return { success: true };
    } catch (error: any) {
        console.error("Verify Razorpay Payment Error:", error);
        return { success: false, error: "Failed to verify payment: " + error.message };
    }
}

"use server";

import { z } from "zod";
import { db } from "@/lib/db";
import { 
    applications, 
    applicationInterests, 
    masterInterests 
} from "@/db/schema";
import { ActionResponse } from "@/db/types";
import { writeFile, mkdir } from "fs/promises";
import path from "path";
import { sendEmail } from "@/lib/mail";
import { safeDeleteFile } from "@/lib/fs-utils";
import { eq } from "drizzle-orm";

const schema = z.object({
    fullName: z.string().min(2),
    designation: z.string().min(2),
    institute: z.string().min(2),
    email: z.string().email(),
    application_type: z.enum(['reviewer', 'editor']).default('reviewer'),
    nationality: z.string().min(2),
});

export async function submitReviewerApplication(formData: FormData): Promise<ActionResponse> {
    const fullName = formData.get("fullName") as string;
    const designation = formData.get("designation") as string;
    const institute = formData.get("institute") as string;
    const email = formData.get("email") as string;
    const application_type = formData.get("application_type") as string;
    const nationality = formData.get("nationality") as string;
    const cv = formData.get("cv") as File;
    const photo = formData.get("photo") as File;
    const researchInterestsStr = formData.get("research_interests") as string;

    // Validate textual data
    const validation = schema.safeParse({ fullName, designation, institute, email, application_type, nationality });
    if (!validation.success) {
        return { success: false, error: "Please fill in all required fields correctly." };
    }

    // Validate files
    if (!cv || cv.size === 0) return { success: false, error: "Please upload your CV." };
    if (!photo || photo.size === 0) return { success: false, error: "Please upload your Photo." };

    let cvUrl: string | null = null;
    let photoUrl: string | null = null;

    try {
        // Save files to public/uploads
        const uploadsDir = path.join(process.cwd(), "public", "uploads", "reviewer-apps");
        await mkdir(uploadsDir, { recursive: true });

        const cvName = `${Date.now()}-${cv.name.replace(/\s/g, '-')}`;
        const photoName = `${Date.now()}-${photo.name.replace(/\s/g, '-')}`;

        await writeFile(path.join(uploadsDir, cvName), Buffer.from(await cv.arrayBuffer()));
        await writeFile(path.join(uploadsDir, photoName), Buffer.from(await photo.arrayBuffer()));

        cvUrl = `/uploads/reviewer-apps/${cvName}`;
        photoUrl = `/uploads/reviewer-apps/${photoName}`;

        // Save to Database
        const applicationId = await db.transaction(async (tx) => {
            const [insertedApp] = await tx.insert(applications).values({
                fullName,
                designation,
                institute,
                email,
                cvUrl,
                photoUrl,
                type: application_type as 'reviewer' | 'editor',
                nationality,
                status: 'pending'
            }).$returningId();

            const appId = insertedApp.id;

            // Persist Normalized Research Interests
            if (researchInterestsStr && appId) {
                try {
                    const interests = JSON.parse(researchInterestsStr) as string[];
                    if (Array.isArray(interests) && interests.length > 0) {
                    // Normalized Interests Insertion
                    for (const name of interests) {
                        const trimmedName = name.trim();
                        if (!trimmedName) continue;

                        let interestId: number;
                        const existing = await tx.select().from(masterInterests).where(eq(masterInterests.name, trimmedName)).limit(1);
                        
                        if (existing[0]) {
                            interestId = existing[0].id;
                        } else {
                            const [inserted] = await tx.insert(masterInterests).values({ name: trimmedName }).$returningId();
                            interestId = inserted.id;
                        }

                        await tx.insert(applicationInterests).values({
                            applicationId: appId,
                            interestId: interestId
                        });
                    }
                    }
                } catch (pErr) {
                    console.error("Error parsing/saving interests:", pErr);
                }
            }
            return appId;
        });

        // Notify Admin via Email
        const adminUrl = `${process.env.NEXT_PUBLIC_APP_URL || 'http://localhost:3000'}/admin/reviewer-applications`;
        const roleName = application_type === 'editor' ? 'Editor' : 'Reviewer';

        sendEmail({
            to: process.env.EMAIL_FROM || 'admin@ijitest.org', // Send to admin
            subject: `New ${roleName} Application: ${fullName}`,
            html: `
                <div style="font-family: sans-serif; padding: 20px;">
                    <h2>New ${roleName} Application</h2>
                    <p><strong>Name:</strong> ${fullName}</p>
                    <p><strong>Role:</strong> ${roleName}</p>
                    <p><strong>Institute:</strong> ${institute}</p>
                    <p><strong>Email:</strong> ${email}</p>
                    <p>Please review the application in the admin panel.</p>
                    <a href="${adminUrl}" style="background: #000; color: #fff; padding: 10px 20px; text-decoration: none; border-radius: 5px;">View Application</a>
                </div>
            `
        });

        // Confirmation to Applicant
        sendEmail({
            to: email,
            subject: `Application Received | IJITEST ${roleName} Board`,
            html: `
                <div style="font-family: serif; color: #1a1a1a; max-width: 600px; margin: 0 auto; padding: 40px; border: 1px solid #f0f0f0; border-radius: 20px;">
                    <div style="text-align: center; margin-bottom: 30px;">
                        <h1 style="color: #6d0202; margin-bottom: 10px;">IJITEST</h1>
                        <p style="color: #666; font-size: 14px; text-transform: ; letter-spacing: 0.2em;">${roleName} Board Application</p>
                    </div>
                    <p>Dear ${fullName},</p>
                    <p>Thank you for applying to join the ${application_type === 'editor' ? 'Editorial' : 'Review'} Board of <strong>IJITEST</strong>.</p>
                    <p>We have received your application and details. Our editorial team will review your profile and academic background.</p>
                    <p>You will receive a follow-up email regarding the status of your application within 24-48 hours.</p>
                    <div style="margin-top: 40px; border-top: 1px solid #eee; pt: 30px; text-align: center;">
                        <p style="color: #999; font-size: 11px;">International Journal of Innovative Trends in Engineering Science and Technology</p>
                    </div>
                </div>
            `
        });

        return { success: true };
    } catch (error: any) {
        console.error("Application Error:", error);

        // Rollback: Delete uploaded assets
        if (cvUrl) await safeDeleteFile(cvUrl);
        if (photoUrl) await safeDeleteFile(photoUrl);

        if (error.code === 'ER_DUP_ENTRY') {
            return { success: false, error: "An application with this email already exists for this role." };
        }
        return { success: false, error: "Failed to submit application. Please try again." };
    }
}

"use server";

import { db } from "@/lib/db";
import { sql, eq, and, desc, inArray, count } from "drizzle-orm";
import { revalidatePath } from "next/cache";
import fs from "fs/promises";
import path from "path";
import { sendEmail, emailTemplates } from "@/lib/mail";
import {
    reviewAssignments,
    reviews,
    submissions,
    submissionVersions,
    submissionFiles,
    submissionAuthors,
    users,
    userProfiles,
} from "@/db/schema";

import { convertDocxToPdf } from "@/lib/ilovepdf";

import { ActionResponse } from "@/db/types";

/**
 * Assign a reviewer to a submission.
 * Enforces a strict limit of 6 reviewers per submission.
 */
export async function assignReviewer(formData: FormData): Promise<ActionResponse> {
    const submissionId = parseInt(formData.get('submissionId') as string);
    const reviewerId = formData.get('reviewerId') as string;
    const deadline = formData.get('deadline') as string;
    const assignedBy = formData.get('assignedBy') as string;
    const pdfFile = formData.get('pdfFile') as File;

    try {
        return await db.transaction(async (tx) => {
            // 1. Max 6 reviewers check (Total assignments for this submission)
            const [totalAssignments] = await tx.select({ value: count() })
                .from(reviewAssignments)
                .where(eq(reviewAssignments.submissionId, submissionId));

            if ((totalAssignments?.value || 0) >= 6) {
                return { success: false, error: "Maximum of 6 reviewers have already been assigned to this submission." };
            }

            // 2. Duplicate check
            const existing = await tx.select()
                .from(reviewAssignments)
                .where(and(
                    eq(reviewAssignments.submissionId, submissionId), 
                    eq(reviewAssignments.reviewerId, reviewerId)
                ));

            if (existing.length > 0) {
                return { success: false, error: "This reviewer is already assigned to this submission." };
            }

            // 3. Conflict of interest check (Same institution)
            const [reviewerProfile] = await tx.select({ institute: userProfiles.institute })
                .from(userProfiles)
                .where(eq(userProfiles.userId, reviewerId))
                .limit(1);

            const [leadAuthor] = await tx.select({ institution: submissionAuthors.institution })
                .from(submissionAuthors)
                .where(and(
                    eq(submissionAuthors.submissionId, submissionId), 
                    eq(submissionAuthors.isCorresponding, true)
                ))
                .limit(1);

            if (reviewerProfile?.institute && leadAuthor?.institution && 
                reviewerProfile.institute.toLowerCase() === leadAuthor.institution.toLowerCase()) {
                return { success: false, error: "Conflict of interest: Reviewer and Author belong to the same institution." };
            }

            // 4. Version Check
            const latestVersions = await tx.select()
                .from(submissionVersions)
                .where(eq(submissionVersions.submissionId, submissionId))
                .orderBy(desc(submissionVersions.versionNumber))
                .limit(1);

            if (!latestVersions.length) return { success: false, error: "Submission version not found." };
            const version = latestVersions[0];

            // 5. PDF copy for reviewer
            let pdfUrl: string | null = null;
            const existingPdfs = await tx.select()
                .from(submissionFiles)
                .where(and(
                    eq(submissionFiles.versionId, version.id), 
                    eq(submissionFiles.fileType, 'pdf_version')
                ))
                .limit(1);

            if (pdfFile && pdfFile.size > 0) {
                const bytes = await pdfFile.arrayBuffer();
                const fileName = `reviewer_copy_${submissionId}_${Date.now()}.pdf`;
                const uploadPath = path.join(process.cwd(), "public/uploads/submissions", fileName);
                await fs.writeFile(uploadPath, Buffer.from(bytes));
                pdfUrl = `/uploads/submissions/${fileName}`;

                await tx.insert(submissionFiles).values({
                    versionId: version.id,
                    fileType: 'pdf_version',
                    fileUrl: pdfUrl,
                    originalName: 'reviewer_manuscript.pdf'
                });
            } else if (existingPdfs.length > 0) {
                pdfUrl = existingPdfs[0].fileUrl;
            } else {
                // Try to find the manuscript and ensure it's a PDF
                const manuscripts = await tx.select()
                    .from(submissionFiles)
                    .where(and(
                        eq(submissionFiles.versionId, version.id), 
                        eq(submissionFiles.fileType, 'main_manuscript')
                    ))
                    .limit(1);

                if (!manuscripts.length) return { error: "No manuscript file available." };
                const manuscript = manuscripts[0];

                if (manuscript.fileUrl.toLowerCase().endsWith('.pdf')) {
                    pdfUrl = manuscript.fileUrl;
                } else {
                    // Convert DOCX to PDF using iLovePDF
                    try {
                        const mPath = path.join(process.cwd(), "public", manuscript.fileUrl);
                        const mBuffer = await fs.readFile(mPath);
                        const pdfBuffer = await convertDocxToPdf(mBuffer, manuscript.originalName || "paper.docx");

                        const fileName = `converted_${submissionId}_${Date.now()}.pdf`;
                        const uploadPath = path.join(process.cwd(), "public/uploads/submissions", fileName);
                        await fs.writeFile(uploadPath, pdfBuffer);
                        pdfUrl = `/uploads/submissions/${fileName}`;

                        await tx.insert(submissionFiles).values({
                            versionId: version.id,
                            fileType: 'pdf_version',
                            fileUrl: pdfUrl,
                            originalName: 'system_converted_pdf.pdf'
                        });
                    } catch (convErr: any) {
                        return { success: false, error: "PDF Conversion failed. Please upload a PDF manually." };
                    }
                }
            }

            // 6. Record Assignment
            const roundRes = await tx.select({ max: sql<number>`MAX(review_round)` })
                .from(reviewAssignments)
                .where(eq(reviewAssignments.submissionId, submissionId));
            const reviewRound = (roundRes[0]?.max || 0) + 1;

            await tx.insert(reviewAssignments).values({
                submissionId,
                reviewerId,
                versionId: version.id,
                assignedBy,
                reviewRound,
                status: 'assigned',
                deadline: new Date(deadline),
                assignedAt: new Date(),
            });

            // 7. Update Submission Status
            await tx.update(submissions)
                .set({ status: 'under_review', updatedAt: new Date() })
                .where(eq(submissions.id, submissionId));

            // 8. Notifications
            const staff = await tx.select({ email: users.email, name: userProfiles.fullName })
                .from(users)
                .leftJoin(userProfiles, eq(users.id, userProfiles.userId))
                .where(eq(users.id, reviewerId))
                .limit(1);

            const paper = await tx.select({ paperId: submissions.paperId, title: submissionVersions.title })
                .from(submissions)
                .join(submissionVersions, eq(submissions.id, submissionVersions.submissionId))
                .where(eq(submissions.id, submissionId))
                .orderBy(desc(submissionVersions.versionNumber))
                .limit(1);

            if (staff[0]?.email) {
                const template = emailTemplates.reviewAssignment(
                    staff[0].name || "Reviewer",
                    paper[0].title,
                    deadline,
                    paper[0].paperId
                );
                await sendEmail({ to: staff[0].email, subject: template.subject, html: template.html });
            }

            revalidatePath('/admin/reviews');
            return { success: true };
        });
    } catch (error: any) {
        console.error("Assign Reviewer Error:", error);
        return { success: false, error: "Failed to assign reviewer: " + error.message };
    }
}

/**
 * Reviewer submits a completed review decision and comments.
 */
export async function submitReview(assignmentId: number, formData: FormData): Promise<ActionResponse> {
    const decision = formData.get('decision') as string;
    const commentsToAuthor = formData.get('commentsToAuthor') as string;
    const commentsToEditor = formData.get('commentsToEditor') as string;
    const score = formData.get('score') ? parseInt(formData.get('score') as string) : null;
    const confidence = formData.get('confidence') ? parseInt(formData.get('confidence') as string) : null;

    try {
        return await db.transaction(async (tx) => {
            // 1. Get Assignment Details
            const rows = await tx.select({
                submissionId: reviewAssignments.submissionId,
                paperId: submissions.paperId,
                title: submissionVersions.title,
                authorEmail: users.email,
                authorName: userProfiles.fullName
            })
            .from(reviewAssignments)
            .join(submissions, eq(reviewAssignments.submissionId, submissions.id))
            .join(submissionVersions, eq(reviewAssignments.versionId, submissionVersions.id))
            .join(users, eq(submissions.correspondingAuthorId, users.id))
            .leftJoin(userProfiles, eq(users.id, userProfiles.userId))
            .where(eq(reviewAssignments.id, assignmentId))
            .limit(1);

            if (!rows.length) throw new Error("Review assignment not found.");
            const info = rows[0];

            // 2. Insert/Update Review
            await tx.insert(reviews).values({
                assignmentId,
                decision,
                score,
                confidence,
                commentsToAuthor,
                commentsToEditor,
                submittedAt: new Date()
            }).onDuplicateKeyUpdate({
                set: {
                    decision,
                    score,
                    confidence,
                    commentsToAuthor,
                    commentsToEditor,
                    submittedAt: new Date()
                }
            });

            // 3. Update Assignment Status
            await tx.update(reviewAssignments)
                .set({ status: 'completed', respondedAt: new Date() })
                .where(eq(reviewAssignments.id, assignmentId));

            // 4. Decision Logic & Notifications
            if (decision === 'accept') {
                const admins = await tx.select({ email: users.email }).from(users).where(inArray(users.role, ['admin', 'editor']));
                await Promise.allSettled(admins.map(a => sendEmail({
                    to: a.email,
                    subject: `Review Decision (Accept): ${info.paperId}`,
                    html: `<p>A reviewer has recommended 'Accept' for paper ${info.paperId}.</p>`
                })));
            } else {
                const statusMap: Record<string, any> = {
                    minor_revision: 'revision_requested',
                    major_revision: 'revision_requested',
                    reject: 'rejected'
                };
                const newStatus = statusMap[decision];

                if (newStatus) {
                    await tx.update(submissions).set({ status: newStatus }).where(eq(submissions.id, info.submissionId));

                    const template = newStatus === 'rejected' 
                        ? emailTemplates.manuscriptRejection(info.authorName, info.title, info.paperId, commentsToAuthor)
                        : emailTemplates.resubmissionRequest(info.authorName, info.title, info.paperId, commentsToAuthor);

                    await sendEmail({ to: info.authorEmail, subject: template.subject, html: template.html });
                }
            }

            revalidatePath('/admin/reviews');
            revalidatePath('/reviewer/reviews');
            return { success: true };
        });
    } catch (error: any) {
        console.error("Submit Review Error:", error);
        return { success: false, error: error.message };
    }
}

/**
 * Fetch all review assignments with joined submission data.
 */
export async function getActiveReviews(reviewerId?: string): Promise<ActionResponse<any[]>> {
    try {
        const query = db.select({
            id: reviewAssignments.id,
            status: reviewAssignments.status,
            assignedAt: reviewAssignments.assignedAt,
            deadline: reviewAssignments.deadline,
            reviewRound: reviewAssignments.reviewRound,
            submissionId: reviewAssignments.submissionId,
            paperId: submissions.paperId,
            submissionStatus: submissions.status,
            title: submissionVersions.title,
            reviewerName: userProfiles.fullName,
            decision: reviews.decision,
            commentsToAuthor: reviews.commentsToAuthor,
            submittedAt: reviews.submittedAt,
            manuscriptPath: sql<string>`(SELECT f.file_url FROM submission_files f WHERE f.version_id = ${reviewAssignments.versionId} AND f.file_type = 'pdf_version' LIMIT 1)`,
            feedbackFilePath: sql<string>`(SELECT f.file_url FROM submission_files f WHERE f.version_id = ${reviewAssignments.versionId} AND f.file_type = 'review_feedback' LIMIT 1)`
        })
        .from(reviewAssignments)
        .join(submissions, eq(reviewAssignments.submissionId, submissions.id))
        .join(submissionVersions, eq(reviewAssignments.versionId, submissionVersions.id))
        .leftJoin(userProfiles, eq(reviewAssignments.reviewerId, userProfiles.userId))
        .leftJoin(reviews, eq(reviewAssignments.id, reviews.assignmentId))
        .orderBy(desc(reviewAssignments.assignedAt));

        const rows = reviewerId ? await query.where(eq(reviewAssignments.reviewerId, reviewerId)) : await query;
        return { success: true, data: rows };
    } catch (error: any) {
        console.error("Get Reviews Error:", error);
        return { success: false, error: error.message };
    }
}

/**
 * Get papers that are ready to be assigned to reviewers.
 */
export async function getUnassignedAcceptedPapers(): Promise<ActionResponse<any[]>> {
    try {
       // Papers that are in stages that require review
       const rows = await db.select({
            id: submissions.id,
            paperId: submissions.paperId,
            title: submissionVersions.title
       })
       .from(submissions)
       .join(submissionVersions, eq(submissions.id, submissionVersions.submissionId))
       .where(and(
           inArray(submissions.status, ['submitted', 'editor_assigned', 'under_review', 'revision_requested']),
           sql`${submissionVersions.versionNumber} = (SELECT MAX(v2.version_number) FROM submission_versions v2 WHERE v2.submission_id = ${submissions.id})`
       ));

        return { success: true, data: rows };
    } catch (error: any) {
        console.error("Get Unassigned Error:", error);
        return { success: false, error: error.message };
    }
}

"use server";

import { db } from "@/lib/db";
import { settings } from "@/db/schema";
import { revalidatePath } from "next/cache";
import fs from "fs/promises";
import path from "path";
import { ActionResponse } from "@/db/types";

const DEFAULT_SETTINGS: Record<string, string> = {
    journal_name: 'International Journal of Innovative Trends in Engineering Science and Technology',
    journal_short_name: 'IJITEST',
    issn_number: 'XXXX-XXXX',
    apc_inr: '2500',
    apc_usd: '50',
    support_email: 'editor@ijitest.org',
    support_phone: '+91 8919643590',
    office_address: 'Felix Academic Publications, Madhurawada, Visakhapatnam, AP, India',
    publisher_name: 'Felix Academic Publications',
    journal_website: 'https://ijitest.org',
    apc_description: 'APC covers SJIF impact evaluation, long-term hosting, indexing maintenance, and editorial handling. There are no submission or processing charges before acceptance.',
    template_url: '/docs/template.docx',
    copyright_url: '/docs/copyright-form.docx',
    is_promotion_active: 'true'
};

export async function getSettings(): Promise<ActionResponse<Record<string, string>>> {
    try {
        const rows = await db.select().from(settings);
        
        const result: Record<string, string> = { ...DEFAULT_SETTINGS };

        rows.forEach((row) => {
            if (row.settingValue) {
                result[row.settingKey] = row.settingValue;
            }
        });

        return { success: true, data: result };
    } catch (error: any) {
        console.error("Get Settings Error:", error);
        return { success: false, error: error.message };
    }
}

/**
 * Utility for Server Components to get raw settings directly.
 */
export async function getSettingsData(): Promise<Record<string, string>> {
    const res = await getSettings();
    return res.data || DEFAULT_SETTINGS;
}

export async function updateSettings(formData: FormData): Promise<ActionResponse> {
    try {
        const entries = Array.from(formData.entries());

        await db.transaction(async (tx) => {
            for (const [key, value] of entries) {
                if (key.startsWith('$')) continue; // Skip Next.js internal fields

                let finalValue: any = value;

                // Handle File Uploads (Template & Copyright Form)
                if (value instanceof File && value.size > 0) {
                    const bytes = await value.arrayBuffer();
                    const buffer = Buffer.from(bytes);

                    const fileExt = value.name.split('.').pop();
                    const fileName = `${key.replace(/_/g, '-')}.${fileExt}`;

                    const uploadDir = path.join(process.cwd(), "public/docs");
                    await fs.mkdir(uploadDir, { recursive: true });

                    const filePath = path.join(uploadDir, fileName);
                    await fs.writeFile(filePath, buffer);

                    finalValue = `/docs/${fileName}`;
                } else if (value instanceof File && value.size === 0) {
                    // Skip empty file uploads (preserving existing values)
                    continue;
                }

                // Standard checkbox handling or empty values
                if (finalValue === null || finalValue === undefined) {
                    finalValue = "";
                }

                await tx.insert(settings)
                    .values({
                        settingKey: key,
                        settingValue: String(finalValue),
                    })
                    .onDuplicateKeyUpdate({
                        set: { settingValue: String(finalValue) }
                    });
            }
        });

        revalidatePath('/admin/settings');
        revalidatePath('/', 'layout');
        revalidatePath('/guidelines');
        revalidatePath('/contact');
        revalidatePath('/about');
        
        return { success: true };
    } catch (error: any) {
        console.error("Update Settings Error:", error);
        return { success: false, error: "Failed to update settings: " + error.message };
    }
}

