    UserWithProfile,
    SubmissionFile,
    ReviewWithReviewer,
} from "@/db/types";
import { revalidatePath } from "next/cache";
import { sendEmail, emailTemplates } from "@/lib/mail";
import fs from 'fs/promises';
import path from 'path';
import { eq, desc, and } from "drizzle-orm";
import { getServerSession } from "next-auth/next";
import { authOptions } from "@/lib/auth";

/**
 * Fetch a unified submission object with all related data joined.
 * Resolves the structural mismatches between the legacy "flat" schema and the new normalized schema.
 */
export async function getSubmissionById(id: number): Promise<ActionResponse<SubmissionUI>> {
    try {
        // 1. Fetch Core Submission + Profile + Latest Version + Publication + Issue
        const submissionRows = await db.select({
            submission: submissions,
            author: users,
            authorProfile: userProfiles,
            issue: volumesIssues,
            publication: publications,
            payment: payments
        })
        .from(submissions)
        .where(eq(submissions.id, id))
        .leftJoin(users, eq(submissions.correspondingAuthorId, users.id))
        .leftJoin(userProfiles, eq(users.id, userProfiles.userId))
        .leftJoin(volumesIssues, eq(submissions.issueId, volumesIssues.id))
        .leftJoin(publications, eq(submissions.id, publications.submissionId))
        .leftJoin(payments, eq(submissions.id, payments.submissionId))
        .limit(1);

        const row = submissionRows[0];
        if (!row) return { success: false, error: "Submission not found" };

        // 2. Fetch Latest Version
        const versionRows = await db.select()
            .from(submissionVersions)
            .where(eq(submissionVersions.submissionId, id))
            .orderBy(desc(submissionVersions.versionNumber))
            .limit(1);

        const latestVersion = versionRows[0];

        // 3. Fetch Authors (Co-authors)
        const authors = await db.select()
            .from(submissionAuthors)
            .where(eq(submissionAuthors.submissionId, id))
            .orderBy(submissionAuthors.orderIndex);

        // 4. Fetch Review Assignments with Reviewer Profiles and Decisions
        const assignments = await db.select({
            ra: reviewAssignments,
            reviewer: users,
            profile: userProfiles,
            review: reviews
        })
        .from(reviewAssignments)
        .where(eq(reviewAssignments.submissionId, id))
        .leftJoin(users, eq(reviewAssignments.reviewerId, users.id))
        .leftJoin(userProfiles, eq(users.id, userProfiles.userId))
        .leftJoin(reviews, eq(reviewAssignments.id, reviews.assignmentId));

        // 5. Fetch Files for the Latest Version
        const files = latestVersion 
            ? await db.select().from(submissionFiles).where(eq(submissionFiles.versionId, latestVersion.id)) 
            : [];

        // 6. Map to Domain Types
        const typedAssignments: ReviewWithReviewer[] = assignments.map(a => ({
            ...a.ra,
            reviewer: { ...a.reviewer, profile: a.profile } as UserWithProfile,
            review: a.review
        }));

        const submissionData: SubmissionDetail = {
            ...row.submission,
            correspondingAuthor: { ...row.author, profile: row.authorProfile } as UserWithProfile,
            versions: latestVersion ? [{ ...latestVersion, files: files as SubmissionFile[] }] : [],
            authors,
            payment: row.payment,
            reviewAssignments: typedAssignments,
            issue: row.issue,
            publication: row.publication
        };

        // 7. Map to UI-Friendly Composite Object (Flat properties for historical compatibility)
        const mainManuscript = files.find(f => f.fileType === 'main_manuscript');
        const pdfVersion = files.find(f => f.fileType === 'pdf_version');
        const finalPdf = row.publication?.finalPdfUrl;

        const data: SubmissionUI = {
            ...submissionData,
            paper_id: submissionData.paperId,
            submitted_at: submissionData.submittedAt,
            updated_at: submissionData.updatedAt,
            title: latestVersion?.title || "Untitled Manuscript",
            abstract: latestVersion?.abstract || "",
            keywords: latestVersion?.keywords || "",
            file_path: mainManuscript?.fileUrl || "",
            pdf_url: finalPdf || pdfVersion?.fileUrl || "", // Priority: Published PDF > Review PDF
            author_name: submissionData.correspondingAuthor?.profile?.fullName || "Unknown Author",
            author_email: submissionData.correspondingAuthor?.email || "",
            co_authors: JSON.stringify(submissionData.authors.map(a => ({
                name: a.name, email: a.email, institution: a.institution
            }))),
            volume_number: submissionData.issue?.volumeNumber,
            issue_number: submissionData.issue?.issueNumber,
            start_page: submissionData.publication?.startPage,
            end_page: submissionData.publication?.endPage,
            issue_id: submissionData.issueId,
            latestVersion: latestVersion ? { ...latestVersion, files: files as SubmissionFile[] } : undefined,
            allFiles: files as SubmissionFile[],
            allReviews: typedAssignments,
        };

        return { success: true, data };
    } catch (error: any) {
        console.error("Get Submission Detail Error:", error);
        return { success: false, error: error.message };
    }
}

/**
 * Fetch all submissions formatted for Admin/Editor listing
 */
export async function getAllSubmissions(filters?: { status?: string }): Promise<ActionResponse<SubmissionUI[]>> {
    try {
        const query = db.select({ id: submissions.id }).from(submissions);
        if (filters?.status && filters.status !== 'all') {
            query.where(eq(submissions.status, filters.status as any));
        }
        query.orderBy(desc(submissions.submittedAt));

        const ids = await query;
        const results = await Promise.all(ids.map(async s => {
            const res = await getSubmissionById(s.id);
            return res.success ? res.data : null;
        }));

        const data = results.filter((s): s is SubmissionUI => s !== null);
        return { success: true, data };
    } catch (error: any) {
        console.error("Get All Submissions Error:", error);
        return { success: false, error: error.message };
    }
}

/**
 * Admin/Editor: Final accept/reject decision
 */
export async function decideSubmission(id: number, decision: 'accepted' | 'rejected'): Promise<ActionResponse> {
    try {
        const subRes = await getSubmissionById(id);
        if (!subRes.success || !subRes.data) return { success: false, error: subRes.error || "Submission not found" };
        const submission = subRes.data;

        const apcRows = await db.select().from(settings).where(eq(settings.settingKey, 'apc_inr')).limit(1);
        const apcAmount = apcRows[0]?.settingValue || '0';
        const apcCurrency = 'INR';

        await db.transaction(async (tx) => {
            const status = decision === 'accepted' ? 'accepted' : 'rejected';
            await tx.update(submissions).set({ status }).where(eq(submissions.id, id));

            if (decision === 'accepted' && parseFloat(apcAmount) > 0) {
                // Prepare payment record if not zero charge
                await tx.insert(payments).values({
                    submissionId: id,
                    amount: apcAmount,
                    currency: apcCurrency,
                    status: 'pending'
                }).onDuplicateKeyUpdate({ set: { status: 'pending' } });
            }

            const isFree = parseFloat(apcAmount) === 0;

            const template = decision === 'accepted' 
                ? emailTemplates.manuscriptAcceptance(submission.author_name, submission.title, submission.paperId, isFree)
                : emailTemplates.manuscriptRejection(submission.author_name, submission.title, submission.paperId, "Does not meet editorial criteria.");

            await sendEmail({ to: submission.author_email, subject: template.subject, html: template.html });
        });

        revalidatePath('/admin/submissions');
        revalidatePath(`/admin/submissions/${id}`);
        return { success: true };
    } catch (error: any) {
        return { success: false, error: "Failed to finalize decision: " + error.message };
    }
}

/**
 * Update submission status and notify author
 */
export async function updateSubmissionStatus(id: number, status: any): Promise<ActionResponse> {
    try {
        await db.update(submissions).set({ status }).where(eq(submissions.id, id));

        const subRes = await getSubmissionById(id);
        if (subRes.success && subRes.data) {
            const submission = subRes.data;
            const apcRows = await db.select().from(settings).where(eq(settings.settingKey, 'apc_inr')).limit(1);
            const isFree = (apcRows[0]?.settingValue || '0') === '0';

            const template = emailTemplates.statusUpdate(
                submission.author_name, 
                submission.title, 
                status, 
                submission.paperId,
                isFree
            );
            await sendEmail({ to: submission.author_email, subject: template.subject, html: template.html });
        }

        revalidatePath('/admin/submissions');
        revalidatePath(`/admin/submissions/${id}`);
        return { success: true };
    } catch (error: any) {
        return { success: false, error: "Failed to update status: " + error.message };
    }
}

/**
 * Request resubmission WITH comments
 */
export async function requestResubmissionWithComments(
    submissionId: number,
    comments: string,
    requestedBy: string
): Promise<ActionResponse> {
    try {
        const subRes = await getSubmissionById(submissionId);
        if (!subRes.success || !subRes.data) return { success: false, error: subRes.error || 'Submission not found' };
        const submission = subRes.data;

        await db.update(submissions)
            .set({ status: 'revision_requested' })
            .where(eq(submissions.id, submissionId));

        const emailData = emailTemplates.resubmissionRequest(
            submission.author_name,
            submission.title,
            submission.paperId,
            comments
        );
        await sendEmail({ to: submission.author_email, subject: emailData.subject, html: emailData.html });

        revalidatePath(`/admin/submissions/${submissionId}`);
        return { success: true };
    } catch (error: any) {
        return { success: false, error: error.message };
    }
}

/**
 * Permanent Delete (Full Cleanup)
 */
export async function deleteSubmission(id: number): Promise<ActionResponse> {
    try {
        const subRes = await getSubmissionById(id);
        if (!subRes.success || !subRes.data) return { success: false, error: subRes.error || "Submission not found" };
        const submission = subRes.data;

        // 1. Database cleanup
        await db.transaction(async (tx) => {
            // Cascade should handle versions, files, and authors, but we do it manually for extra safety
            await tx.delete(submissionAuthors).where(eq(submissionAuthors.submissionId, id));
            await tx.delete(payments).where(eq(payments.submissionId, id));
            await tx.delete(reviewAssignments).where(eq(reviewAssignments.submissionId, id));
            await tx.delete(submissions).where(eq(submissions.id, id));
        });

        // 2. File system cleanup
        for (const file of submission.allFiles) {
            try {
                await fs.unlink(path.join(process.cwd(), 'public', file.fileUrl));
            } catch { /* ignore */ }
        }

        revalidatePath('/admin/submissions');
        return { success: true };
    } catch (error: any) {
        return { success: false, error: "Failed to delete: " + error.message };
    }
}

/**
 * Admin/Editor: Upload a finalized PDF version of the manuscript
 */
export async function uploadManuscriptPdf(submissionId: number, formData: FormData): Promise<ActionResponse> {
    try {
        const session = await getServerSession(authOptions);
        if (!session?.user || !['admin', 'editor'].includes(session.user.role)) {
            return { success: false, error: "Unauthorized" };
        }

        const pdfFile = formData.get("pdfFile") as File;
        if (!pdfFile || pdfFile.size === 0) return { success: false, error: "PDF file is required." };

        // 1. Get Latest Version
        const versionRows = await db.select()
            .from(submissionVersions)
            .where(eq(submissionVersions.submissionId, submissionId))
            .orderBy(desc(submissionVersions.versionNumber))
            .limit(1);

        if (!versionRows.length) return { success: false, error: "No version records found for this submission." };
        const latestVersion = versionRows[0];

        // 2. Prepare File Path
        const timestamp = Date.now();
        const fileName = `final_manuscript_${submissionId}_v${latestVersion.versionNumber}_${timestamp}.pdf`;
        const fileUrl = `/uploads/submissions/${fileName}`;
        const uploadDir = path.join(process.cwd(), "public/uploads/submissions");

        // 3. Database Update (Insert File Record)
        await db.transaction(async (tx) => {
            // Check if a PDF version already exists for this version
            const existing = await tx.select().from(submissionFiles).where(and(
                eq(submissionFiles.versionId, latestVersion.id),
                eq(submissionFiles.fileType, 'pdf_version')
            )).limit(1);

            if (existing.length > 0) {
                await tx.delete(submissionFiles).where(eq(submissionFiles.id, existing[0].id));
            }

            await tx.insert(submissionFiles).values({
                versionId: latestVersion.id,
                fileType: 'pdf_version',
                fileUrl: fileUrl,
                originalName: pdfFile.name,
                fileSize: pdfFile.size
            });

            await tx.update(submissions).set({ updatedAt: new Date() }).where(eq(submissions.id, submissionId));
        });

        // 4. File System Operation
        await fs.mkdir(uploadDir, { recursive: true });
        await fs.writeFile(path.join(uploadDir, fileName), Buffer.from(await pdfFile.arrayBuffer()));

        revalidatePath(`/admin/submissions/${submissionId}`);
        revalidatePath('/admin/submissions');

        return { success: true };
    } catch (error: any) {
        console.error("Upload PDF Error:", error);
        return { success: false, error: "Failed to upload PDF: " + error.message };
    }
}

"use server";

import { db } from "@/lib/db";
import {
    submissions,
    submissionFiles,
    submissionVersions,
    submissionAuthors,
    users,
    userProfiles
} from "@/db/schema";
import { z } from "zod";
import fs from "fs/promises";
import path from "path";
import { revalidatePath } from "next/cache";
import { sendEmail, emailTemplates } from "@/lib/mail";
import { count, eq, inArray } from "drizzle-orm";
import crypto from 'crypto';
import { ActionResponse } from "@/db/types";

const submissionSchema = z.object({
    author_name: z.string().min(2, "Author name is required"),
    author_email: z.string().email("Invalid email address"),
    author_phone: z.string().regex(/^[0-9]+$/, "Author phone must contain only numbers"),
    author_designation: z.string().min(2, "Author designation is required"),
    affiliation: z.string().min(2, "Affiliation is required"),
    title: z.string().min(10, "Title must be at least 10 characters"),
    abstract: z.string().min(50, "Abstract must be at least 50 characters"),
    keywords: z.string().min(5, "Keywords are required"),
    co_authors: z.string().optional(),
    terms_accepted: z.string().refine(val => val === "on", {
        message: "You must accept the terms and guidelines"
    }),
});

/**
 * Handles new manuscript submission with transactional DB-first logic.
 * Ensures data integrity by saving DB records before attempting file uploads.
 */
export async function submitPaper(formData: FormData): Promise<ActionResponse<{ paperId: string }>> {
    const fileCleanupList: string[] = [];
    let invitationToken: string | null = null;
    let submissionToCleanup: number | null = null;

    try {
        // 1. Validation
        const rawData = {
            author_name: formData.get("author_name") as string,
            author_email: formData.get("author_email") as string,
            author_phone: formData.get("author_phone") as string,
            author_designation: formData.get("author_designation") as string,
            affiliation: formData.get("affiliation") as string,
            title: formData.get("title") as string,
            abstract: formData.get("abstract") as string,
            keywords: formData.get("keywords") as string,
            co_authors: formData.get("co_authors") as string,
            terms_accepted: formData.get("terms_accepted") as string,
        };

        const validated = submissionSchema.safeParse(rawData);
        if (!validated.success) return { success: false, error: validated.error.issues[0].message };

        const manuscriptFile = formData.get("manuscript") as File;
        const copyrightFile = formData.get("copyright_form") as File;
        if (!manuscriptFile || manuscriptFile.size === 0) return { success: false, error: "Manuscript file is mandatory" };
        if (!copyrightFile || copyrightFile.size === 0) return { success: false, error: "Copyright form is mandatory" };

        // 2. Transactional Database Operations (Save everything BUT don't upload files yet)
        const result = await db.transaction(async (tx) => {
            // A. User/Author Account Management
            const existingUsers = await tx.select().from(users).where(eq(users.email, validated.data.author_email)).limit(1);
            let userId: string;

            if (existingUsers.length === 0) {
                userId = crypto.randomUUID();
                invitationToken = crypto.randomBytes(32).toString('hex');
                const expires = new Date();
                expires.setHours(expires.getHours() + 168); // 7-day window for account setup

                await tx.insert(users).values({
                    id: userId,
                    email: validated.data.author_email,
                    role: "author",
                    passwordHash: null, // Force setup
                });

                await tx.insert(userProfiles).values({
                    userId,
                    fullName: validated.data.author_name,
                    institute: validated.data.affiliation,
                    phone: validated.data.author_phone,
                    designation: validated.data.author_designation,
                });
            } else {
                userId = existingUsers[0].id;
                // Update profile with latest info
                await tx.update(userProfiles)
                    .set({
                        fullName: validated.data.author_name,
                        institute: validated.data.affiliation,
                        phone: validated.data.author_phone,
                        designation: validated.data.author_designation,
                    })
                    .where(eq(userProfiles.userId, userId));
            }

            // B. Paper Metadata Generation
            const [countRes] = await tx.select({ value: count() }).from(submissions);
            const total = countRes?.value || 0;
            const paperId = `IJITEST-${new Date().getFullYear()}-${String(total + 1).padStart(4, "0")}`;

            // C. Insert Core Submission
            const [submissionInsert] = await tx.insert(submissions).values({
                paperId,
                status: "submitted",
                correspondingAuthorId: userId,
            }).$returningId();
            const subId = submissionInsert.id;

            // D. Insert Version 1
            const [versionInsert] = await tx.insert(submissionVersions).values({
                submissionId: subId,
                versionNumber: 1,
                title: validated.data.title,
                abstract: validated.data.abstract,
                keywords: validated.data.keywords,
            }).$returningId();
            const verId = versionInsert.id;

            // E. Authors (Lead + Co-authors)
            const authorsList: any[] = [{
                submissionId: subId,
                name: validated.data.author_name,
                email: validated.data.author_email,
                phone: validated.data.author_phone,
                designation: validated.data.author_designation,
                institution: validated.data.affiliation,
                isCorresponding: true,
                orderIndex: 0,
            }];

            if (validated.data.co_authors) {
                try {
                    const coAuthors = JSON.parse(validated.data.co_authors);
                    if (Array.isArray(coAuthors)) {
                        coAuthors.forEach((ca, idx) => {
                            authorsList.push({
                                submissionId: subId,
                                name: ca.name,
                                email: ca.email,
                                phone: ca.phone,
                                designation: ca.designation,
                                institution: ca.institution,
                                isCorresponding: false,
                                orderIndex: idx + 1,
                            });
                        });
                    }
                } catch {}
            }
            await tx.insert(submissionAuthors).values(authorsList);

            // F. Predictable File URLs (Saved to DB first as requested)
            const timestamp = Date.now();
            const mName = `manuscript_${subId}_${timestamp}.${manuscriptFile.name.split('.').pop()}`;
            const cName = `copyright_${subId}_${timestamp}.${copyrightFile.name.split('.').pop()}`;
            const mUrl = `/uploads/submissions/${mName}`;
            const cUrl = `/uploads/submissions/${cName}`;

            await tx.insert(submissionFiles).values([
                { versionId: verId, fileType: "main_manuscript", fileUrl: mUrl, originalName: manuscriptFile.name, fileSize: manuscriptFile.size },
                { versionId: verId, fileType: "copyright_form", fileUrl: cUrl, originalName: copyrightFile.name, fileSize: copyrightFile.size }
            ]);

            return { paperId, subId, mName, cName };
        });

        // 3. File Uploads (Happens post-transaction to strictly follow "DB First" rule)
        // If this fails, the DB record exists but we'll mark it as failed or return an error.
        submissionToCleanup = result.subId;
        const uploadDir = path.join(process.cwd(), "public/uploads/submissions");
        await fs.mkdir(uploadDir, { recursive: true });

        try {
            await fs.writeFile(path.join(uploadDir, result.mName), Buffer.from(await manuscriptFile.arrayBuffer()));
            fileCleanupList.push(path.join(uploadDir, result.mName));

            await fs.writeFile(path.join(uploadDir, result.cName), Buffer.from(await copyrightFile.arrayBuffer()));
            fileCleanupList.push(path.join(uploadDir, result.cName));
        } catch (uploadErr) {
            // If upload fails, we must cleanup the DB record we just created to avoid "zombie" submissions
            await db.delete(submissions).where(eq(submissions.id, result.subId));
            throw new Error("File upload failed. Our servers might be busy. Please try again.");
        }

        // 4. Notifications
        const baseUrl = process.env.NEXT_PUBLIC_APP_URL || 'https://ijitest.org';
        const loginUrl = `${baseUrl}/auth/signin`; // Credentials sent via setup link if new

        // Author Notification
        const authorTemplate = emailTemplates.submissionReceived(
            validated.data.author_name,
            validated.data.title,
            result.paperId,
            invitationToken ? `${baseUrl}/auth/setup?token=${invitationToken}` : loginUrl
        );

        await sendEmail({
            to: validated.data.author_email,
            subject: authorTemplate.subject,
            html: authorTemplate.html
        });

        // Co-author Notifications
        if (validated.data.co_authors) {
            const coAuthors = JSON.parse(validated.data.co_authors);
            if (Array.isArray(coAuthors)) {
                await Promise.allSettled(coAuthors.map(ca => sendEmail({
                    to: ca.email,
                    subject: `Submission Notification: ${result.paperId}`,
                    html: `<p>Dear ${ca.name}, you have been added as a co-author for the paper <strong>${validated.data.title}</strong> at IJITEST.</p>`
                })));
            }
        }

        // Team Notification
        const staff = await db.select({ email: users.email }).from(users).where(inArray(users.role, ['admin', 'editor']));
        await Promise.allSettled(staff.map(s => sendEmail({
            to: s.email,
            subject: `New Paper [${result.paperId}] Received`,
            html: `<p>New submission from ${validated.data.author_name}. <a href="${baseUrl}/admin/submissions/${result.subId}">Review here</a></p>`
        })));

        revalidatePath('/admin/submissions');
        return { success: true, data: { paperId: result.paperId } };

    } catch (error: any) {
        console.error("Submission Failure:", error);
        return { success: false, error: error.message || "An unexpected error occurred during submission." };
    }
}

"use server";
 
import { db } from "@/lib/db";
import { submissions, reviews, reviewAssignments, submissionVersions, userProfiles, users } from "@/db/schema";
import { eq, and, min, desc } from "drizzle-orm";
import { ActionResponse } from "@/db/types";
 
export async function trackManuscript(paperId: string, authorEmail?: string): Promise<ActionResponse<{ manuscript: any }>> {
    try {
        // 1. Get the submission and its latest version
        const result = await db.select({
            id: submissions.id,
            paperId: submissions.paperId,
            status: submissions.status,
            submittedAt: submissions.submittedAt,
            updatedAt: submissions.updatedAt,
            title: submissionVersions.title,
            authorName: userProfiles.fullName,
            authorEmail: users.email,
        })
        .from(submissions)
        .innerJoin(submissionVersions, eq(submissions.id, submissionVersions.submissionId))
        .innerJoin(userProfiles, eq(submissions.correspondingAuthorId, userProfiles.userId))
        .innerJoin(users, eq(submissions.correspondingAuthorId, users.id))
        .where(eq(submissions.paperId, paperId))
        .orderBy(desc(submissionVersions.versionNumber))
        .limit(1);
 
        const manuscriptRow = result[0];
 
        if (!manuscriptRow) {
            return { success: false, error: "No manuscript found with these credentials. Please check your Paper ID." };
        }
 
        // Logic for email verification if provided
        if (authorEmail && manuscriptRow.authorEmail.toLowerCase() !== authorEmail.toLowerCase()) {
            return { success: false, error: "Email verification failed. Please check the registered correspondent email." };
        }
 
        // 2. Get the review start date (min assigned_at from assignments)
        const assignments = await db.select({
            reviewStartedAt: min(reviewAssignments.assignedAt)
        })
        .from(reviewAssignments)
        .where(eq(reviewAssignments.submissionId, manuscriptRow.id));
 
        const manuscript: any = {
            ...manuscriptRow,
            review_started_at: assignments[0]?.reviewStartedAt,
            // Map to UI-friendly names (Historical compatibility)
            paper_id: manuscriptRow.paperId,
            submitted_at: manuscriptRow.submittedAt,
            updated_at: manuscriptRow.updatedAt,
            author_name: manuscriptRow.authorName,
            author_email: manuscriptRow.authorEmail,
        };
 
        // 3. If rejected, fetch reviewer feedback (commentsToAuthor)
        if (manuscript.status === 'rejected') {
            const feedbackRows = await db.select({ feedback: reviews.commentsToAuthor })
                .from(reviews)
                .innerJoin(reviewAssignments, eq(reviews.assignmentId, reviewAssignments.id))
                .where(
                    and(
                        eq(reviewAssignments.submissionId, manuscript.id),
                        eq(reviewAssignments.status, "completed")
                    )
                );
            manuscript.reviewer_feedback = feedbackRows.map(r => r.feedback).filter(Boolean);
        }
 
        return { success: true, data: { manuscript } };
    } catch (error: any) {
        console.error("Track Manuscript Error:", error);
        return { success: false, error: "An error occurred while fetching the status. Please try again later." };
    }
}

import { getPaperById } from "@/actions/archives";
import PageHeader from "@/components/layout/PageHeader";
import PaperDetailClient from "@/features/archives/components/PaperDetailClient";
import { notFound } from "next/navigation";
import type { Metadata } from 'next';
import { getSettingsData } from '@/actions/settings';
import SettingsInitializer from "@/components/providers/SettingsInitializer";
import { getPublishedPapers } from "@/actions/archives";

export async function generateStaticParams() {
    try {
        const res = await getPublishedPapers();
        if (!res.success || !res.data) return [];
        
        return res.data.map((paper: any) => ({
            id: paper.id.toString(),
        }));
    } catch (error) {
        console.error("Generate Static Params Error:", error);
        return [];
    }
}

export async function generateMetadata({ params }: { params: Promise<{ id: string }> }): Promise<Metadata> {
    const { id } = await params;
    const [paperRes, settings] = await Promise.all([
        getPaperById(id),
        getSettingsData()
    ]);
    
    const paper = paperRes.success ? paperRes.data : null;
    
    if (!paper) return { title: 'Article Not Found | IJITEST' };

    const baseUrl = settings.journal_website || 'https://ijitest.org';
    const mainAuthor = paper.author_name;
    const coAuthors = paper.co_authors ? paper.co_authors.split(',').map((s: string) => s.trim()) : [];
    const allAuthors = [mainAuthor, ...coAuthors].filter(Boolean);

    return {
        title: `${paper.title} | IJITEST Archive`,
        description: paper.abstract?.substring(0, 160) + "...",
        keywords: paper.keywords,
        openGraph: {
            title: paper.title,
            description: paper.abstract?.substring(0, 160),
            type: 'article',
            authors: allAuthors,
        },
        other: {
            // Highwire Press (Google Scholar)
            'citation_title': paper.title,
            'citation_author': allAuthors,
            'citation_publication_date': paper.published_at ? new Date(paper.published_at).toISOString().split('T')[0].replace(/-/g, '/') : (paper.publication_year?.toString() || ''),
            'citation_journal_title': settings.journal_name || 'International Journal of Information Technology (IJITEST)',
            'citation_volume': paper.volume_number?.toString() || '',
            'citation_issue': paper.issue_number?.toString() || '',
            'citation_firstpage': paper.start_page?.toString() || '',
            'citation_lastpage': paper.end_page?.toString() || '',
            'citation_pdf_url': paper.pdf_url ? (paper.pdf_url.startsWith('http') ? paper.pdf_url : `${baseUrl}${paper.pdf_url}`) : '',
            
            // Dublin Core
            'dc.title': paper.title || '',
            'dc.creator': allAuthors,
            'dc.date': paper.published_at ? new Date(paper.published_at).toISOString().split('T')[0] : (paper.publication_year?.toString() || ''),
            'dc.subject': paper.keywords || '',
            'dc.description': paper.abstract || '',
        }
    };
}

export default async function PaperDetailPage({ params }: { params: Promise<{ id: string }> }) {
    const { id } = await params;
    const [paperRes, settings] = await Promise.all([
        getPaperById(id),
        getSettingsData()
    ]);
    
    const paper = paperRes.success ? paperRes.data : null;

    if (!paper) notFound();

    return (
        <div className="bg-white min-h-screen pb-20">
            <SettingsInitializer settings={settings} />
            <PageHeader
                title="Research Article"
                description={paper.paper_id}
                breadcrumbs={[
                    { name: 'Home', href: '/' },
                    { name: 'Archives', href: '/archives' },
                    { name: paper.paper_id, href: `/archives/${id}` },
                ]}
            />
            <PaperDetailClient paper={paper} id={id} />
        </div>
    );
}

