                                                    <Badge className={`border-none text-[10px] 2xl:text-sm font-semibold uppercase py-1 px-3 rounded-full ${
                                                        sub.status === 'published' ? 'bg-emerald-500/10 text-emerald-600' : 
                                                        sub.status === 'retracted' ? 'bg-rose-600/10 text-rose-600' :
                                                        'bg-primary/10 text-primary'}`}>
                                                        {sub.status.replace('_', ' ')}
                                                    </Badge>
                                                </Link>
                                            ))}
                                        </div>
                                    </CardContent>
                                </Card>

                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    <Card className="p-4 border-border/50 bg-card">
                                        <h4 className="text-[10px] font-semibold uppercase text-muted-foreground tracking-widest mb-4 opacity-60">Operations Metrics</h4>
                                        <div className="space-y-4">
                                            <div>
                                                <div className="flex justify-between text-[9px] font-semibold uppercase tracking-widest mb-1.5 opacity-50">
                                                    <span>Publication Rate</span>
                                                    <span>{pubPercent.toFixed(1)}%</span>
                                                </div>
                                                <div className="h-1 w-full bg-muted rounded-full overflow-hidden">
                                                    <div className="h-full bg-emerald-500 rounded-full w-(--pub-progress)" style={{ '--pub-progress': `${pubPercent}%` } as React.CSSProperties} />
                                                </div>
                                            </div>
                                            <div>
                                                <div className="flex justify-between text-[9px] font-semibold uppercase tracking-widest mb-1.5 opacity-50">
                                                    <span>Review Rate</span>
                                                    <span>{revPercent.toFixed(1)}%</span>
                                                </div>
                                                <div className="h-1 w-full bg-muted rounded-full overflow-hidden">
                                                    <div className="h-full bg-blue-500 rounded-full w-(--rev-progress)" style={{ '--rev-progress': `${revPercent}%` } as React.CSSProperties} />
                                                </div>
                                            </div>
                                        </div>
                                    </Card>
                                    <Card className="p-4 border-border/50 bg-card border-dashed flex flex-col items-center justify-center text-center">
                                        <TrendingUp className="w-8 h-8 text-primary/30 mb-2" />
                                        <h4 className="text-[10px] font-semibold uppercase tracking-widest text-primary">Expand Team</h4>
                                        <p className="text-[10px] font-semibold tracking-widest uppercase text-muted-foreground mb-3 leading-wider opacity-40">Scale infrastructure system.</p>
                                        <InviteEditorModal />
                                    </Card>
                                </div>
                            </div>

                            <div className="space-y-4">
                                <Card className="border-border/50 shadow-sm bg-card transition-colors">
                                    <CardHeader className="pb-3 border-b border-border/30">
                                        <CardTitle className="text-[11px] sm:text-xs font-semibold text-foreground uppercase tracking-widest flex items-center gap-2 opacity-60">
                                            <ClipboardList className="w-4 h-4 text-primary" /> Pending Applications
                                        </CardTitle>
                                    </CardHeader>
                                    <CardContent className="p-0">
                                        <div className="divide-y divide-border/20">
                                            {pendingApplications.length === 0 ? (
                                                <div className="p-8 text-center text-[10px] text-muted-foreground font-semibold uppercase tracking-widest opacity-40">No pending requests</div>
                                            ) : pendingApplications.map((app: any) => (
                                                <div key={app.id} className="p-4 space-y-3">
                                                    <div className="flex items-center justify-between">
                                                        <Badge variant="outline" className="text-[9px] font-semibold uppercase tracking-widest px-2 h-5 rounded-full border-primary/10 text-primary/60">{app.applicationType}</Badge>
                                                        <span className="text-[10px] text-muted-foreground font-semibold uppercase tracking-widest opacity-40">{new Date(app.createdAt).toLocaleDateString()}</span>
                                                    </div>
                                                    <h5 className=" font-semibold text-foreground leading-wider tracking-wider uppercase">{app.fullName}</h5>
                                                    <ApplicationDecisionButtons id={app.id} />
                                                </div>
                                            ))}
                                        </div>
                                        <div className="p-3 bg-muted/20 border-t border-border/20 text-center">
                                            <Button asChild variant="ghost" className="h-8 text-[10px] font-semibold uppercase tracking-widest text-primary hover:bg-primary/15 cursor-pointer">
                                                <Link className="cursor-pointer" href="/admin/applications">Audit Performance</Link>
                                            </Button>
                                        </div>
                                    </CardContent>
                                </Card>
                            </div>
                        </div>
                    </TabsContent>

                    <TabsContent value="my-papers" className="space-y-4">
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                            {mySubmissions.length === 0 ? (
                                <Card className="md:col-span-2 lg:col-span-3 border-dashed border-2 bg-muted/10 py-16 text-center">
                                    <div className="max-w-xs mx-auto space-y-4">
                                        <div className="w-12 h-12 rounded-full bg-background flex items-center justify-center mx-auto shadow-sm">
                                            <FileText className="w-6 h-6 text-muted-foreground/30" />
                                        </div>
                                        <p className="text-sm text-muted-foreground font-medium px-4">Submit and track your own research manuscripts from the system portal.</p>
                                        <Button asChild size="sm" className="bg-primary text-white hover:bg-primary/90 rounded-lg cursor-pointer">
                                            <Link className="cursor-pointer" href="/submit">New Manuscript</Link>
                                        </Button>
                                    </div>
                                </Card>
                            ) : mySubmissions.map((paper: any) => (
                                <Card key={paper.id} className="border-border/50 shadow-sm bg-card hover:border-primary/20 transition-all group overflow-hidden">
                                    <div className="p-5 space-y-4">
                                        <div className="flex items-center justify-between">
                                            <Badge variant="outline" className="text-[9px] font-semibold tracking-widest uppercase border-none bg-muted px-2 py-0.5">ID: {paper.paper_id}</Badge>
                                            <Badge className={`text-[9px] font-semibold uppercase tracking-widest py-0.5 px-2 border-none rounded-full ${paper.status === 'published' ? 'bg-emerald-500/10 text-emerald-600' :
                                                paper.status === 'rejected' ? 'bg-rose-500/10 text-rose-600' :
                                                    'bg-indigo-500/10 text-indigo-600'
                                                }`}>
                                                {paper.status}
                                            </Badge>
                                        </div>
                                        <h3 className=" font-semibold text-foreground line-clamp-2 h-10 group-hover:text-primary transition-colors leading-wider tracking-wider uppercase">{paper.title}</h3>
                                        <div className="flex items-center justify-between pt-4 border-t border-border/10">
                                            <span className="text-[10px] text-muted-foreground flex items-center gap-1.5 font-semibold uppercase tracking-widest opacity-40"><Clock className="w-3 h-3" /> {new Date(paper.submitted_at).toLocaleDateString()}</span>
                                            <Button asChild variant="ghost" size="sm" className="h-7 px-3 text-primary hover:bg-primary/15 rounded-md text-[10px] font-semibold uppercase tracking-widest cursor-pointer">
                                                <Link href={`/track?id=${paper.paper_id}`} className="flex items-center gap-1.5 cursor-pointer">
                                                    Portal <ExternalLink className="w-3 h-3" />
                                                </Link>
                                            </Button>
                                        </div>
                                    </div>
                                    <div className="h-1 bg-muted/20 overflow-hidden">
                                        <div
                                            className={`h-full transition-all duration-1000 ${paper.status === 'published' ? 'bg-emerald-500' : 'bg-primary'} w-(--status-progress)`}
                                            style={{ '--status-progress': paper.status === 'published' ? '100%' : '15%' } as React.CSSProperties}
                                        />
                                    </div>
                                </Card>
                            ))}
                        </div>
                    </TabsContent>

                    {/* Infrastructure tab omitted for brevity but should be refactored similarly */}
                    <TabsContent value="infrastructure" className="space-y-4">
                         <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                            <Card className="lg:col-span-2 border-border/50 shadow-sm bg-card overflow-hidden">
                                <CardHeader className="p-4 border-b border-border/30 flex flex-row items-center justify-between bg-muted/10">
                                    <CardTitle className="text-[11px] sm:text-xs font-semibold text-foreground uppercase tracking-widest flex items-center gap-2 opacity-60">
                                        <Users className="w-4 h-4 text-primary" /> Active Personnel
                                    </CardTitle>
                                    <Button size="sm" asChild className="h-8 px-4 bg-primary text-white dark:text-slate-900 hover:opacity-90 dark:hover:text-slate-900 text-[10px] font-semibold uppercase tracking-widest rounded-lg cursor-pointer">
                                        <Link className="cursor-pointer" href="/admin/users">Manage All</Link>
                                    </Button>
                                </CardHeader>
                                <CardContent className="p-0">
                                    <div className="divide-y divide-border/20">
                                        {allStaff.map((staff: any) => (
                                            <div key={staff.id} className="p-3 flex items-center justify-between hover:bg-muted/20 transition-colors">
                                                <div className="flex items-center gap-4">
                                                    <div className="w-9 h-9 rounded-xl bg-primary/10 text-primary flex items-center justify-center font-semibold text-xs uppercase border border-primary/10">
                                                        {staff.full_name?.charAt(0) || staff.email.charAt(0)}
                                                    </div>
                                                    <div>
                                                        <h5 className=" font-semibold text-foreground tracking-wider uppercase">{staff.full_name || 'System User'}</h5>
                                                        <p className="text-[10px] font-semibold text-muted-foreground uppercase tracking-widest opacity-60 leading-none">{staff.email}</p>
                                                    </div>
                                                </div>
                                                <Badge variant="outline" className={`h-6 text-[9px] font-semibold uppercase tracking-widest border-none px-3 rounded-full ${staff.role === 'admin' ? 'bg-rose-500/10 text-rose-600' : staff.role === 'editor' ? 'bg-blue-500/10 text-blue-600' : 'bg-emerald-500/10 text-emerald-600'}`}>
                                                    {staff.role}
                                                </Badge>
                                            </div>
                                        ))}
                                    </div>
                                </CardContent>
                            </Card>

                            <Card className="border-border/50 shadow-sm bg-card transition-colors">
                                <CardHeader className="pb-3 border-b border-border/30">
                                    <CardTitle className="text-[11px] sm:text-xs font-semibold text-foreground uppercase tracking-widest opacity-60">Infrastructure Health</CardTitle>
                                </CardHeader>
                                <CardContent className="p-4 space-y-4">
                                    {[
                                        { label: 'Latency', value: `${dbLatency}ms`, status: Number(dbLatency) < 5 ? 'Optimal' : 'Nominal', icon: Activity },
                                        { label: 'Storage', value: `${storageMB}MB / ${storageLimit}MB`, status: storagePercent < 80 ? 'Healthy' : 'Near Limit', icon: Download },
                                        { label: 'System Load', value: `${memUsedPercent}%`, status: Number(memUsedPercent) < 70 ? 'Optimal' : 'Elevated', icon: Users }
                                    ].map((metric) => (
                                        <div key={metric.label} className="p-4 rounded-xl bg-muted/20 border border-border/30 space-y-1.5 transition-all hover:bg-muted/30">
                                            <div className="flex justify-between items-center text-[9px] uppercase font-semibold tracking-widest text-muted-foreground opacity-60">
                                                <span className="flex items-center gap-1.5"><metric.icon className="w-3 h-3" /> {metric.label}</span>
                                                <span className={metric.status === 'Optimal' || metric.status === 'Healthy' ? 'text-emerald-600' : 'text-amber-600'}>{metric.status}</span>
                                            </div>
                                            <p className="text-xl font-semibold text-foreground tracking-wider">{metric.value}</p>
                                        </div>
                                    ))}
                                </CardContent>
                            </Card>
                        </div>
                    </TabsContent>
                </Tabs>
            </section>
        );
    } catch (error: any) {
        console.error("Admin Dashboard Error:", error);
        return <section className="p-12 text-center text-muted-foreground font-semibold text-[10px] uppercase tracking-widest min-h-[400px] flex flex-col items-center justify-center gap-4">
            <div className="w-12 h-12 rounded-2xl bg-destructive/5 flex items-center justify-center text-destructive">
                <AlertCircle className="w-6 h-6" />
            </div>
            Critical System Logic Error. Contact technical support protocols.
        </section>;
    }
}

"use client";

import { CreditCard, DollarSign, CheckCircle, Clock, Search, Plus, User, ShieldCheck, Mail, ArrowRight, AlertTriangle, History, Eye, Globe } from 'lucide-react';
import {
    usePayments,
    useUnpaidPapers,
    useInitializePayment,
    useUpdatePaymentStatus
} from '@/hooks/queries/usePayments';
import { useState } from 'react';
import { toast } from 'sonner';
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Separator } from "@/components/ui/separator";
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
    DialogFooter
} from "@/components/ui/dialog";
import { Label } from "@/components/ui/label";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import { InputGroup, InputGroupAddon, InputGroupInput } from "@/components/ui/input-group";

export default function PaymentManagement() {
    const { data: payments = [], isLoading: loading } = usePayments();
    const { data: unpaidPapers = [], isLoading: loadingUnpaid } = useUnpaidPapers();
    const initMutation = useInitializePayment();
    const updateMutation = useUpdatePaymentStatus();

    const [showInitModal, setShowInitModal] = useState(false);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [searchQuery, setSearchQuery] = useState('');
    const [statusFilter, setStatusFilter] = useState('all');

    async function handleInitPayment(formData: FormData) {
        setIsSubmitting(true);
        const submissionId = parseInt(formData.get('submissionId') as string);
        const amount = parseFloat(formData.get('amount') as string);
        const currency = formData.get('currency') as string;

        try {
            const res = await initMutation.mutateAsync({ submissionId, amount, currency });
            if (res.success) {
                setShowInitModal(false);
                toast.success("Transaction initialized");
            } else {
                toast.error(res.error);
            }
        } catch (error) {
            toast.error("Failed to initialize transaction");
        }
        setIsSubmitting(false);
    }

    async function handleStatusUpdate(id: number, status: 'pending' | 'paid' | 'verified' | 'failed' | 'waived', transactionId: string) {
        try {
            const res = await updateMutation.mutateAsync({ id, status, transactionId });
            if (res.success) {
                toast.success("Status Synchronized");
            } else {
                toast.error(res.error);
            }
        } catch (error) {
            toast.error("Failed to update status");
        }
    }

    if (loading) return <div className="p-40 text-center space-y-6">
        <div className="w-16 h-16 border-4 border-primary/20 border-t-primary rounded-full animate-spin mx-auto" />
        <p className="font-semibold text-muted-foreground tracking-widest text-xs animate-pulse uppercase">Verifying Financial Records...</p>
    </div>;

    const filteredPayments = payments.filter(p => {
        const matchesSearch =
            p.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
            p.authorName.toLowerCase().includes(searchQuery.toLowerCase()) ||
            p.paperId.toLowerCase().includes(searchQuery.toLowerCase()) ||
            (p.transactionId && p.transactionId.toLowerCase().includes(searchQuery.toLowerCase()));

        const matchesStatus = statusFilter === 'all' || p.status === statusFilter;

        return matchesSearch && matchesStatus;
    });

    const revenueStats = {
        gross: payments.filter(p => p.status === 'verified').reduce((acc, curr) => acc + parseFloat(curr.amount), 0),
        paid: payments.filter(p => p.status === 'paid' || p.status === 'verified').length,
        projected: payments.filter(p => p.status === 'pending').reduce((acc, curr) => acc + parseFloat(curr.amount), 0),
        pending: payments.filter(p => p.status === 'pending').length
    };

    const stats = [
        { label: 'Gross revenue (verified)', value: `₹${revenueStats.gross}`, variant: 'emerald', icon: <DollarSign className="w-4 h-4" /> },
        { label: 'Verified transactions', value: revenueStats.paid, variant: 'blue', icon: <CheckCircle className="w-4 h-4" /> },
        { label: 'Projected revenue', value: `₹${revenueStats.projected}`, variant: 'orange', icon: <History className="w-4 h-4" /> },
        { label: 'Pending requests', value: revenueStats.pending, variant: 'rose', icon: <Clock className="w-4 h-4" /> },
    ];

    const getStatusVariant = (status: string) => {
        switch (status) {
            case 'verified': return 'bg-emerald-500/10 text-emerald-600 border-none';
            case 'paid': return 'bg-blue-600/10 text-blue-600 border-none';
            case 'pending': return 'bg-orange-500/10 text-orange-600 border-none';
            case 'waived': return 'bg-purple-500/10 text-purple-600 border-none';
            default: return 'bg-muted text-muted-foreground border-none';
        }
    };

    return (
        <section className="space-y-8 pb-12">
            {/* Header Section */}
            <header className="flex flex-col sm:flex-row sm:items-center justify-between gap-6 border-b border-primary/5 pb-6 2xl:pb-12">
                <div className="space-y-1 2xl:space-y-2">
                    <h1 className="font-serif text-2xl xl:text-3xl 2xl:text-4xl font-semibold text-foreground tracking-tight capitalize leading-none">Financial oversight</h1>
                    <p className="text-[9px] xl:text-xs 2xl:text-sm font-medium text-muted-foreground border-l-2 border-primary/10 pl-4 capitalize tracking-wide">Article processing charge (APC) management and financial protocol enforcement.</p>
                </div>
                <div className="flex items-center gap-3">
                    <Dialog open={showInitModal} onOpenChange={setShowInitModal}>
                        <DialogTrigger asChild>
                            <Button className="h-10 xl:h-12 2xl:h-14 px-6 gap-3 bg-primary text-white dark:text-slate-900 font-semibold text-xs capitalize tracking-widest rounded-xl shadow-xl shadow-primary/20 hover:scale-[1.02] transition-all cursor-pointer">
                                <Plus className="w-5 h-5 2xl:w-6 2xl:h-6" /> Initialize APC request
                            </Button>
                        </DialogTrigger>
                        <DialogContent className="sm:max-w-md rounded-xl p-8 bg-card border-primary/5 shadow-2xl overflow-hidden">
                            <div className="absolute top-0 left-0 w-full h-2 bg-primary/10" />
                            <DialogHeader className="space-y-2">
                                <DialogTitle className="text-xl sm:text-2xl lg:text-2xl xl:text-3xl 2xl:text-4xl font-semibold text-foreground tracking-wider uppercase">Manual Request</DialogTitle>
                                <DialogDescription className="text-[9px] sm:text-[10px] xl:text-[11px] 2xl:text-xs font-semibold text-muted-foreground uppercase tracking-widest leading-relaxed opacity-60">
                                    Initialize a payment node for an accepted manuscript without automated triggers.
                                </DialogDescription>
                            </DialogHeader>
                            <form action={handleInitPayment} className="space-y-6 pt-6">
                                <div className="space-y-3">
                                    <Label className="text-[9px] sm:text-[10px] xl:text-[11px] 2xl:text-xs font-semibold text-muted-foreground tracking-widest px-1 uppercase">Accepted Paper</Label>
                                    <Select name="submissionId" required>
                                        <SelectTrigger className="h-16 w-full rounded-xl bg-muted border-none px-6 text-sm font-semibold text-foreground dark:text-primary focus:ring-4 focus:ring-primary/5">
                                            <SelectValue placeholder="Select target paper..." />
                                        </SelectTrigger>
                                        <SelectContent className="rounded-xl border-primary/5 bg-card">
                                            {unpaidPapers.map(paper => (
                                                <SelectItem key={paper.id} value={paper.id.toString()} className="font-semibold">
                                                    {paper.paperId} | {paper.title.slice(0, 50)}...
                                                </SelectItem>
                                            ))}
                                        </SelectContent>
                                    </Select>
                                </div>
                                <div className="grid grid-cols-2 gap-8">
                                    <div className="space-y-3">
                                        <Label className="text-xs font-semibold text-muted-foreground tracking-widest px-1 uppercase">Amount</Label>
                                        <Input name="amount" type="number" step="0.01" required className="h-16 bg-primary/5 border-none focus-visible:ring-4 focus-visible:ring-primary/5 font-semibold text-sm rounded-xl px-6" placeholder="2500" defaultValue="2500" />
                                    </div>
                                    <div className="space-y-3">
                                        <Label className="text-xs font-semibold text-muted-foreground tracking-widest px-1 uppercase">Currency</Label>
                                        <Select name="currency" defaultValue="INR">
                                            <SelectTrigger className="h-16 w-full rounded-xl bg-muted border-none px-6 text-sm font-semibold text-foreground dark:text-primary focus:ring-4 focus:ring-primary/5">
                                                <SelectValue />
                                            </SelectTrigger>
                                            <SelectContent className="rounded-xl border-primary/5 bg-card">
                                                <SelectItem value="INR" className="font-semibold">INR</SelectItem>
                                                <SelectItem value="USD" className="font-semibold">USD</SelectItem>
                                            </SelectContent>
                                        </Select>
                                    </div>
                                </div>
                                <DialogFooter className="pt-4">
                                    <Button type="submit" className="w-full h-14 bg-primary text-white dark:text-slate-900 font-semibold shadow-vip hover:scale-[1.02] transition-transform rounded-xl cursor-pointer">
                                        CREATE PAYMENT NODE
                                    </Button>
                                </DialogFooter>
                            </form>
                        </DialogContent>
                    </Dialog>
                </div>
            </header>

            {/* Stats Grid */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 2xl:gap-8 transition-all duration-500">
                {stats.map(stat => (
                    <Card key={stat.label} className="border-primary/5 shadow-vip bg-card group hover:scale-[1.02] transition-all 2xl:rounded-3xl">
                        <CardContent className="p-8 2xl:p-14">
                            <div className="flex items-center justify-between mb-6 2xl:mb-12">
                                <div className={`w-12 h-12 2xl:w-20 2xl:h-20 rounded-xl 2xl:rounded-2xl flex items-center justify-center ${stat.variant === 'emerald' ? 'bg-emerald-500/10 text-emerald-600' : stat.variant === 'blue' ? 'bg-blue-500/10 text-blue-600' : stat.variant === 'orange' ? 'bg-orange-500/10 text-orange-600' : 'bg-rose-500/10 text-rose-600'}`}>
                                    <div className="[&>svg]:w-5 [&>svg]:h-5 [&>svg]:2xl:w-10 [&>svg]:2xl:h-10">
                                        {stat.icon}
                                    </div>
                                </div>
                                <Badge variant="outline" className="h-6 2xl:h-9 px-2 2xl:px-4 text-[10px] 2xl:text-base font-semibold uppercase tracking-widest opacity-20 group-hover:opacity-100 transition-opacity">Live Metric</Badge>
                            </div>
                            <div className="space-y-1 2xl:space-y-2">
                                <p className="text-[9px] xl:text-xs font-semibold text-primary/40 capitalize tracking-widest leading-none transition-all duration-500">{stat.label}</p>
                                <h3 className=" font-semibold text-foreground dark:text-white tracking-wider transition-all duration-500 text-lg xl:text-xl 2xl:text-2xl">{stat.value}</h3>
                            </div>
                        </CardContent>
                    </Card>
                ))}
            </div>

            {/* Registry Search & Filter */}
            <div className="flex flex-col md:flex-row items-center gap-4 bg-muted/50 backdrop-blur-sm p-4 2xl:p-10 rounded-xl border border-primary/5 transition-all duration-500">
                <InputGroup className="flex-1 h-16 2xl:h-24 bg-card border-primary/5 rounded-xl shadow-sm overflow-hidden focus-within:ring-4 focus-within:ring-primary/5 transition-all">
                    <InputGroupAddon className="pl-6 2xl:pl-10">
                        <Search className="w-5 h-5 2xl:w-8 2xl:h-8 text-primary/20 group-focus-within/input-group:text-primary transition-colors" />
                    </InputGroupAddon>
                    <InputGroupInput
                        placeholder="Search by Title, ID, Author, or Transaction..."
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        className="h-full px-6 2xl:px-12 font-semibold text-sm 2xl:text-xl bg-transparent border-0 ring-0 focus-visible:ring-0 transition-all duration-500"
                    />
                </InputGroup>
                <div className="flex items-center gap-2 w-full md:w-auto">
                    <Select value={statusFilter} onValueChange={setStatusFilter}>
                        <SelectTrigger className="h-16 2xl:h-24 px-8 2xl:px-12 bg-card border border-primary/5 rounded-xl text-xs 2xl:text-lg font-semibold uppercase tracking-widest shadow-sm focus:ring-4 focus:ring-primary/5 transition-all text-foreground dark:text-primary min-w-[200px] 2xl:min-w-[350px]">
                            <SelectValue placeholder="Global Status" />
                        </SelectTrigger>
                        <SelectContent className="rounded-xl border-primary/5 bg-card">
                            <SelectItem value="all" className="font-semibold text-xs 2xl:text-base uppercase tracking-widest">Global Status</SelectItem>
                            <SelectItem value="unpaid" className="font-semibold text-xs 2xl:text-base uppercase tracking-widest">Pending</SelectItem>
                            <SelectItem value="paid" className="font-semibold text-xs 2xl:text-base uppercase tracking-widest">Remitted</SelectItem>
                            <SelectItem value="verified" className="font-semibold text-xs 2xl:text-base uppercase tracking-widest">Verified</SelectItem>
                            <SelectItem value="waived" className="font-semibold text-xs 2xl:text-base uppercase tracking-widest">Waived</SelectItem>
                        </SelectContent>
                    </Select>
                </div>
            </div>

            {/* Payments List */}
            <div className="space-y-4">
                <div className="flex items-center justify-between px-4">
                    <div className="flex items-center gap-3 transition-all duration-500">
                        <h2 className=" font-semibold text-primary tracking-widest capitalize">Transaction registry</h2>
                        <span className="text-[9px] xl:text-xs font-semibold text-primary/40 bg-primary/5 px-3 py-1 rounded-full">{filteredPayments.length}</span>
                    </div>
                </div>

                <div className="grid grid-cols-1 gap-4 2xl:gap-8">
                    {filteredPayments.map((item) => (
                        <Card key={item.id} className="border-primary/5 shadow-vip hover:shadow-2xl hover:scale-[1.005] transition-all group overflow-hidden bg-card relative 2xl:rounded-3xl">
                            <div className={`absolute top-0 left-0 w-1.5 h-full ${item.status === 'verified' ? 'bg-emerald-500/20' : item.status === 'paid' ? 'bg-blue-500/20' : item.status === 'waived' ? 'bg-purple-500/20' : 'bg-orange-500/20'}`} />
                            <CardContent className="p-0">
                                <div className="p-8 2xl:p-14 flex flex-col xl:flex-row xl:items-center justify-between gap-8 2xl:gap-16">
                                    <div className="flex-1 space-y-4 2xl:space-y-8 min-w-0">
                                        <div className="flex items-center gap-4 2xl:gap-8">
                                            <Badge className={`h-8 2xl:h-12 px-3 2xl:px-6 text-xs 2xl:text-lg font-semibold uppercase tracking-[0.2em] shadow-sm rounded-lg ${getStatusVariant(item.status)}`}>
                                                {item.status === 'verified' ? 'Authorized' : item.status}
                                            </Badge>
                                            <div className="flex items-center gap-3 2xl:gap-5 bg-primary/5 px-4 2xl:px-7 py-1.5 2xl:py-3 rounded-full border border-primary/5 shadow-inner">
                                                <ShieldCheck className="w-4 h-4 2xl:w-7 2xl:h-7 text-primary/30" />
                                                <span className="text-[10px] 2xl:text-base font-semibold text-primary/60 tracking-widest uppercase">{item.paperId}</span>
                                            </div>
                                        </div>
                                        <h3 className=" font-semibold text-foreground dark:text-white leading-wider tracking-wider line-clamp-1 group-hover:text-secondary transition-colors duration-500 2xl:text-xl">
                                            {item.title}
                                        </h3>
                                        <div className="flex flex-wrap gap-12 2xl:gap-20 items-center border-t border-primary/5 pt-6 2xl:pt-10">
                                            <div className="space-y-2 2xl:space-y-3">
                                                <p className="text-[9px] sm:text-[10px] xl:text-[11px] 2xl:text-xs font-semibold text-primary/30 uppercase tracking-widest">Primary Investigator</p>
                                                <div className="flex items-center gap-3 2xl:gap-5 text-sm 2xl:text-lg font-semibold text-primary uppercase">
                                                    <User className="w-4.5 h-4.5 2xl:w-6 2xl:h-6 text-primary/40" />
                                                    <span>{item.authorName}</span>
                                                </div>
                                            </div>
                                            <div className="space-y-2 2xl:space-y-3">
                                                <p className="text-[9px] xl:text-xs font-semibold text-primary/30 capitalize tracking-widest">Remittance value</p>
                                                <div className="flex items-center gap-3 2xl:gap-5 text-base xl:text-lg 2xl:text-xl font-semibold text-emerald-600">
                                                    <CreditCard className="w-4.5 h-4.5 opacity-40" />
                                                    <span>{item.amount} {item.currency}</span>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                    <div className="shrink-0 flex flex-wrap items-center gap-4 2xl:gap-8 border-t xl:border-t-0 pt-6 xl:pt-0 border-primary/5">
                                        <div className="flex items-center gap-3 2xl:gap-5">
                                            <Button asChild variant="ghost" size="icon" className="w-12 h-12 2xl:w-20 2xl:h-20 rounded-xl 2xl:rounded-2xl bg-primary/5 text-primary/60 dark:text-primary/80 hover:text-primary hover:bg-primary/20 transition-all shadow-sm cursor-pointer">
                                                <a href={`/admin/submissions/${item.submissionId}`} title="View Manuscript Detail">
                                                    <Eye className="w-5 h-5 2xl:w-9 2xl:h-9" />
                                                </a>
                                            </Button>
                                            <Button asChild variant="ghost" size="icon" className="w-12 h-12 2xl:w-20 2xl:h-20 rounded-xl 2xl:rounded-2xl bg-primary/5 text-primary/60 dark:text-primary/80 hover:text-primary hover:bg-primary/20 transition-all shadow-sm cursor-pointer">
                                                <a href={`mailto:${item.authorEmail}`} title={`Contact ${item.authorName}`}>
                                                    <Mail className="w-5 h-5 2xl:w-9 2xl:h-9" />
                                                </a>
                                            </Button>
                                        </div>
                                        <Separator orientation="vertical" className="h-10 2xl:h-16 mx-2 2xl:mx-4 bg-primary/5 hidden xl:block" />
                                        {item.status === 'pending' ? (
                                            <Button
                                                onClick={async () => {
                                                    const txId = prompt("Enter Bank/Gateway Transaction Reference:");
                                                    if (txId) {
                                                        await handleStatusUpdate(item.id, 'paid', txId);
                                                    }
                                                }}
                                                className="h-14 2xl:h-20 px-8 2xl:px-12 gap-3 2xl:gap-5 bg-card border-2 border-secondary text-secondary hover:text-white dark:hover:text-slate-900 font-semibold text-xs 2xl:text-lg tracking-widest rounded-xl 2xl:rounded-2xl hover:bg-secondary transition-all shadow-lg shadow-secondary/5 uppercase"
                                            >
                                                <CheckCircle className="w-5 h-5 2xl:w-9 2xl:h-9" /> VERIFY REMITTANCE
                                            </Button>
                                        ) : item.status === 'paid' ? (
                                            <Button
                                                onClick={async () => {
                                                    if (confirm("Finalize archive authorization for this manuscript?")) {
                                                        await handleStatusUpdate(item.id, 'verified', item.transactionId || '');
                                                    }
                                                }}
                                                className="h-14 2xl:h-20 px-10 2xl:px-14 gap-3 2xl:gap-5 bg-emerald-600 text-white dark:text-slate-900 font-semibold text-xs 2xl:text-lg tracking-widest rounded-xl 2xl:rounded-2xl shadow-xl shadow-emerald-600/20 hover:bg-emerald-700 hover:scale-[1.02] transition-all uppercase"
                                            >
                                                <ShieldCheck className="w-5 h-5 2xl:w-9 2xl:h-9" /> AUTHORIZE ARCHIVE
                                            </Button>
                                        ) : item.status === 'verified' ? (
                                            <div className="flex items-center gap-4 2xl:gap-6 bg-emerald-500/10 px-8 2xl:px-12 py-4 2xl:py-7 rounded-xl 2xl:rounded-2xl text-emerald-600 border border-emerald-500/10 shadow-inner">
                                                <Globe className="w-5 h-5 2xl:w-9 2xl:h-9" />
                                                <span className="font-semibold text-xs 2xl:text-lg uppercase tracking-widest">Archive Active</span>
                                            </div>
                                        ) : (
                                            <div className="flex items-center gap-4 2xl:gap-6 bg-purple-500/10 px-8 2xl:px-12 py-4 2xl:py-7 rounded-xl 2xl:rounded-2xl text-purple-600 border border-purple-500/10 shadow-inner">
                                                <Badge variant="ghost" className="p-0 hover:bg-transparent"><ArrowRight className="w-5 h-5 2xl:w-9 2xl:h-9" /></Badge>
                                                <span className="font-semibold text-xs 2xl:text-lg uppercase tracking-widest">Fee Waived</span>
                                            </div>
                                        )}
                                    </div>
                                </div>
                            </CardContent>
                        </Card>
                    ))}

                    {filteredPayments.length === 0 && !loading && (
                        <div className="flex flex-col items-center justify-center py-32 bg-primary/2 border-2 border-dashed border-primary/5 rounded-xl space-y-6">
                            <div className="w-20 h-20 rounded-xl bg-muted shadow-sm flex items-center justify-center text-primary/40">
                                <AlertTriangle className="w-10 h-10" />
                            </div>
                            <div className="text-center space-y-2">
                                <h3 className=" font-semibold text-primary/60 dark:text-primary/80 uppercase tracking-[0.3em] ">Record Depth Null</h3>
                                <p className="text-[10px] font-medium text-primary/40 dark:text-primary/60 tracking-widest ">No financial transactions correlate with your active query.</p>
                            </div>
                        </div>
                    )}
                </div>
            </div>
        </section>
    );
}

import { getServerSession } from "next-auth/next";
import { authOptions } from "@/lib/auth";
import { redirect } from "next/navigation";
import ProfileDossier from "@/features/profile/components/ProfileDossier";
import { Suspense } from "react";
import { Loader2 } from "lucide-react";

export const dynamic = "force-dynamic";

export const metadata = {
    title: "Account Profile | Admin Panel",
};

export default async function AdminProfilePage() {
    const session = await getServerSession(authOptions);

    if (!session?.user) {
        redirect("/login");
    }

    return (
        <section className="space-y-10">
            <header className="space-y-1 2xl:space-y-2 border-b border-white/5 pb-8">
                <h1 className="font-serif text-2xl xl:text-3xl 2xl:text-4xl font-semibold text-foreground tracking-tight capitalize leading-none">Administrative identity</h1>
                <p className="text-[9px] xl:text-xs 2xl:text-sm font-medium text-muted-foreground capitalize tracking-widest opacity-60">Manage your core credentials and architectural clearance.</p>
            </header>

            <Suspense fallback={
                <div className="h-96 flex flex-col items-center justify-center gap-4 text-muted-foreground">
                    <Loader2 className="w-8 h-8 animate-spin opacity-20" />
                    <p className="font-mono text-[10px] uppercase tracking-widest animate-pulse">Initializing Identity Dossier...</p>
                </div>
            }>
                <ProfileDossier role="admin" userId={(session.user as any).id} />
            </Suspense>
        </section>
    );
}

"use client";

import { Plus, BookOpen, Clock, CheckCircle2, Trash2, Globe, Calendar, Layers, CheckCircle, Save, ChevronDown as ChevronDownIcon, ChevronUp, FileText, Eye, Unlink } from 'lucide-react';

import {
    useVolumesIssues,
    usePapersByIssue,
    useCreateVolumeIssue,
    useUpdateVolumeIssue,
    useDeleteVolumeIssue,
    usePublishIssue,
    useUnassignPaper
} from '@/hooks/queries/usePublications';
import { useState } from 'react';
import { toast } from 'sonner';
import { motion, AnimatePresence } from 'framer-motion';
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Label } from "@/components/ui/label";
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
    DialogFooter
} from "@/components/ui/dialog";

export default function PublicationsPage() {
    const { data: volumes = [], isLoading: loading } = useVolumesIssues();
    const createMutation = useCreateVolumeIssue();
    const updateMutation = useUpdateVolumeIssue();
    const deleteMutation = useDeleteVolumeIssue();
    const publishMutation = usePublishIssue();
    const unassignMutation = useUnassignPaper();

    const [showCreateModal, setShowCreateModal] = useState(false);
    const [showEditModal, setShowEditModal] = useState<any>(null);
    const [expandedIssue, setExpandedIssue] = useState<number | null>(null);
    const [isSubmitting, setIsSubmitting] = useState(false);

    const { data: issuePapers = [], isLoading: loadingPapers } = usePapersByIssue(expandedIssue);

    async function handleCreate(formData: FormData) {
        setIsSubmitting(true);
        toast.promise(
            createMutation.mutateAsync(formData).then((res) => {
                if (!res.success) throw new Error(res.error || "Failed to initialize cycle");
                return res;
            }),
            {
                loading: 'Deploying publication cycle...',
                success: () => { setShowCreateModal(false); return 'Publication cycle initialized'; },
                error: (err) => err.message,
            }
        );
        setIsSubmitting(false);
    }

    async function handlePublish(id: number) {
        if (!confirm('Are you sure you want to PUBLISH this issue? This will also update the status of all assigned papers.')) return;
        toast.promise(
            publishMutation.mutateAsync(id).then((res) => {
                if (!res.success) throw new Error(res.error || "Failed to publish issue");
                return res;
            }),
            {
                loading: 'Publishing issue & updating all manuscripts...',
                success: 'Issue published successfully',
                error: (err) => err.message,
            }
        );
    }

    function toggleExpand(id: number) {
        setExpandedIssue(expandedIssue === id ? null : id);
    }

    async function handleUnassign(paperId: number) {
        if (!confirm('Unlink this paper from this issue? Its status will revert to "Paid".')) return;
        toast.promise(
            unassignMutation.mutateAsync(paperId).then((res) => {
                if (!res.success) throw new Error(res.error || "Failed to unassign paper");
                return res;
            }),
            {
                loading: 'Unlinking paper from issue...',
                success: 'Paper unassigned successfully',
                error: (err) => err.message,
            }
        );
    }

    async function handleEdit(formData: FormData) {
        if (!showEditModal) return;
        setIsSubmitting(true);
        toast.promise(
            updateMutation.mutateAsync({ id: showEditModal.id, formData }).then((res) => {
                if (!res.success) throw new Error(res.error || "Failed to update metadata");
                return res;
            }),
            {
                loading: 'Committing parameter updates...',
                success: () => { setShowEditModal(null); return 'Metadata updated successfully'; },
                error: (err) => err.message,
            }
        );
        setIsSubmitting(false);
    }

    async function handleDelete(id: number) {
        if (!confirm('Delete this issue? All assigned papers will be unlinked and reverted to "Paid" status.')) return;
        toast.promise(
            deleteMutation.mutateAsync(id).then((res) => {
                if (!res.success) throw new Error(res.error || "Failed to delete issue");
                return res;
            }),
            {
                loading: 'Removing publication cycle...',
                success: 'Issue deleted successfully',
                error: (err) => err.message,
            }
        );
    }


    const stats = {
        totalVolumes: new Set(volumes.map(v => v.volume_number)).size,
        publishedIssues: volumes.filter(v => v.status === 'published').length,
        openIssues: volumes.filter(v => v.status === 'open').length,
        totalPapers: volumes.reduce((acc, v) => acc + (v.paper_count || 0), 0)
    };

    if (loading) {
        return (
            <div className="p-32 text-center space-y-6">
                <div className="w-14 h-14 border-[3px] border-primary/20 border-t-primary rounded-full animate-spin mx-auto" />
                <p className="font-black text-primary/40 tracking-[0.4em] text-xs animate-pulse uppercase">Syncing Publication Registry...</p>
            </div>
        );
    }

    return (
        <section className="space-y-12 pb-24 max-w-7xl 2xl:max-w-[1900px] mx-auto overflow-visible">
            {/* Header */}
            <header className="flex flex-col lg:flex-row lg:items-end justify-between gap-8 border-b border-primary/5 pb-12">
                <div className="space-y-4">
                    <div className="flex items-center gap-3">
                        <div className="w-12 h-12 2xl:w-20 2xl:h-20 bg-secondary/10 rounded-3xl flex items-center justify-center border border-secondary/20 shadow-inner">
                            <BookOpen className="w-6 h-6 2xl:w-10 2xl:h-10 text-secondary" />
                        </div>
                        <h1 className="font-serif font-black text-foreground tracking-tighter uppercase leading-none text-3xl xl:text-4xl 2xl:text-6xl">
                            Journal <span className="text-primary opacity-50">Archives</span>
                        </h1>
                    </div>
                    <p className="text-xs sm:text-sm 2xl:text-2xl font-bold text-muted-foreground border-l-4 border-primary/50 pl-6 py-1 max-w-2xl leading-relaxed">
                        Orchestrate the global publication schedule, manage volume hierarchies, and lock immutable archival cycles.
                    </p>
                </div>

                <Dialog open={showCreateModal} onOpenChange={setShowCreateModal}>
                    <DialogTrigger asChild>
                        <Button className="h-14 2xl:h-20 px-12 2xl:px-20 gap-4 bg-secondary text-white dark:text-black font-black text-[10px] 2xl:text-2xl tracking-[0.3em] rounded-2xl 2xl:rounded-3xl shadow-2xl shadow-secondary/20 hover:scale-[1.02] active:scale-[0.98] transition-all cursor-pointer border-t border-white/20">
                            <Plus className="w-6 h-6 2xl:w-10 2xl:h-10" /> Deploy New Cycle
                        </Button>
                    </DialogTrigger>
                    <DialogContent className="sm:max-w-md rounded-4xl p-10 bg-card border-primary/5 shadow-3xl overflow-hidden glassmorphism">
                        <DialogHeader className="space-y-6">
                            <div className="w-16 h-16 rounded-2xl bg-secondary/10 border border-secondary/20 flex items-center justify-center text-secondary shadow-inner">
                                <Plus className="w-8 h-8" />
                            </div>
                            <div className="space-y-2">
                                <DialogTitle className="text-3xl font-black text-foreground tracking-tight uppercase">Initialize Hub</DialogTitle>
                                <DialogDescription className="text-xs font-bold text-muted-foreground leading-relaxed tracking-widest uppercase opacity-60">
                                    Define a new volume or issue for manuscript aggregation.
                                </DialogDescription>
                            </div>
                        </DialogHeader>
                        <form action={handleCreate} className="space-y-6 pt-6">
                            <div className="grid grid-cols-2 gap-6">
                                <div className="space-y-3">
                                    <Label className="text-[10px] font-black text-primary/60 tracking-[0.2em] px-1 uppercase">Volume Number</Label>
                                    <Input
                                        name="volume"
                                        type="number"
                                        required
                                        className="h-14 bg-primary/5 border-primary/5 focus-visible:ring-2 focus-visible:ring-secondary/20 font-black text-base shadow-inner rounded-2xl px-6"
                                        placeholder="e.g. 1"
                                    />
                                </div>
                                <div className="space-y-3">
                                    <Label className="text-[10px] font-black text-primary/60 tracking-[0.2em] px-1 uppercase">Issue Number</Label>
                                    <Input
                                        name="issue"
                                        type="number"
                                        required
                                        className="h-14 bg-primary/5 border-primary/5 focus-visible:ring-2 focus-visible:ring-secondary/20 font-black text-base shadow-inner rounded-2xl px-6"
                                        placeholder="e.g. 1"
                                    />
                                </div>
                            </div>

                            <div className="space-y-3">
                                <Label className="text-[10px] font-black text-primary/60 tracking-[0.2em] px-1 uppercase">Publication Year</Label>
                                <Input
                                    name="year"
                                    type="number"
                                    required
                                    defaultValue={new Date().getFullYear()}
                                    className="h-14 bg-primary/5 border-primary/5 focus-visible:ring-2 focus-visible:ring-secondary/20 font-black text-base shadow-inner rounded-2xl px-6"
                                />
                            </div>

                            <div className="space-y-3">
                                <Label className="text-[10px] font-black text-primary/60 tracking-[0.2em] px-1 uppercase">Cycle Duration</Label>
                                <Input
                                    name="monthRange"
                                    type="text"
                                    required
                                    placeholder="e.g. Jan - Mar"
                                    className="h-14 bg-primary/5 border-primary/5 focus-visible:ring-2 focus-visible:ring-secondary/20 font-black text-base shadow-inner rounded-2xl px-6"
                                />
                            </div>

                            <DialogFooter className="pt-4">
                                <Button disabled={isSubmitting} type="submit" className="w-full h-16 bg-secondary text-white dark:text-black font-black text-xs tracking-[0.2em] shadow-2xl shadow-secondary/20 hover:scale-[1.02] transition-all rounded-2xl cursor-pointer uppercase border-t border-white/20">
                                    {isSubmitting ? (
                                        <div className="w-6 h-6 border-3 border-white/20 border-t-white rounded-full animate-spin" />
                                    ) : (
                                        'Commit Publication Node'
                                    )}
                                </Button>
                            </DialogFooter>
                        </form>
                    </DialogContent>
                </Dialog>
            </header>

            {/* Publication Metrics */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
                {[
                    { label: 'Total Volumes', value: stats.totalVolumes, icon: Layers, color: 'text-indigo-600', bg: 'bg-indigo-500/10' },
                    { label: 'Published Issues', value: stats.publishedIssues, icon: CheckCircle2, color: 'text-emerald-600', bg: 'bg-emerald-500/10' },
                    { label: 'Open Cycles', value: stats.openIssues, icon: Clock, color: 'text-orange-600', bg: 'bg-orange-500/10' },
                    { label: 'Papers Indexed', value: stats.totalPapers, icon: FileText, color: 'text-blue-600', bg: 'bg-blue-500/10' },
                ].map((item, idx) => (
                    <motion.div
                        key={item.label}
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ delay: idx * 0.1 }}
                        className="p-8 bg-card rounded-4xl shadow-vip border-none group hover:scale-[1.02] transition-all duration-300 relative overflow-hidden"
                    >
                        <div className={`absolute top-0 right-0 w-20 h-20 ${item.bg} rounded-full -mr-10 -mt-10 blur-2xl opacity-50 group-hover:opacity-100 transition-opacity`} />
                        <div className="flex items-center justify-between relative z-10">
                            <div className="space-y-1">
                                <p className="text-[10px] font-black text-muted-foreground tracking-[0.2em] uppercase">{item.label}</p>
                                <h3 className="text-3xl 2xl:text-5xl font-black text-foreground tracking-tighter">{item.value}</h3>
                            </div>
                            <div className={`w-14 h-14 2xl:w-20 2xl:h-20 rounded-3xl ${item.bg} flex items-center justify-center border border-primary/5 shadow-sm group-hover:rotate-6 transition-transform duration-500`}>
                                <item.icon className={`w-6 h-6 2xl:w-10 2xl:h-10 ${item.color}`} />
                            </div>
                        </div>
                    </motion.div>
                ))}
            </div>


            {/* Grid of Issues */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10 xl:gap-14">
                {volumes.map((v, idx) => (
                    <motion.div
                        key={v.id}
                        initial={{ opacity: 0, scale: 0.95 }}
                        animate={{ opacity: 1, scale: 1 }}
                        transition={{ delay: idx * 0.05 }}
                    >
                        <Card className="border-primary/5 shadow-vip hover:shadow-2xl transition-all duration-500 group overflow-hidden bg-card relative rounded-[2.5rem] border-t-4 border-t-transparent hover:border-t-secondary/40">
                            <div className={`absolute top-0 left-0 w-1.5 h-full ${v.status === 'published' ? 'bg-emerald-500/40' : 'bg-orange-500/40'} opacity-50`} />
                            <CardContent className="p-0">
                                <div className="p-10 xl:p-14 space-y-10">
                                    <div className="flex items-start justify-between gap-6">
                                        <div className="space-y-3">
                                            <div className="flex items-center gap-3">
                                                <p className="text-[10px] 2xl:text-base font-black text-primary/30 tracking-[0.4em] uppercase">Archive Node {v.volume_number}</p>
                                                <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-all duration-300 translate-x-4 group-hover:translate-x-0">
                                                    <button title='Edit Metadata' onClick={() => setShowEditModal(v)} className="p-2 2xl:p-4 hover:text-secondary transition-colors hover:bg-secondary/10 rounded-xl border border-transparent hover:border-secondary/20">
                                                        <Save className="w-4 h-4 2xl:w-8 2xl:h-8" />
                                                    </button>
                                                    <button title='Remove Node' onClick={() => handleDelete(v.id)} className="p-2 2xl:p-4 hover:text-red-500 transition-colors hover:bg-red-500/10 rounded-xl border border-transparent hover:border-red-500/20">
                                                        <Trash2 className="w-4 h-4 2xl:w-8 2xl:h-8" />
                                                    </button>
                                                </div>
                                            </div>
                                            <h3 className="font-serif font-black text-foreground tracking-tight leading-none group-hover:text-primary transition-colors text-2xl xl:text-3xl 2xl:text-5xl uppercase">
                                                Issue <span className="opacity-40">{v.issue_number}</span>
                                            </h3>
                                        </div>
                                        <Badge className={`h-10 2xl:h-14 px-5 2xl:px-8 text-[10px] 2xl:text-lg font-black tracking-[0.2em] border-none rounded-2xl shadow-xl uppercase ${v.status === 'published' ? 'bg-emerald-500 text-white shadow-emerald-500/10' : 'bg-orange-500 text-white shadow-orange-500/10'}`}>
                                            {v.status === 'published' ? (
                                                <span className="flex items-center gap-3"><Globe className="w-5 h-5 2xl:w-8 2xl:h-8" /> Indexed</span>
                                            ) : (
                                                <span className="flex items-center gap-3"><Clock className="w-5 h-5 2xl:w-8 2xl:h-8" /> Staging</span>
                                            )}
                                        </Badge>
                                    </div>

                                    <div className="grid grid-cols-2 gap-6 2xl:gap-10">
                                        <div className="bg-primary/3 p-6 2xl:p-10 rounded-4xl border border-primary/5 shadow-inner group-hover:bg-primary/5 transition-colors">
                                            <Calendar className="w-6 h-6 2xl:w-10 2xl:h-10 text-primary/20 mb-4" />
                                            <p className="text-[10px] 2xl:text-base font-black text-primary/30 tracking-[0.2em] mb-2 uppercase leading-none">Fiscal Year</p>
                                            <p className="text-xl 2xl:text-4xl font-black text-primary tracking-tighter">{v.year}</p>
                                        </div>
                                        <div className="bg-primary/3 p-6 2xl:p-10 rounded-4xl border border-primary/5 shadow-inner group-hover:bg-primary/5 transition-colors">
                                            <Layers className="w-6 h-6 2xl:w-10 2xl:h-10 text-primary/20 mb-4" />
                                            <p className="text-[10px] 2xl:text-base font-black text-primary/30 tracking-[0.2em] mb-2 uppercase leading-none">Cycle Window</p>
                                            <p className="text-xl 2xl:text-3xl font-black text-primary truncate tracking-tighter uppercase">{v.month_range}</p>
                                        </div>
                                    </div>

                                    <div className="space-y-4 2xl:space-y-8">
                                        <Button
                                            variant="outline"
                                            onClick={() => toggleExpand(v.id)}
                                            className="w-full h-14 2xl:h-24 gap-4 2xl:gap-6 border-primary/10 text-primary font-black text-[10px] 2xl:text-2xl tracking-[0.3em] rounded-2xl 2xl:rounded-[2.5rem] hover:bg-primary hover:text-white shadow-xl shadow-primary/5 uppercase transition-all duration-300"
                                        >
                                            {expandedIssue === v.id ? <ChevronUp className="w-6 h-6 2xl:w-10 2xl:h-10" /> : <ChevronDownIcon className="w-6 h-6 2xl:w-10 2xl:h-10" />}
                                            {expandedIssue === v.id ? 'Collapse Dossier' : `Access Manuscripts (${v.paper_count || 0})`}
                                        </Button>

                                        <AnimatePresence>
                                            {expandedIssue === v.id && (
                                                <motion.div
                                                    initial={{ height: 0, opacity: 0 }}
                                                    animate={{ height: 'auto', opacity: 1 }}
                                                    exit={{ height: 0, opacity: 0 }}
                                                    className="overflow-hidden bg-primary/2 rounded-4xl border border-primary/10 shadow-inner"
                                                >
                                                    <div className="p-6 xl:p-10 space-y-4">
                                                        {loadingPapers ? (
                                                            <div className="py-12 text-center">
                                                                <div className="w-10 h-10 border-4 border-primary/10 border-t-primary rounded-full animate-spin mx-auto" />
                                                            </div>
                                                        ) : issuePapers.length > 0 ? (
                                                            <div className="space-y-4">
                                                                {issuePapers.map((paper) => (
                                                                    <div key={paper.id} className="p-6 bg-card rounded-2xl border border-primary/5 shadow-sm space-y-3 group/paper relative overflow-hidden transition-all hover:border-secondary/20">
                                                                        <div className="absolute top-0 left-0 w-1 h-full bg-secondary/10 group-hover/paper:bg-secondary/40 transition-colors" />
                                                                        <div className="flex items-start justify-between gap-6 relative z-10">
                                                                            <div className="min-w-0 space-y-1">
                                                                                <p className="text-xs 2xl:text-xl font-black text-primary tracking-tight leading-tight line-clamp-2 uppercase">{paper.title}</p>
                                                                                <p className="text-[10px] 2xl:text-base font-bold text-muted-foreground mt-1 uppercase tracking-widest opacity-40">Registry: {paper.paper_id}</p>
                                                                            </div>
                                                                            <div className="flex items-center gap-3 shrink-0">
                                                                                <Button asChild variant="ghost" size="icon" className="w-10 h-10 2xl:w-16 2xl:h-16 text-primary/40 hover:text-primary hover:bg-primary/10 rounded-xl transition-all cursor-pointer">
                                                                                    <a title='Inspect Manuscript' href={`/admin/submissions/${paper.id}`} target="_blank">
                                                                                        <Eye className="w-5 h-5 2xl:w-8 2xl:h-8" />
                                                                                    </a>
                                                                                </Button>
                                                                                <Button title='Unlink from Node' onClick={() => handleUnassign(paper.id)} variant="ghost" size="icon" className="w-10 h-10 2xl:w-16 2xl:h-16 text-red-500/40 hover:text-red-500 hover:bg-red-500/10 rounded-xl transition-all">
                                                                                    <Unlink className="w-5 h-5 2xl:w-8 2xl:h-8" />
                                                                                </Button>
                                                                            </div>
                                                                        </div>
                                                                    </div>
                                                                ))}
                                                            </div>
                                                        ) : (
                                                            <div className="py-20 text-center space-y-4">
                                                                <FileText className="w-12 h-12 2xl:w-20 2xl:h-20 text-primary/10 mx-auto" />
                                                                <p className="text-[10px] 2xl:text-xl font-black text-primary/20 tracking-[0.4em] uppercase">No Manuscripts Indexed</p>
                                                            </div>
                                                        )}
                                                    </div>
                                                </motion.div>
                                            )}
                                        </AnimatePresence>

                                        {v.status === 'open' ? (
                                            <Button
                                                onClick={() => handlePublish(v.id)}
                                                className="w-full h-16 2xl:h-28 gap-4 2xl:gap-6 bg-secondary text-white dark:text-black font-black text-[10px] sm:text-xs 2xl:text-2xl tracking-[0.4em] shadow-2xl shadow-secondary/20 rounded-2xl 2xl:rounded-[2.5rem] hover:bg-emerald-600 transition-all uppercase border-t border-white/20 active:scale-[0.98]"
                                            >
                                                <CheckCircle className="w-6 h-6 2xl:w-10 2xl:h-10" /> Finalize Archives
                                            </Button>
                                        ) : (
                                            <div className="w-full h-16 2xl:h-28 bg-emerald-500/5 text-emerald-600 rounded-2xl 2xl:rounded-[2.5rem] font-black text-xs 2xl:text-2xl tracking-[0.4em] flex items-center justify-center gap-4 2xl:gap-8 border border-emerald-500/10 shadow-inner uppercase">
                                                <Globe className="w-6 h-6 2xl:w-12 2xl:h-12" /> Immutable Vault LOCKED
                                            </div>
                                        )}
                                    </div>
                                </div>
                            </CardContent>
                        </Card>
                    </motion.div>
                ))}

                {volumes.length === 0 && (
                    <div className="col-span-full py-60 bg-primary/2 border-2 border-dashed border-primary/10 rounded-[4rem] flex flex-col items-center justify-center text-center shadow-inner space-y-10 group hover:bg-primary/4 transition-colors">
                        <div className="w-32 h-32 2xl:w-48 2xl:h-48 rounded-4xl 2xl:rounded-[4rem] bg-card border border-primary/10 flex items-center justify-center text-primary/10 shadow-2xl group-hover:scale-110 transition-transform">
                            <BookOpen className="w-16 h-16 2xl:w-24 2xl:h-24" />
                        </div>
                        <div className="space-y-4">
                            <h3 className="font-serif font-black text-primary/40 tracking-tight uppercase text-3xl xl:text-4xl 2xl:text-6xl leading-none">Global Vault Offline</h3>
                            <p className="text-xs 2xl:text-2xl font-bold text-primary/20 tracking-widest max-w-2xl leading-relaxed uppercase mx-auto px-10">No publication cycles detected in the primary registry. Initialize the first volume to begin manuscript orchestration.</p>
                        </div>
                    </div>
                )}
            </div>

            {/* Edit Modal */}
            <Dialog open={!!showEditModal} onOpenChange={(open) => !open && setShowEditModal(null)}>
                <DialogContent className="sm:max-w-md rounded-xl p-8 bg-card border-primary/5 shadow-2xl overflow-hidden">
                    <div className="absolute top-0 left-0 w-full h-2 bg-secondary/10" />
                    <DialogHeader className="space-y-4">
                        <div className="w-12 h-12 rounded-xl bg-secondary/5 border border-secondary/10 flex items-center justify-center text-secondary shadow-inner mb-0">
                            <Save className="w-6 h-6" />
                        </div>
                        <DialogTitle className="text-xl sm:text-2xl 2xl:text-3xl font-black text-foreground dark:text-primary tracking-wider uppercase">Update Metadata</DialogTitle>
                        <DialogDescription className="text-[11px] 2xl:text-sm font-semibold text-muted-foreground leading-relaxed tracking-wider uppercase opacity-60">
                            Modify the archival parameters for this publication node.
                        </DialogDescription>
                    </DialogHeader>
                    {showEditModal && (
                        <form action={handleEdit} className="space-y-4 pt-4">
                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-2">
                                    <Label className="text-[10px] 2xl:text-xs font-black text-primary/60 tracking-[0.2em] px-1 uppercase">Volume</Label>
                                    <Input
                                        name="volume"
                                        type="number"
                                        required
                                        defaultValue={showEditModal.volume_number}
                                        className="h-12 bg-primary/5 border-primary/5 focus-visible:ring-1 focus-visible:ring-primary/20 font-bold text-sm shadow-inner rounded-xl px-4"
                                    />
                                </div>
                                <div className="space-y-2">
                                    <Label className="text-[10px] 2xl:text-xs font-black text-primary/60 tracking-[0.2em] px-1 uppercase">Issue</Label>
                                    <Input
                                        name="issue"
                                        type="number"
                                        required
                                        defaultValue={showEditModal.issue_number}
                                        className="h-12 bg-primary/5 border-primary/5 focus-visible:ring-1 focus-visible:ring-primary/20 font-bold text-sm shadow-inner rounded-xl px-4"
                                    />
                                </div>
                            </div>

                            <div className="space-y-2">
                                <Label className="text-[10px] 2xl:text-xs font-black text-primary/60 tracking-[0.2em] px-1 uppercase">Year</Label>
                                <Input
                                    name="year"
                                    type="number"
                                    required
                                    defaultValue={showEditModal.year}
                                    className="h-12 bg-primary/5 border-primary/5 focus-visible:ring-1 focus-visible:ring-primary/20 font-black text-sm shadow-inner rounded-xl px-4"
                                />
                            </div>

                            <div className="space-y-2">
                                <Label className="text-[10px] 2xl:text-xs font-black text-primary/60 tracking-[0.2em] px-1 uppercase">Month Range</Label>
                                <Input
                                    name="monthRange"
                                    type="text"
                                    required
                                    defaultValue={showEditModal.month_range}
                                    className="h-12 bg-primary/5 border-primary/5 focus-visible:ring-1 focus-visible:ring-primary/20 font-bold text-sm shadow-inner rounded-xl px-4"
                                />
                            </div>

                            <DialogFooter className="pt-2">
                                <Button disabled={isSubmitting} type="submit" className="w-full h-12 font-black text-[10px] 2xl:text-base tracking-[0.2em] bg-secondary text-white shadow-xl shadow-secondary/20 hover:scale-[1.02] transition-all rounded-xl cursor-pointer uppercase">
                                    {isSubmitting ? (
                                        <div className="w-5 h-5 border-2 border-white/20 border-t-white rounded-full animate-spin" />
                                    ) : (
                                        'Commit Parameter Updates'
                                    )}
                                </Button>
                            </DialogFooter>
                        </form>
                    )}
                </DialogContent>
            </Dialog>
        </section>
    );
}

