export async function generateMetadata({ params }: { params: Promise<{ id: string }> }): Promise<Metadata> {
    const { id } = await params;
    const response = await getSubmissionById(parseInt(id));
    const submission = response.data;
    if (!response.success || !submission) return { title: 'Submission Not Found | Admin' };

    return {
        title: `Manage: ${submission.paper_id} | IJITEST Admin`,
        description: `Administrative oversight for manuscript ${submission.paper_id}: ${submission.title}`,
    };
}

export default async function SubmissionDetails({ params }: { params: Promise<{ id: string }> }) {
    const { id: idStr } = await params;
    const id = parseInt(idStr);

    if (isNaN(id)) {
        return (
            <div className="flex flex-col items-center justify-center min-h-[50vh] p-6 text-center">
                <AlertCircle className="w-12 h-12 text-muted-foreground/20 mb-4" />
                <h2 className=" font-semibold text-foreground tracking-wider mb-2">Invalid Identification</h2>
                <p className="text-xs font-medium text-muted-foreground mb-6">The manuscript reference provided is not in a valid numerical format.</p>
                <Button asChild variant="outline" className="h-10 px-6 font-semibold text-[10px]  tracking-widest rounded-xl cursor-pointer">
                    <Link className="cursor-pointer" href="/admin/submissions">Return to Repository</Link>
                </Button>
            </div>
        );
    }

    const response = await getSubmissionById(id);
    const submission = response.data;

    if (!response.success || !submission) {
        return (
            <div className="flex flex-col items-center justify-center min-h-[50vh] p-6 text-center">
                <div className="w-16 h-16 rounded-full bg-muted flex items-center justify-center mb-6">
                    <FileText className="w-8 h-8 text-muted-foreground/30" />
                </div>
                <h2 className=" font-semibold text-foreground tracking-wider mb-2">Manuscript Not Found</h2>
                <p className="text-xs font-medium text-muted-foreground mb-6 max-w-sm">The requested manuscript (Ref: {id}) could not be located in the primary database node.</p>
                <Button asChild variant="outline" className="h-10 px-6 font-semibold text-[10px]  tracking-widest rounded-xl cursor-pointer">
                    <Link className="cursor-pointer" href="/admin/submissions">Back to Submissions</Link>
                </Button>
            </div>
        );
    }

    const getStatusVariant = (status: string) => {
        switch (status) {
            case 'submitted': return 'bg-indigo-500/10 text-indigo-600 border-none';
            case 'under_review': return 'bg-amber-500/10 text-amber-600 border-none';
            case 'accepted': return 'bg-purple-500/10 text-purple-600 border-none';
            case 'paid': return 'bg-emerald-500/10 text-emerald-600 border-none';
            case 'published': return 'bg-cyan-500/10 text-cyan-600 border-none';
            case 'rejected': return 'bg-rose-500/10 text-rose-600 border-none';
            default: return 'bg-muted text-muted-foreground border-none';
        }
    };

    return (
        <section className="space-y-6 pb-20">
            {/* Breadcrumb / Top Bar */}
            <div className="flex items-center justify-between gap-4">
                <Button asChild variant="ghost" size="sm" className="h-9 gap-2 text-muted-foreground hover:text-primary font-semibold text-[10px]  tracking-widest -ml-2 cursor-pointer">
                    <Link className="cursor-pointer" href="/admin/submissions">
                        <ChevronLeft className="w-4 h-4" /> Submissions Console
                    </Link>
                </Button>
            </div>

            <Card className="border-border/50 shadow-lg overflow-hidden bg-background 2xl:rounded-3xl">
                <CardHeader className="p-8 bg-muted/20 border-b border-border/50">
                    <div className="flex flex-col md:flex-row md:items-start justify-between gap-6">
                        <div className="space-y-4 max-w-2xl 2xl:max-w-4xl">
                            <Badge className={`h-5 2xl:h-9 px-1.5 2xl:px-4 text-[9px] 2xl:text-base font-semibold tracking-widest whitespace-nowrap capitalize ${getStatusVariant(submission.status)}`}>
                                {submission.status.replace('_', ' ')}
                            </Badge>
                            <h1 className="font-serif text-2xl xl:text-3xl 2xl:text-4xl font-semibold text-foreground tracking-tight capitalize leading-none">
                                {submission.title}
                            </h1>
                            <div className="flex flex-wrap items-center gap-6 2xl:gap-10 text-[9px] xl:text-xs 2xl:text-base font-semibold text-muted-foreground tracking-widest capitalize">
                                <div className="flex items-center gap-2 2xl:gap-4">
                                    <Clock className="w-3.5 h-3.5 2xl:w-6 2xl:h-6 opacity-50" />
                                    <span>{new Date((submission as any).submitted_at).toLocaleDateString(undefined, { dateStyle: 'long' })}</span>
                                </div>
                                <div className="flex items-center gap-2 2xl:gap-4 text-primary">
                                    <Shield className="w-3.5 h-3.5 2xl:w-5 2xl:h-5" />
                                    <span>{(submission as any).paper_id}</span>
                                </div>
                                {(submission as any).keywords && (
                                    <div className="flex items-center gap-2 2xl:gap-4">
                                        <Tag className="w-3.5 h-3.5 2xl:w-6 2xl:h-6 opacity-50" />
                                        <span className="truncate max-w-[200px] 2xl:max-w-md">{(submission as any).keywords}</span>
                                    </div>
                                )}
                            </div>
                        </div>
                        <div className="flex flex-col gap-2 2xl:gap-4 shrink-0">
                            {submission.file_path && (
                                <Button asChild className="h-10 xl:h-12 2xl:h-14 px-6 gap-2 bg-primary text-white font-semibold text-[9px] xl:text-xs 2xl:text-sm capitalize tracking-widest rounded-xl shadow-xl shadow-primary/20 hover:scale-[1.05] hover:opacity-90 transition-all cursor-pointer">
                                    <a href={submission.file_path} download>
                                        <Download className="w-4 h-4 2xl:w-6 2xl:h-6" /> Download manuscript
                                    </a>
                                </Button>
                            )}
                            <p className="text-[9px] sm:text-[10px] xl:text-[11px] 2xl:text-base font-semibold text-muted-foreground text-center tracking-widest opacity-60">Authored by {submission.author_name}</p>
