                            <div className="space-y-2">
                                <label htmlFor="staff-role" className="text-xs font-semibold text-muted-foreground tracking-widest px-1 uppercase">User Role</label>
                                <select id="staff-role" name="role" required className="flex h-12 w-full rounded-xl bg-muted/50 px-3 py-1 text-sm font-semibold transition-colors outline-none border-none ring-offset-background placeholder:text-muted-foreground focus:ring-1 focus:ring-primary/30 disabled:cursor-not-allowed disabled:opacity-50 text-foreground">
                                    <option value="reviewer">Reviewer (Expert witness)</option>
                                    <option value="editor">Editor (Decision-maker)</option>
                                    <option value="admin">Administrator (Architect)</option>
                                </select>
                            </div>
                            <DialogFooter className="pt-4">
                                <Button type="submit" className="w-full h-12 font-semibold text-xs tracking-widest shadow-xl shadow-primary/20 rounded-xl bg-primary text-white dark:text-slate-900 hover:bg-primary/90 cursor-pointer">
                                    Send Invitation
                                </Button>
                            </DialogFooter>
                        </form>
                    </DialogContent>
                </Dialog>
                </div>
            </header>

            {/* Users Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 2xl:gap-8 transition-all duration-500">
                {users.length === 0 ? (
                    <div className="col-span-full py-20 bg-muted/20 border-2 border-dashed border-border/50 rounded-xl flex flex-col items-center justify-center text-center">
                        <Users className="w-10 h-10 text-muted-foreground/20 mb-4" />
                        <h3 className=" font-semibold text-muted-foreground tracking-wider">No Staff Found</h3>
                        <p className="text-[10px] font-medium text-muted-foreground  tracking-widest ">Start by adding your first team member.</p>
                    </div>
                ) : users.map((user) => (
                    <Card key={user.id} className="border-border/50 shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all duration-300 group overflow-hidden bg-card/50 backdrop-blur-sm">
                        <CardContent className="p-5">
                            <div className="flex items-center gap-4 mb-5">
                                <div className="w-14 h-14 rounded-xl bg-muted flex items-center justify-center text-muted-foreground group-hover:bg-primary/20 group-hover:text-primary transition-all duration-300 border border-border/10 shrink-0 shadow-inner">
                                    <UserCog className="w-8 h-8" />
                                </div>
                                <div className="min-w-0">
                                    <h3 className="font-semibold text-foreground tracking-wider truncate leading-none mb-2 transition-all duration-500 text-sm xl:text-base 2xl:text-xl">{user.profile?.fullName || 'No Name'}</h3>
                                    <Badge className={`h-5 xl:h-6 2xl:h-8 px-2 xl:px-3 2xl:px-5 text-[9px] xl:text-xs 2xl:text-sm font-semibold tracking-widest border-none shadow-sm transition-all duration-500 capitalize ${getRoleVariant(user.role)}`}>
                                        {user.role}
                                    </Badge>
                                </div>
                                {user.role === 'admin' && (
                                    <div className="ml-auto opacity-20 group-hover:opacity-100 transition-opacity">
                                        <Shield className="w-4 h-4 text-emerald-600" />
                                    </div>
                                )}
                            </div>

                            <div className="space-y-4 mb-6 2xl:space-y-6">
                                <div className="flex items-center gap-3 text-[9px] xl:text-xs 2xl:text-sm font-semibold text-muted-foreground/80 truncate bg-muted/30 px-3 py-2 xl:px-4 xl:py-2.5 2xl:px-6 2xl:py-3.5 rounded-xl border border-border/5">
                                    <Mail className="w-3.5 h-3.5 xl:w-4 xl:h-4 2xl:w-5 2xl:h-5 opacity-40 text-primary" />
                                    <span>{user.email}</span>
                                </div>
                                <div className="flex items-center gap-2.5 text-[10px] 2xl:text-base font-semibold text-muted-foreground tracking-widest px-1">
                                    <ShieldCheck className="w-4 h-4 2xl:w-6 2xl:h-6 opacity-30" />
                                    <span>Member since {user.createdAt ? new Date(user.createdAt).toLocaleDateString('en-US', { month: 'short', year: 'numeric' }) : 'Unknown'}</span>
                                </div>
                            </div>

                            <Separator className="mb-4 opacity-50" />

                             <div className="pt-2 2xl:pt-6">
                                <p className="text-[9px] xl:text-xs 2xl:text-sm font-semibold text-muted-foreground capitalize tracking-widest mb-3 2xl:mb-6">Administrative controls</p>
                                <div className="flex items-center justify-between gap-4">
                                    <Badge variant="outline" className="text-[10px] 2xl:text-base font-mono font-semibold text-muted-foreground/50 tracking-widest bg-muted/20 border-border/20 px-2.5 py-1 2xl:px-4 2xl:py-2">
                                        ID-{String(user.id).padStart(3, '0')}
                                    </Badge>
                                    {session?.user && String((session.user as any).id) === String(user.id) ? (
                                        <Badge variant="outline" className="h-10 2xl:h-16 px-5 2xl:px-10 text-xs 2xl:text-lg font-semibold tracking-widest text-emerald-600 border-emerald-500/20 bg-emerald-500/5 rounded-xl uppercase flex items-center gap-2.5">
                                            <ShieldCheck className="w-4 h-4 2xl:w-6 2xl:h-6" /> My Active Session
                                        </Badge>
                                    ) : (
                                        <Button
                                            variant="destructive"
                                            size="sm"
                                            onClick={() => setUserToDelete(user)}
                                            className="h-10 2xl:h-16 px-5 2xl:px-10 gap-2.5 bg-rose-600 hover:bg-rose-700 text-white border-none rounded-xl 2xl:rounded-2xl transition-all text-xs 2xl:text-lg font-semibold uppercase tracking-widest shadow-lg shadow-rose-600/20 active:scale-95 cursor-pointer"
                                        >
                                            <Trash2 className="w-4.5 h-4.5 2xl:w-6 2xl:h-6" /> Delete Account
                                        </Button>
                                    )}
                                </div>
                            </div>
                        </CardContent>
                    </Card>
                ))}
            </div>

            {/* Delete Confirmation Modal */}
            <Dialog open={!!userToDelete} onOpenChange={(open) => !open && setUserToDelete(null)}>
                <DialogContent className="sm:max-w-md rounded-xl p-6">
                    <DialogHeader className="space-y-3">
                        <div className="w-12 h-12 rounded-xl bg-destructive/10 flex items-center justify-center text-destructive mb-2">
                            <AlertCircle className="w-6 h-6" />
                        </div>
                        <DialogTitle className="text-xl font-semibold text-foreground tracking-wider">Revoke Staff Access?</DialogTitle>
                        <DialogDescription className="text-sm font-medium text-muted-foreground leading-relaxed">
                            You are about to revoke system access for <span className="text-foreground font-semibold">{userToDelete?.profile?.fullName || 'this user'}</span>. This action will immediately invalidate their credentials and remove their administrative permissions.
                        </DialogDescription>
                    </DialogHeader>
                    <div className="bg-muted/30 p-5 rounded-xl border border-border/50 mb-2">
                        <div className="flex items-center gap-4">
                            <div className="p-2.5 bg-background rounded-xl">
                                <Mail className="w-5 h-5 text-muted-foreground" />
                            </div>
                            <div className="min-w-0">
                                <p className="text-[10px] font-semibold text-muted-foreground uppercase tracking-widest">Account email</p>
                                <p className="text-sm font-semibold text-foreground truncate">{userToDelete?.email}</p>
                            </div>
                        </div>
                    </div>
                    <DialogFooter className="flex flex-col sm:flex-row gap-3 mt-4">
                        <Button
                            variant="outline"
                            onClick={() => setUserToDelete(null)}
                            disabled={isDeleting}
                            className="flex-1 h-11 text-[11px] font-semibold uppercase tracking-widest rounded-xl"
                        >
                            Maintain Access
                        </Button>
                        <Button
                            variant="destructive"
                            onClick={async () => {
                                setIsDeleting(true);
                                try {
                                    const result = await deleteUserMutation.mutateAsync(userToDelete.id);
                                    if (result?.error) {
                                        toast.error(result.error);
                                    } else {
                                        toast.success("Staff access revoked");
                                        setUserToDelete(null);
                                    }
                                } catch (error) {
                                    toast.error("Failed to revoke staff access");
                                }
                                setIsDeleting(false);
                            }}
                            disabled={isDeleting}
                            className="flex-1 h-11 text-[11px] font-semibold uppercase tracking-widest rounded-xl shadow-lg shadow-destructive/20"
                        >
                            {isDeleting ? "Revoking..." : "Confirm Revocation"}
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>

            {/* Role Reference Guide */}
            <div className="mt-12 space-y-4">
                <div className="flex items-center gap-3 border-b border-border pb-3">
                    <h2 className="font-semibold text-foreground tracking-widest transition-all duration-500 text-xs xl:text-sm 2xl:text-lg capitalize">Role reference guide</h2>
                    <Info className="w-5 h-5 2xl:w-8 2xl:h-8 text-muted-foreground/30" />
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-3 gap-4 2xl:gap-8 transition-all duration-500">
                    {[
                        {
                            role: 'Admin',
                            title: 'The Architect',
                            desc: 'Configuration and system oversight.',
                            variant: 'primary',
                            actions: ['Creating accounts', 'Site security', 'Metadata (ISSN)', 'Bug fixing']
                        },
                        {
                            role: 'Editor',
                            title: 'The Decision-Maker',
                            desc: 'Content Flow & Life Cycle management.',
                            variant: 'blue',
                            actions: ['Screening', 'Assigning reviewers', 'Final decisions', 'Scheduling releases']
                        },
                        {
                            role: 'Reviewer',
                            title: 'The Expert Witness',
                            desc: 'Technical evaluation & control.',
                            variant: 'emerald',
                            actions: ['Reading manuscripts', 'Error/Plagiarism check', 'Providing advice']
                        }
                    ].map((guide) => (
                        <Card key={guide.role} className="border-border/50 shadow-sm">
                            <CardContent className="p-6">
                                <div className="flex flex-col gap-3 mb-5">
                                    <div className={`w-12 h-12 rounded-xl flex items-center justify-center text-white dark:text-slate-900 shadow-lg ${guide.variant === 'primary' ? 'bg-primary shadow-primary/20' : guide.variant === 'blue' ? 'bg-blue-600 shadow-blue-600/20' : 'bg-emerald-600 shadow-emerald-600/20'}`}>
                                        {guide.role === 'Admin' ? <Shield className="w-6 h-6" /> : guide.role === 'Editor' ? <UserCog className="w-6 h-6" /> : <ShieldCheck className="w-6 h-6" />}
                                    </div>
                                    <div>
                                        <h3 className="font-semibold text-foreground tracking-wider ">{guide.role} <span className="text-[11px] text-muted-foreground font-semibold uppercase block mt-1">{guide.title}</span></h3>
                                    </div>
                                </div>
                                <p className="text-sm font-semibold text-muted-foreground leading-relaxed mb-6">{guide.desc}</p>
                                <div className="space-y-2">
                                    <p className="text-[10px] font-semibold text-muted-foreground/50 tracking-widest mb-3 uppercase">Key Actions</p>
                                    {guide.actions.map((action, i) => (
                                        <div key={i} className="flex items-center gap-3 text-xs font-semibold text-foreground bg-muted/30 px-3 py-2 rounded-xl">
                                            <CheckCircle className={`w-4 h-4 ${guide.variant === 'primary' ? 'text-primary' : guide.variant === 'blue' ? 'text-blue-600' : 'text-emerald-600'}`} />
                                            {action}
                                        </div>
                                    ))}
                                </div>
                            </CardContent>
                        </Card>
                    ))}
                </div>

                 <div className="border border-border/50 rounded-xl 2xl:rounded-4xl overflow-hidden mt-6 shadow-sm overflow-x-auto">
                    <Table>
                        <TableHeader className="bg-muted/30">
                            <TableRow className="border-border/50">
                                <TableHead className="h-10 2xl:h-20 px-6 2xl:px-10 text-[10px] 2xl:text-lg font-semibold text-muted-foreground  tracking-widest">Level</TableHead>
                                <TableHead className="h-10 2xl:h-20 px-6 2xl:px-10 text-[10px] 2xl:text-lg font-semibold text-muted-foreground  tracking-widest">Focus</TableHead>
                                <TableHead className="h-10 2xl:h-20 px-6 2xl:px-10 text-[10px] 2xl:text-lg font-semibold text-muted-foreground  tracking-widest text-center">Publish?</TableHead>
                                <TableHead className="h-10 2xl:h-20 px-6 2xl:px-10 text-[10px] 2xl:text-lg font-semibold text-muted-foreground  tracking-widest text-center">Manage Staff?</TableHead>
                            </TableRow>
                        </TableHeader>
                        <TableBody>
                            {[
                                { role: 'Admin', focus: 'Infrastructure', publish: true, staff: true },
                                { role: 'Editor', focus: 'Workflow', publish: true, staff: false },
                                { role: 'Reviewer', focus: 'Accuracy', publish: false, staff: false },
                            ].map((row) => (
                                <TableRow key={row.role} className="border-border/50 hover:bg-muted/20 transition-colors">
                                    <TableCell className="px-6 py-4 2xl:px-10 2xl:py-8 font-semibold text-sm 2xl:text-2xl text-foreground">{row.role}</TableCell>
                                    <TableCell className="px-6 py-4 2xl:px-10 2xl:py-8 text-xs 2xl:text-xl font-semibold text-muted-foreground uppercase">{row.focus}</TableCell>
                                    <TableCell className="px-6 py-4 2xl:px-10 2xl:py-8 text-center">
                                        <div className={`w-2.5 h-2.5 2xl:w-5 2xl:h-5 rounded-full mx-auto ${row.publish ? 'bg-emerald-500' : 'bg-muted'}`} />
                                    </TableCell>
                                    <TableCell className="px-6 py-4 2xl:px-10 2xl:py-8 text-center">
                                        <div className={`w-2.5 h-2.5 2xl:w-5 2xl:h-5 rounded-full mx-auto ${row.staff ? 'bg-emerald-500' : 'bg-muted'}`} />
                                    </TableCell>
                                </TableRow>
                            ))}
                        </TableBody>
                    </Table>
                </div>
            </div>
        </section >
    );
}

/**
 * Author Dashboard - Modernized for IJITEST
 */
import {
    FileStack, Clock, CheckCircle, BookOpen, ArrowRight,
    AlertCircle, Upload, ExternalLink, CreditCard, Timer,
    FileText, TrendingUp, Sparkles, LayoutDashboard
} from 'lucide-react';
import Link from 'next/link';
import { redirect } from 'next/navigation';
import { getServerSession } from 'next-auth/next';
import { authOptions } from '@/lib/auth';
import { getAuthorDashboard } from '@/actions/author-submissions';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { SubmissionProgress } from '@/features/author/components/SubmissionProgress';
import { cn } from '@/lib/utils';

export const dynamic = 'force-dynamic';

const STATUS_CONFIG: Record<string, { label: string; color: string; bg: string }> = {
    submitted: { label: 'Under Editorial Review', color: 'text-blue-600', bg: 'bg-blue-500/10' },
    editor_assigned: { label: 'Editor Assigned', color: 'text-indigo-600', bg: 'bg-indigo-500/10' },
    under_review: { label: 'Peer Review In Progress', color: 'text-amber-600', bg: 'bg-amber-500/10' },
    revision_requested: { label: 'Revision Required', color: 'text-orange-600', bg: 'bg-orange-500/10' },
    accepted: { label: 'Accepted', color: 'text-emerald-600', bg: 'bg-emerald-500/10' },
    rejected: { label: 'Not Accepted', color: 'text-rose-600', bg: 'bg-rose-500/10' },
    payment_pending: { label: 'Payment Required', color: 'text-purple-600', bg: 'bg-purple-500/10' },
    published: { label: 'Published', color: 'text-emerald-700', bg: 'bg-emerald-500/15' },
};

function getDaysRemaining(updatedAt: string): number {
    const d = 15 - Math.floor((Date.now() - new Date(updatedAt).getTime()) / (1000 * 60 * 60 * 24));
    return Math.max(0, d);
}

export default async function AuthorDashboard() {
    try {
        const session: any = await getServerSession(authOptions);
        if (!session?.user) redirect('/login');
        if (session.user.role !== 'author') redirect(`/${session.user.role}`);

        const response = await getAuthorDashboard();
        const submissions = response.data?.submissions || [];

        const stats = [
            { label: 'Total Submitted', value: submissions.length, icon: <FileStack className="w-5 h-5 text-primary" /> },
            { label: 'Under Review', value: submissions.filter((s: any) => ['submitted', 'editor_assigned', 'under_review'].includes(s.status)).length, icon: <Clock className="w-5 h-5 text-amber-500" /> },
            { label: 'Accepted', value: submissions.filter((s: any) => ['accepted', 'payment_pending', 'published'].includes(s.status)).length, icon: <CheckCircle className="w-5 h-5 text-emerald-500" /> },
            { label: 'Published', value: submissions.filter((s: any) => s.status === 'published').length, icon: <BookOpen className="w-5 h-5 text-blue-500" /> },
        ];

        return (
            <section className="space-y-12 pb-20 max-w-7xl mx-auto px-4">
                {/* Header Section */}
                <header className="relative flex flex-col md:flex-row md:items-end justify-between gap-8 pt-8 outline-none">
                    <div className="space-y-4">
                        <div className="flex items-center gap-2 group">
                             <div className="p-2 rounded-xl bg-primary/10 text-primary group-hover:rotate-12 transition-transform duration-500">
                                <LayoutDashboard className="w-5 h-5" />
                             </div>
                             <span className="text-[10px] font-black uppercase tracking-[0.3em] text-primary/60">Center of Operations</span>
                        </div>
                        <h1 className="text-4xl md:text-5xl font-black text-foreground tracking-tight leading-none">
                           Welcome back, <span className="bg-linear-to-r from-primary to-primary/40 bg-clip-text text-transparent">{session.user.name?.split(' ')[0] || 'Scholar'}</span>.
                        </h1>
                        <p className="text-sm font-medium text-muted-foreground max-w-2xl leading-relaxed border-l-2 border-primary/20 pl-6">
                            IJITEST Author Portal provides end-to-end visibility into your research lifecycle — from initial submission through peer review and final branding.
                        </p>
                    </div>
                    <Button asChild className="h-14 px-8 bg-primary hover:bg-primary/90 text-white dark:text-black font-black uppercase text-xs tracking-widest rounded-2xl shadow-2xl shadow-primary/20 group">
                        <Link href="/submit" className="flex items-center gap-3">
                            <PlusIcon className="w-4 h-4 group-hover:rotate-90 transition-transform duration-300" /> Submit New Research
                        </Link>
                    </Button>
                </header>

                {/* Performance Snapshot */}
                <div className="grid grid-cols-2 lg:grid-cols-4 gap-6">
                    {stats.map((stat, idx) => (
                        <Card key={stat.label} className="group relative border-border/40 bg-background/40 backdrop-blur-xl overflow-hidden hover:border-primary/30 transition-all duration-500 rounded-3xl">
                            <CardContent className="p-8">
                                <div className="absolute top-0 right-0 w-24 h-24 bg-primary/5 rounded-bl-full -translate-y-8 translate-x-8 group-hover:scale-150 transition-transform duration-700" />
                                <div className="space-y-4 relative z-10">
                                    <div className="w-12 h-12 rounded-2xl bg-muted/50 flex items-center justify-center transition-all duration-500 group-hover:bg-primary group-hover:text-white">
                                        {stat.icon}
                                    </div>
                                    <div>
                                        <p className="text-[10px] font-black text-muted-foreground tracking-widest uppercase mb-1">{stat.label}</p>
                                        <p className="text-4xl font-black text-foreground tabular-nums tracking-tighter">{stat.value}</p>
                                    </div>
                                </div>
                            </CardContent>
                        </Card>
                    ))}
                </div>

                {/* Submissions Management */}
                <div className="space-y-8">
                    <div className="flex items-center justify-between">
                        <h2 className="text-[11px] font-black text-foreground uppercase tracking-[0.3em] flex items-center gap-3">
                           Active Manuscripts <div className="h-px w-20 bg-primary/20" />
                        </h2>
                        <div className="flex items-center gap-2 text-[10px] font-bold text-muted-foreground uppercase opacity-50">
                           Auto-sync: Active <Clock className="w-3 h-3" />
                        </div>
                    </div>

                    {submissions.length === 0 ? (
                        <Card className="border-dashed border-2 border-border/50 bg-muted/5 py-32 text-center rounded-[3rem] overflow-hidden group">
                            <CardContent className="flex flex-col items-center gap-6">
                                <div className="relative">
                                    <div className="absolute inset-0 bg-primary/20 blur-3xl rounded-full scale-150 group-hover:scale-200 transition-transform duration-1000" />
                                    <FileText className="w-16 h-16 text-primary/20 relative z-10" />
                                </div>
                                <div className="space-y-2 relative z-10">
                                    <h3 className="font-black uppercase tracking-widest text-sm">Quiet for now...</h3>
                                    <p className="text-xs text-muted-foreground max-w-xs mx-auto leading-relaxed">
                                        Your scholarly journey at IJITEST starts with your first submission. We're ready when you are.
                                    </p>
                                </div>
                                <Button asChild size="lg" className="mt-4 bg-foreground text-background hover:bg-foreground/90 font-black uppercase text-[10px] tracking-widest rounded-xl px-10">
                                    <Link href="/submit">Initialize Submission</Link>
                                </Button>
                            </CardContent>
                        </Card>
                    ) : (
                        <div className="grid grid-cols-1 gap-8">
                            {submissions.map((sub: any, idx: number) => {
                                const cfg = STATUS_CONFIG[sub.status] || { label: sub.status, color: 'text-muted-foreground', bg: 'bg-muted/30' };
                                const daysLeft = ['revision_requested', 'rejected'].includes(sub.status) ? getDaysRemaining(sub.updated_at) : null;
                                const isUrgent = daysLeft !== null && daysLeft <= 5;

                                return (
                                    <Card 
                                        key={sub.id} 
                                        className={cn(
                                            "group relative border-border/40 bg-background/50 hover:bg-background transition-all duration-500 rounded-[2.5rem] overflow-hidden shadow-sm hover:shadow-2xl hover:shadow-primary/5",
                                            isUrgent ? "border-orange-500/20" : ""
                                        )}
                                    >
                                        <CardContent className="p-0">
                                            <div className="flex flex-col lg:flex-row min-h-56">
                                                {/* Left Panel: Status & Info */}
                                                <div className="lg:w-1/3 p-8 flex flex-col justify-between border-b lg:border-b-0 lg:border-r border-border/20 bg-muted/5 group-hover:bg-transparent transition-colors">
                                                    <div className="space-y-4">
                                                        <div className="flex items-center gap-3">
                                                            <Badge variant="outline" className="px-3 py-1 text-[10px] font-black font-mono tracking-widest rounded-lg bg-background shadow-sm border-primary/20">
                                                                {sub.paperId}
                                                            </Badge>
                                                            <Badge className={cn("px-3 py-1 text-[10px] font-black uppercase tracking-wider rounded-lg border-none shadow-sm", cfg.bg, cfg.color)}>
                                                                {cfg.label}
                                                            </Badge>
                                                        </div>
                                                        <h3 className="text-xl font-bold text-foreground leading-snug group-hover:text-primary transition-colors duration-500 min-h-12">
                                                            {sub.title || "Untitled Manuscript"}
                                                        </h3>
                                                    </div>
                                                    <div className="flex items-center gap-4 pt-4">
                                                        <div className="flex -space-x-2 overflow-hidden">
                                                            {/* Placeholder for co-authors or editor */}
                                                            <div className="flex h-6 w-6 rounded-full ring-2 ring-background bg-primary/10 items-center justify-center text-[8px] font-black">AU</div>
                                                            {sub.volumeNumber && <div className="flex h-6 w-6 rounded-full ring-2 ring-background bg-emerald-500/10 items-center justify-center text-[8px] font-black text-emerald-600">PUB</div>}
                                                        </div>
                                                        <span className="text-[10px] font-bold text-muted-foreground/60 tracking-wider">
                                                           {new Date(sub.submittedAt).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })}
                                                        </span>
                                                    </div>
                                                </div>

                                                {/* Right Panel: Lifecycle & Actions */}
                                                <div className="lg:w-2/3 p-8 flex flex-col justify-between gap-8 bg-background/50">
                                                    <div className="space-y-6">
                                                        <div className="flex items-center justify-between">
                                                            <span className="text-[10px] font-black text-muted-foreground uppercase tracking-widest">Manuscript Lifecycle Roadmap</span>
                                                            {daysLeft !== null && (
