                            <div className="space-y-1">
                                <h3 className="text-lg font-black tracking-tight">Paper Published!</h3>
                                <p className="text-xs text-white/60 font-black uppercase tracking-widest">
                                    Volume {sub.publication.volume}, Issue {sub.publication.issue}
                                </p>
                            </div>
                            <Badge className="bg-white/20 text-white border-0 text-[10px] tracking-widest font-black h-8 px-5 rounded-full backdrop-blur-sm">VIEW ARCHIVE</Badge>
                        </Link>
                    )}
                </div>
            </div>
        </div>
    );
}

import { redirect, notFound } from "next/navigation";
import { getServerSession } from "next-auth/next";
import { authOptions } from "@/lib/auth";
import { checkResubmissionEligibility, getAuthorSubmission } from "@/actions/author-submissions";
import { ResubmitForm } from "@/components/forms/ResubmitForm";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { XCircle, ArrowLeft } from "lucide-react";
import Link from "next/link";

export const dynamic = 'force-dynamic';

export default async function ResubmitPage({ params }: { params: { id: string } }) {
    const session: any = await getServerSession(authOptions);
    if (!session?.user) redirect('/login');
    if (session.user.role !== 'author') redirect(`/${session.user.role}`);

    const submissionId = parseInt(params.id);
    if (isNaN(submissionId)) notFound();

    const [submissionRes, eligibilityRes] = await Promise.all([
        getAuthorSubmission(submissionId),
        checkResubmissionEligibility(submissionId),
    ]);

    if (!submissionRes.success || !submissionRes.data) notFound();
    const submission = submissionRes.data;
    const eligibility = eligibilityRes.data || { eligible: false, daysRemaining: 0 };

    return (
        <section className="max-w-2xl mx-auto space-y-6 pb-20">
            <header className="flex items-center gap-4 border-b border-primary/5 pb-6">
                <Button asChild variant="ghost" size="sm" className="rounded-lg">
                    <Link href={`/author/submissions/${submissionId}`} className="flex items-center gap-2 text-xs font-bold uppercase">
                        <ArrowLeft className="w-3.5 h-3.5" /> Back
                    </Link>
                </Button>
                <div>
                    <h1 className="font-black text-foreground tracking-widest uppercase text-xl">Submit Revision</h1>
                    <p className="text-xs text-muted-foreground font-medium">Upload your revised manuscript and copyright form</p>
                </div>
            </header>

            {!eligibility.eligible ? (
                <Card className="border-rose-200 dark:border-rose-500/20 bg-rose-50/50 dark:bg-rose-500/5">
                    <CardContent className="p-10 flex flex-col items-center gap-4 text-center">
                        <XCircle className="w-12 h-12 text-rose-500" />
                        <h3 className="font-black text-xl uppercase tracking-widest text-foreground">Not Eligible</h3>
                        <p className="text-sm text-muted-foreground max-w-sm">{eligibilityRes.error || "Window Expired"}</p>
                        <Button asChild variant="outline" size="sm" className="rounded-xl font-bold uppercase text-xs">
                            <Link href="/author">Back to Dashboard</Link>
                        </Button>
                    </CardContent>
                </Card>
            ) : (
                <ResubmitForm
                    submissionId={submissionId}
                    paperId={submission.paperId}
                    title={submission.title}
                    daysRemaining={eligibility.daysRemaining || 0}
                    currentStatus={submission.status}
                />
            )}
        </section>
    );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { FileText, Upload, CheckCircle2, AlertCircle, Loader2, Info } from "lucide-react";
import { resubmitPaper } from "@/actions/author-submissions";
import { toast } from "sonner";

interface ResubmissionFormProps {
    submissionId: number;
    paperId: string;
    daysRemaining: number;
}

export function ResubmissionForm({ submissionId, paperId, daysRemaining }: ResubmissionFormProps) {
    const router = useRouter();
    const [loading, setLoading] = useState(false);
    const [success, setSuccess] = useState(false);

    async function handleSubmit(e: React.FormEvent<HTMLFormElement>) {
        e.preventDefault();
        setLoading(true);

        const formData = new FormData(e.currentTarget);
        const res = await resubmitPaper(submissionId, formData);

        setLoading(false);
        if (res.success) {
            setSuccess(true);
            toast.success("Manuscript resubmitted successfully!");
            setTimeout(() => {
                router.refresh();
            }, 2000);
        } else {
            toast.error(res.error || "Failed to resubmit");
        }
    }

    if (success) {
        return (
            <Card className="border-green-100 bg-green-50/30">
                <CardContent className="flex flex-col items-center justify-center py-10 text-center">
                    <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mb-4">
                        <CheckCircle2 className="w-8 h-8 text-green-600" />
                    </div>
                    <CardTitle className="text-green-900 mb-2">Resubmission Successful!</CardTitle>
                    <CardDescription className="text-green-700">
                        Your revised manuscript has been uploaded and the editorial team has been notified.
                    </CardDescription>
                </CardContent>
            </Card>
        );
    }

    return (
        <Card className="border-primary/10 shadow-xl shadow-primary/5">
            <CardHeader className="border-b border-primary/5 bg-primary/1">
                <div className="flex items-center justify-between">
                    <div>
                        <CardTitle className="text-xl font-black tracking-tight text-primary">Submit Revised Manuscript</CardTitle>
                        <CardDescription>Upload your updated documents and address reviewer feedback.</CardDescription>
                    </div>
                    <div className="bg-orange-50 text-orange-700 px-4 py-2 rounded-xl text-xs font-bold border border-orange-100 flex items-center gap-2">
                        <AlertCircle className="w-4 h-4" />
                        {daysRemaining} days remaining to resubmit
                    </div>
                </div>
            </CardHeader>
            <CardContent className="pt-6">
                <form onSubmit={handleSubmit} className="space-y-6">
                    <div className="space-y-2">
                        <Label htmlFor="changelog" className="text-sm font-bold text-primary/60">Response to Reviewers / Changelog</Label>
                        <Textarea 
                            id="changelog" 
                            name="changelog"
                            placeholder="Briefly describe the changes made in this revision..."
                            className="min-h-[120px] rounded-xl border-primary/10 focus:border-secondary transition-all"
                            required
                        />
                    </div>

                    <div className="grid md:grid-cols-2 gap-6">
                        <div className="space-y-2">
                            <Label htmlFor="manuscript" className="text-sm font-bold text-primary/60">Revised Manuscript (Main File)</Label>
                            <label className="flex flex-col items-center justify-center w-full h-32 border-2 border-dashed border-primary/10 rounded-2xl cursor-pointer hover:bg-primary/2 hover:border-secondary/30 transition-all">
                                <div className="flex flex-col items-center justify-center pt-5 pb-6">
                                    <Upload className="w-8 h-8 text-primary/20 mb-2" />
                                    <p className="text-xs text-primary/40 font-bold">DOCX, PDF (Max 20MB)</p>
                                </div>
                                <Input id="manuscript" name="manuscript" type="file" className="hidden" required />
                            </label>
                        </div>

                        <div className="space-y-2">
                            <Label htmlFor="copyright_form" className="text-sm font-bold text-primary/60">Updated Copyright Form</Label>
                            <label className="flex flex-col items-center justify-center w-full h-32 border-2 border-dashed border-primary/10 rounded-2xl cursor-pointer hover:bg-primary/2 hover:border-secondary/30 transition-all">
                                <div className="flex flex-col items-center justify-center pt-5 pb-6">
                                    <FileText className="w-8 h-8 text-primary/20 mb-2" />
                                    <p className="text-xs text-primary/40 font-bold">PDF Only (Max 5MB)</p>
                                </div>
                                <Input id="copyright_form" name="copyright_form" type="file" className="hidden" required />
                            </label>
                        </div>
                    </div>

                    <Alert className="bg-primary/5 border-primary/10 rounded-2xl">
                        <Info className="w-4 h-4" />
                        <AlertTitle className="text-xs font-black uppercase tracking-widest text-primary/40">Important Note</AlertTitle>
                        <AlertDescription className="text-sm text-primary/60 italic">
                            Uploading a revision will reset the status to "Submitted" and notify the editors. Please ensure all reviewer comments have been addressed.
                        </AlertDescription>
                    </Alert>

                    <Button 
                        type="submit" 
                        disabled={loading}
                        className="w-full h-14 rounded-2xl bg-primary hover:bg-secondary transition-all text-white font-black tracking-widest shadow-xl shadow-primary/20"
                    >
                        {loading ? (
                            <>
                                <Loader2 className="w-5 h-5 mr-2 animate-spin" />
                                Processing Resubmission...
                            </>
                        ) : (
                            "Finalize & Resubmit Manuscript"
                        )}
                    </Button>
                </form>
            </CardContent>
        </Card>
    );
}

import { redirect } from "next/navigation";
import { getServerSession } from "next-auth/next";
import { authOptions } from "@/lib/auth";
import { getAuthorDashboard, checkResubmissionEligibility } from "@/actions/author-submissions";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import Link from "next/link";
import { FileText, Upload, ExternalLink, Clock, Timer } from "lucide-react";

export const dynamic = 'force-dynamic';

const STATUS_CONFIG: Record<string, { label: string; color: string; bg: string }> = {
    submitted: { label: 'Under Review', color: 'text-blue-600', bg: 'bg-blue-500/10' },
    editor_assigned: { label: 'Editor Assigned', color: 'text-indigo-600', bg: 'bg-indigo-500/10' },
    under_review: { label: 'Peer Review', color: 'text-amber-600', bg: 'bg-amber-500/10' },
    revision_requested: { label: 'Revision Required', color: 'text-orange-600', bg: 'bg-orange-500/10' },
    accepted: { label: 'Accepted', color: 'text-emerald-600', bg: 'bg-emerald-500/10' },
    rejected: { label: 'Not Accepted', color: 'text-rose-600', bg: 'bg-rose-500/10' },
    payment_pending: { label: 'Payment Pending', color: 'text-purple-600', bg: 'bg-purple-500/10' },
    published: { label: 'Published', color: 'text-emerald-700', bg: 'bg-emerald-500/15' },
};

export default async function AuthorSubmissionsList() {
    const session: any = await getServerSession(authOptions);
    if (!session?.user) redirect('/login');
    if (session.user.role !== 'author') redirect(`/${session.user.role}`);

    const dashboardResponse = await getAuthorDashboard();
    const submissions = dashboardResponse.data?.submissions || [];

    // Attach eligibility data in parallel
    const withEligibility = await Promise.all(
        submissions.map(async (sub: any) => {
            if (['revision_requested', 'rejected'].includes(sub.status)) {
                const el = await checkResubmissionEligibility(sub.id);
                return { ...sub, eligibility: el };
            }
            return { ...sub, eligibility: null };
        })
    );

    return (
        <section className="space-y-6 pb-20">
            <header className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 border-b border-primary/5 pb-6">
                <div>
                    <h1 className="font-black text-foreground tracking-widest uppercase text-2xl">My Submissions</h1>
                    <p className="text-xs text-muted-foreground font-medium mt-1">All manuscripts you have submitted to IJITEST</p>
                </div>
                <Button asChild className="bg-primary text-white dark:text-black hover:bg-primary/90 font-bold uppercase text-xs rounded-xl h-10 px-5">
                    <Link href="/submit">+ New Submission</Link>
                </Button>
            </header>

            {withEligibility.length === 0 ? (
                <Card className="border-dashed border-2 border-border/50 bg-muted/10 py-20 text-center rounded-xl">
                    <CardContent className="flex flex-col items-center gap-3 text-muted-foreground">
                        <FileText className="w-10 h-10 opacity-20" />
                        <span className="font-bold uppercase tracking-widest text-xs">No Submissions</span>
                        <Button asChild size="sm" className="mt-2 bg-primary text-white dark:text-black hover:bg-primary/90 font-bold uppercase text-[10px] rounded-lg">
                            <Link href="/submit">Start Your First Submission</Link>
                        </Button>
                    </CardContent>
                </Card>
            ) : (
                <div className="grid grid-cols-1 gap-4">
                    {withEligibility.map((sub: any) => {
                        const cfg = STATUS_CONFIG[sub.status] || { label: sub.status, color: 'text-muted-foreground', bg: 'bg-muted/30' };
                        const eligible = sub.eligibility?.eligible;
                        const daysLeft = sub.eligibility?.daysRemaining;
                        const isUrgent = eligible && daysLeft <= 5;

                        return (
                            <Card key={sub.id} className={`border-border/50 bg-background hover:shadow-md transition-all group ${isUrgent ? 'ring-1 ring-orange-400/40' : ''}`}>
                                <CardContent className="p-6">
                                    <div className="flex flex-col sm:flex-row sm:items-center gap-4 justify-between">
                                        <div className="flex-1 min-w-0 space-y-2">
                                            <div className="flex flex-wrap items-center gap-2">
                                                <Badge variant="outline" className="text-[9px] font-mono">{sub.paper_id}</Badge>
                                                <Badge className={`text-[9px] font-bold border-none uppercase ${cfg.bg} ${cfg.color}`}>{cfg.label}</Badge>
                                            </div>
                                            <h3 className="font-bold text-foreground line-clamp-1 group-hover:text-primary transition-colors">
                                                {sub.title}
                                            </h3>
                                            <div className="flex flex-wrap gap-4 text-[10px] text-muted-foreground">
                                                <span className="flex items-center gap-1"><Clock className="w-3 h-3" />{new Date(sub.submitted_at).toLocaleDateString()}</span>
                                                {daysLeft !== undefined && daysLeft !== null && (
                                                    <span className={`flex items-center gap-1 font-bold ${isUrgent ? 'text-orange-600' : 'text-amber-600'}`}>
                                                        <Timer className="w-3 h-3" />
                                                        {daysLeft > 0 ? `${daysLeft}d to resubmit` : 'Window expired'}
                                                    </span>
                                                )}
                                            </div>
                                        </div>

                                        <div className="flex flex-wrap gap-2 shrink-0">
                                            <Button asChild variant="outline" size="sm" className="h-8 text-[10px] font-bold uppercase rounded-lg">
                                                <Link href={`/author/submissions/${sub.id}`} className="flex items-center gap-1.5">Details <ExternalLink className="w-3 h-3" /></Link>
                                            </Button>
                                            {eligible && daysLeft > 0 && (
                                                <Button asChild size="sm" className="h-8 text-[10px] bg-orange-500 hover:bg-orange-600 text-white font-bold uppercase rounded-lg">
                                                    <Link href={`/author/submissions/${sub.id}/resubmit`} className="flex items-center gap-1.5">
                                                        <Upload className="w-3 h-3" /> Resubmit
                                                    </Link>
                                                </Button>
                                            )}
                                        </div>
                                    </div>
                                </CardContent>
                            </Card>
                        );
                    })}
                </div>
            )}
        </section>
    );
}

"use client";

export const dynamic = "force-dynamic";
import { useApplications, useApproveApplication, useRejectApplication } from '@/hooks/queries/useApplications';
import { useState, Suspense } from 'react';
import { toast } from 'sonner';
import {
    User,
    FileText,
    Mail,
    Building2,
    Search,
    Filter,
    Clock,
    Briefcase,
    CheckCircle,
    X
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";

function ManageApplicationsContent() {
    const { data: applications = [], isLoading: loading } = useApplications();
    const approveMutation = useApproveApplication();
    const rejectMutation = useRejectApplication();

    const [searchTerm, setSearchTerm] = useState('');
    const [filterRole, setFilterRole] = useState<'all' | 'reviewer' | 'editor'>('all');
    const [processingId, setProcessingId] = useState<number | null>(null);
    const [rejectionReason, setRejectionReason] = useState<{ id: number; text: string } | null>(null);

    const handleApprove = async (id: number) => {
        if (!confirm('Are you sure you want to APPROVE this application?\nThis will automatically create a user account and send an invitation.')) return;

        setProcessingId(id);
        try {
            const result = await approveMutation.mutateAsync(id);
            if (result.success) {
                toast.success('Application approved successfully!');
            } else {
                toast.error(result.error);
            }
        } catch (error) {
            toast.error('Failed to approve application');
        }
        setProcessingId(null);
    };

    const handleReject = async (id: number) => {
        if (!rejectionReason || rejectionReason.id !== id) {
            setRejectionReason({ id, text: "" });
            return;
        }

        const reason = rejectionReason.text;
        const finalReason = reason.trim();
        if (finalReason.length < 20) {
            toast.error("Reason Required", {
                 description: "Please provide a rejection reason (min 20 characters)."
            });
            return;
        }

        setProcessingId(id);
        try {
            const result = await rejectMutation.mutateAsync({ id, reason: finalReason });
            if (result.success) {
                toast.success('Application rejected successfully!');
                setRejectionReason(null);
            } else {
                toast.error(result.error);
            }
        } catch (error) {
            toast.error('Failed to reject application');
        }
        setProcessingId(null);
    };

    const filteredApps = applications.filter(app => {
        const matchesSearch = app.fullName?.toLowerCase().includes(searchTerm.toLowerCase()) ||
            app.email?.toLowerCase().includes(searchTerm.toLowerCase());
        const matchesRole = filterRole === 'all' || app.type === filterRole;
        return matchesSearch && matchesRole;
    });

    return (
        <section className="space-y-6 pb-20">
            {/* Header Section */}
            <header className="flex flex-col sm:flex-row sm:items-center justify-between gap-6 border-b border-primary/5 pb-8">
                <div className="space-y-2">
                    <h1 className="font-serif text-2xl xl:text-3xl 2xl:text-4xl font-semibold text-foreground tracking-tight capitalize leading-none">Board proposals</h1>
                    <p className="text-xs xl:text-sm font-semibold text-muted-foreground border-l-2 border-primary/10 pl-4 mt-2 capitalize tracking-wide transition-all duration-500">Vetting pipeline for editorial staff and technical reviewer candidates.</p>
                </div>
                <div className="flex bg-muted/50 p-1.5 rounded-xl border border-border/50 shrink-0 h-10">
                    <Button
                        variant={filterRole === 'all' ? 'secondary' : 'ghost'}
                        size="sm"
                        onClick={() => setFilterRole('all')}
                        className={`h-full px-6 text-xs font-semibold tracking-widest transition-all rounded-lg capitalize ${filterRole === 'all' ? 'bg-background shadow-sm' : 'text-muted-foreground hover:text-foreground'}`}
                    >
                        All records
                    </Button>
                    <Button
                        variant={filterRole === 'reviewer' ? 'secondary' : 'ghost'}
                        size="sm"
                        onClick={() => setFilterRole('reviewer')}
                        className={`h-full px-6 text-xs font-semibold tracking-widest transition-all rounded-lg capitalize ${filterRole === 'reviewer' ? 'bg-background shadow-sm' : 'text-muted-foreground hover:text-foreground'}`}
                    >
                        Reviewers
                    </Button>
                    <Button
                        variant={filterRole === 'editor' ? 'secondary' : 'ghost'}
                        size="sm"
                        onClick={() => setFilterRole('editor')}
                        className={`h-full px-6 text-[10px] xl:text-[11px] 2xl:text-xs font-semibold tracking-widest transition-all rounded-lg capitalize ${filterRole === 'editor' ? 'bg-background shadow-sm' : 'text-muted-foreground hover:text-foreground'}`}
                    >
                        Editors
                    </Button>
                </div>
            </header>

            {/* Filter Bar */}
            <Card className="border-border/50 shadow-sm overflow-hidden bg-muted/10 rounded-xl">
                <CardContent className="p-4 flex flex-col md:flex-row gap-4 items-center">
                    <div className="relative flex-1 group w-full">
                        <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground group-focus-within:text-primary transition-colors" />
                        <Input
                            type="text"
                            placeholder="Query candidate database..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="bg-background border-none h-11 pl-11 text-sm font-semibold text-foreground focus-visible:ring-1 focus-visible:ring-primary/20 rounded-xl capitalize"
                        />
                    </div>
                    <div className="flex items-center gap-3 px-5 py-2.5 bg-background rounded-xl border border-border/50 shrink-0 h-11">
                        <Clock className="w-4 h-4 text-primary" />
                        <span className="text-[10px] xl:text-[11px] 2xl:text-xs font-semibold text-muted-foreground tracking-widest capitalize">{filteredApps.length} pending records</span>
                    </div>
                </CardContent>
            </Card>

            {/* Applications List */}
            <div className="grid grid-cols-1 gap-4">
                {loading ? (
                    <div className="py-24 flex flex-col items-center justify-center gap-6 text-muted-foreground">
                        <div className="w-10 h-10 border-[3px] border-primary/10 border-t-primary rounded-full animate-spin" />
                        <p className="font-semibold text-xs tracking-[0.2em] animate-pulse">Accessing Secure Records...</p>
                    </div>
                ) : filteredApps.length === 0 ? (
                    <div className="flex flex-col items-center justify-center py-24 bg-muted/20 border border-dashed border-border/50 rounded-xl">
                        <Filter className="w-12 h-12 text-muted-foreground/20 mb-6" />
                        <p className="text-xs font-semibold text-muted-foreground tracking-[0.2em] uppercase">No join requests detected </p>
                    </div>
                ) : (
                    <AnimatePresence mode="popLayout">
                        {filteredApps.map((app) => (
                            <motion.div
                                key={app.id}
                                layout
                                initial={{ opacity: 0, scale: 0.98 }}
                                animate={{ opacity: 1, scale: 1 }}
                                exit={{ opacity: 0, scale: 0.95 }}
                            >
                                <Card className="border-border/50 shadow-sm overflow-hidden hover:border-primary/20 transition-all group">
                                    <div className="flex flex-col md:flex-row">
                                        <div className="p-5 flex-1 flex flex-col sm:flex-row gap-5 items-center sm:items-start">
                                            <div className="w-24 h-24 rounded-xl bg-muted border border-border/50 shrink-0 overflow-hidden group-hover:shadow-xl transition-all shadow-inner relative">
                                                {app.photoUrl ? (
                                                    <img src={app.photoUrl} alt="" className="w-full h-full object-cover" />
                                                ) : (
                                                    <div className="w-full h-full flex items-center justify-center">
                                                        <User className="w-10 h-10 text-muted-foreground/30" />
                                                    </div>
                                                )}
                                            </div>

                                            <div className="space-y-3 flex-1 text-center sm:text-left min-w-0">
                                                <div className="flex flex-wrap items-center justify-center sm:justify-start gap-3">
                                                    <h3 className="font-serif text-lg xl:text-xl font-semibold text-foreground tracking-tight capitalize">{app.fullName}</h3>
                                                    <Badge className={`h-6 px-2.5 text-[10px] font-semibold tracking-widest capitalize border-none ${app.type === 'editor'
                                                        ? 'bg-purple-500/10 text-purple-600'
                                                        : 'bg-emerald-500/10 text-emerald-600'
                                                        }`}>
                                                        {app.type}
                                                    </Badge>
                                                </div>

                                                <div className="flex flex-wrap items-center justify-center sm:justify-start gap-x-6 gap-y-2.5 text-muted-foreground text-xs font-semibold uppercase tracking-wider">
                                                    <p className="flex items-center gap-2"><Mail className="w-4 h-4 text-primary/60" /> {app.email}</p>
                                                    <p className="flex items-center gap-2"><Building2 className="w-4 h-4 text-primary/60" /> {app.institute}</p>
                                                    <p className="flex items-center gap-2"><Briefcase className="w-4 h-4 text-primary/60" /> {app.designation}</p>
                                                </div>

                                                <div className="flex flex-wrap items-center justify-center sm:justify-start gap-4 pt-2">
                                                    <Button asChild variant="secondary" size="sm" className="h-10 px-5 gap-2.5 text-xs font-semibold tracking-widest rounded-xl hover:bg-muted border border-border/20 cursor-pointer">
                                                        <a href={app.cvUrl || '#'} target="_blank" className="flex items-center gap-2.5 cursor-pointer">
                                                            <FileText className="w-4.5 h-4.5" /> View Academic Profile
                                                        </a>
                                                    </Button>
                                                    <p className="text-[11px] font-semibold text-muted-foreground opacity-50 tracking-widest uppercase">
                                                        Authenticated: {new Date(app.createdAt || Date.now()).toLocaleDateString(undefined, { day: 'numeric', month: 'short', year: 'numeric' })}
                                                    </p>
                                                </div>
                                            </div>
                                        </div>

                                        <div className="bg-muted/10 md:w-72 p-6 border-t md:border-t-0 md:border-l border-border/50 flex flex-col justify-center gap-3">
                                             {rejectionReason?.id === app.id && rejectionReason && (
                                                 <div className="space-y-3 mb-3 animate-in fade-in slide-in-from-top-1">
                                                     <textarea
                                                         className="w-full h-24 p-3 text-[10px] bg-background border border-border/50 rounded-xl focus:ring-1 focus:ring-red-500/20 outline-none resize-none font-medium text-foreground placeholder:text-muted-foreground/50"
                                                         placeholder="Reason for rejection (min 20 characters)..."
                                                         value={rejectionReason.text}
                                                         onChange={(e) => setRejectionReason({ id: app.id, text: e.target.value })}
                                                     />
                                                     <Button
                                                         variant="ghost"
                                                         size="sm"
                                                         onClick={() => setRejectionReason(null)}
                                                         className="h-8 w-full text-[10px] font-semibold uppercase tracking-widest text-muted-foreground hover:text-foreground"
                                                     >
                                                         Cancel
                                                     </Button>
                                                 </div>
                                             )}
                                             
                                             <Button
                                                 disabled={processingId !== null}
                                                 onClick={() => handleReject(app.id)}
                                                 variant={rejectionReason?.id === app.id ? "destructive" : "outline"}
                                                 className={`w-full h-12 gap-2.5 font-semibold tracking-widest transition-all rounded-xl cursor-pointer ${rejectionReason?.id === app.id 
                                                     ? 'bg-red-600 text-white hover:bg-red-700 shadow-lg shadow-red-600/20' 
                                                     : 'border-red-500/20 text-red-600 hover:bg-red-500 hover:text-white'
                                                 } ${rejectionReason?.id === app.id ? 'text-[9px] sm:text-[10px] xl:text-[11px] 2xl:text-xs' : 'text-xs'}`}
                                             >
                                                 {processingId === app.id ? (
                                                     <span className="animate-pulse">Declining...</span>
                                                 ) : (
                                                     <>
                                                         {rejectionReason?.id === app.id ? 'Confirm Rejection' : 'Reject Request'}
                                                         <X className="w-4.5 h-4.5" />
                                                     </>
                                                 )}
                                             </Button>

                                             {!rejectionReason && (
                                                 <Button
                                                     disabled={processingId !== null}
                                                     onClick={() => handleApprove(app.id)}
                                                     className="w-full h-12 gap-2.5 bg-emerald-600 hover:bg-emerald-700 text-white font-semibold text-[9px] sm:text-[10px] xl:text-[11px] 2xl:text-xs tracking-widest border-none shadow-lg shadow-emerald-600/20 transition-all rounded-xl cursor-pointer"
                                                 >
                                                     {processingId === app.id ? (
                                                         <span className="animate-pulse">Authorizing...</span>
                                                     ) : (
                                                         <>
                                                             Approve Proposal
                                                             <CheckCircle className="w-4.5 h-4.5" />
                                                         </>
                                                     )}
                                                 </Button>
                                             )}
                                         </div>
                                    </div>
                                </Card>
                            </motion.div>
                        ))}
                    </AnimatePresence>
                )}
            </div>
        </section>
    );
}

export default function ManageApplicationsPage() {
    return (
        <Suspense fallback={<div className="p-20 flex flex-col items-center justify-center gap-4 text-muted-foreground"><div className="w-8 h-8 border-2 border-primary/10 border-t-primary rounded-full animate-spin" /><p className="font-semibold text-[10px] tracking-[0.2em] animate-pulse">Initializing Interface...</p></div>}>
            <ManageApplicationsContent />
        </Suspense>
    );
}

"use client";

import { MessageSquare, Mail, Calendar, Archive, Search, Trash2, User, Send } from 'lucide-react';
import { useMessages, useUpdateMessageStatus, useDeleteMessage } from '@/hooks/queries/useMessages';
import { useState } from 'react';
import { toast } from 'sonner';
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { ScrollArea } from "@/components/ui/scroll-area";
import { InputGroup, InputGroupAddon, InputGroupInput } from "@/components/ui/input-group";

export default function Messages() {
    const { data: messages = [], isLoading: loading } = useMessages();
    const updateMutation = useUpdateMessageStatus();
    const deleteMutation = useDeleteMessage();

    const [selectedMessage, setSelectedMessage] = useState<any>(null);
    const [activeTab, setActiveTab] = useState<'inbox' | 'archived'>('inbox');
    const [searchQuery, setSearchQuery] = useState('');

    async function handleStatusChange(id: number, status: 'resolved' | 'archived' | 'pending') {
        try {
            await updateMutation.mutateAsync({ id, status });
            if (selectedMessage?.id === id) {
                setSelectedMessage({ ...selectedMessage, status });
            }
            toast.success(`Message marked as ${status}`);
        } catch (error) {
            toast.error("Failed to update status");
        }
    }

    async function handleDelete(id: number) {
        if (!confirm('Are you sure you want to permanently delete this message?')) return;
        try {
            const res = await deleteMutation.mutateAsync(id);
            if (res.error) {
                toast.error(res.error);
            } else {
                toast.success("Message deleted");
                setSelectedMessage(null);
            }
        } catch (error) {
            toast.error("Failed to delete message");
        }
    }

    if (loading) {
        return (
            <div className="p-40 text-center space-y-6">
                <div className="w-16 h-16 border-4 border-primary/20 border-t-primary rounded-full animate-spin mx-auto" />
                <p className="font-semibold text-muted-foreground tracking-widest text-xs uppercase animate-pulse">Connecting to Communication Server...</p>
            </div>
        );
    }

    const activeMessages = messages.filter(m => {
        const matchesTab = activeTab === 'inbox' ? m.status !== 'archived' : m.status === 'archived';
        const matchesSearch =
            (m.name?.toLowerCase() || '').includes(searchQuery.toLowerCase()) ||
            (m.subject?.toLowerCase() || '').includes(searchQuery.toLowerCase()) ||
            (m.email?.toLowerCase() || '').includes(searchQuery.toLowerCase());
        return matchesTab && matchesSearch;
    });

    const unreadCount = messages.filter(m => m.status === 'pending').length;

    return (
        <main className="h-[calc(100vh-100px)] flex flex-col gap-6 pb-6">

            {/* Header & Controls */}
            <header className="flex flex-col sm:flex-row sm:items-center justify-between gap-6 shrink-0 border-b border-primary/5 pb-8">
                <div className="space-y-2">
                    <h1 className="font-serif text-2xl xl:text-3xl 2xl:text-4xl font-semibold text-foreground tracking-tight capitalize leading-none">Inbox hub</h1>
                    <p className="text-xs xl:text-sm font-semibold text-muted-foreground border-l-2 border-primary/10 pl-4 mt-2 capitalize tracking-wide transition-all duration-500">Central command for editorial inquiries & peer review sync.</p>
                </div>

                <div className="flex flex-col sm:flex-row items-center gap-4">
                    {/* Tabs */}
                    <div className="flex items-center p-1 bg-muted/50 backdrop-blur-sm rounded-xl border border-primary/5 shadow-sm">
                        <button
                            onClick={() => setActiveTab('inbox')}
                            className={`relative px-8 py-3 rounded-xl text-xs font-semibold capitalize tracking-widest transition-all ${activeTab === 'inbox' ? 'text-primary-foreground bg-primary shadow-md dark:text-black' : 'text-muted-foreground hover:text-primary dark:text-muted-foreground dark:hover:text-primary'}`}
                        >
                            Active inbox
                            {unreadCount > 0 && activeTab !== 'inbox' && (
                                <span className="absolute top-2 right-2 w-2.5 h-2.5 rounded-full bg-rose-500 animate-pulse" />
                            )}
                        </button>
                        <button
                            onClick={() => setActiveTab('archived')}
                            className={`px-8 py-3 rounded-xl text-[10px] xl:text-[11px] 2xl:text-xs font-semibold capitalize tracking-widest transition-all ${activeTab === 'archived' ? 'text-primary-foreground bg-primary shadow-md dark:text-black' : 'text-muted-foreground hover:text-primary dark:text-muted-foreground dark:hover:text-primary'}`}
                        >
                            Archived comm
                        </button>
                    </div>

                    <InputGroup className="flex-1 w-full sm:w-80 h-12 bg-muted border-none rounded-xl shadow-inner overflow-hidden focus-within:ring-1 focus-within:ring-primary/20 transition-all">
                        <InputGroupAddon className="pl-6 group-focus-within/input-group:text-primary transition-colors pr-2">
                            <Search className="w-4 h-4 text-primary/30" />
                        </InputGroupAddon>
                        <InputGroupInput
                            type="text"
                            placeholder="Query intel..."
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            className="h-full px-6 text-sm font-semibold bg-transparent border-0 ring-0 focus-visible:ring-0 placeholder:text-muted-foreground/40 text-foreground capitalize"
                        />
                    </InputGroup>
                </div>
            </header>

            {/* Main Content Area */}
            <div className="flex flex-col lg:flex-row gap-6 flex-1 min-h-0">
                {/* Sidebar List */}
                <Card className="lg:w-[380px] flex flex-col border-primary/5 shadow-vip overflow-hidden bg-card shrink-0 rounded-xl relative">
                    <div className="absolute top-0 left-0 w-full h-1.5 bg-primary/10" />
                    <CardHeader className="p-6 bg-primary/2 border-b border-primary/5 space-y-2">
                        <div className="flex items-center justify-between">
                            <CardTitle className="text-xs font-semibold text-primary tracking-widest capitalize">Communications</CardTitle>
                            <Badge className="h-7 px-3 bg-primary/10 text-primary text-[10px] xl:text-[11px] 2xl:text-xs font-semibold border-none capitalize tracking-widest rounded-lg">
                                {activeMessages.length} records
                            </Badge>
                        </div>
                    </CardHeader>
                    <ScrollArea className="flex-1">
                        <div className="divide-y divide-primary/5">
                            {activeMessages.map((m) => {
                                const isSelected = selectedMessage?.id === m.id;
                                const isUnread = m.status === 'pending';

                                return (
                                    <div
                                        key={m.id}
                                        onClick={() => {
                                            setSelectedMessage(m);
                                            if (isUnread) handleStatusChange(m.id, 'resolved');
                                        }}
                                        className={`p-6 cursor-pointer transition-all hover:bg-primary/2 relative group ${isSelected ? 'bg-primary/4' : ''}`}
                                    >
                                        <div className={`absolute left-0 top-0 bottom-0 w-1.5 transition-all ${isSelected ? 'bg-primary' : isUnread ? 'bg-primary/30' : 'bg-transparent'}`} />
                                        <div className="flex items-center justify-between mb-3">
                                            <span className="text-[10px] font-semibold text-muted-foreground/60 capitalize tracking-widest truncate max-w-[150px]">
                                                {m.subject || 'No subject'}
                                            </span>
                                            <span className="text-[9px] sm:text-[10px] xl:text-[11px] 2xl:text-xs font-semibold text-muted-foreground/40 capitalize tracking-widest">
                                                {new Date(m.createdAt || Date.now()).toLocaleDateString(undefined, { month: 'short', day: 'numeric' })}
                                            </span>
                                        </div>
                                        <h3 className={`font-serif tracking-tight leading-tight mb-2 truncate capitalize ${isUnread ? 'text-lg font-semibold text-foreground' : 'text-base font-semibold text-muted-foreground'}`}>
                                            {m.name}
                                        </h3>
                                        <p className="text-xs text-muted-foreground/70 line-clamp-1 font-medium leading-relaxed group-hover:text-foreground transition-colors italic">
                                            {m.message}
                                        </p>
                                    </div>
                                );
                            })}
                        </div>
                        {activeMessages.length === 0 && (
                            <div className="p-16 text-center space-y-4 flex flex-col items-center">
                                <div className="w-16 h-16 rounded-xl bg-primary/5 flex items-center justify-center">
                                    <MessageSquare className="w-6 h-6 text-primary/20" />
                                </div>
                                <div className="space-y-1">
                                    <p className="text-[10px] font-semibold text-muted-foreground/60 uppercase tracking-[0.3em]">Queue Empty</p>
                                    <p className="text-[9px] font-medium text-muted-foreground/40 tracking-widest">No matching records found.</p>
                                </div>
                            </div>
                        )}
                    </ScrollArea>
                </Card>

                {/* Message Detail Pane */}
                <Card className="flex-1 border-primary/5 shadow-vip flex flex-col overflow-hidden bg-card rounded-xl relative">
                    <div className="absolute top-0 left-0 w-full h-1.5 bg-primary/10" />
                    {selectedMessage ? (
                        <>
                            <CardHeader className="p-4 sm:p-8 bg-primary/2 border-b border-primary/5 flex flex-col sm:flex-row sm:items-start justify-between gap-6">
                                <div className="flex flex-col sm:flex-row items-start gap-4 sm:gap-8">
                                    <div className="w-16 h-16 rounded-xl bg-muted border border-primary/10 flex items-center justify-center shadow-sm shrink-0">
                                        <User className="w-8 h-8 text-muted-foreground/40" />
                                    </div>
                                    <div className="space-y-2">
                                        <h2 className="font-serif text-xl xl:text-2xl font-semibold text-foreground tracking-tight capitalize break-all sm:break-normal">{selectedMessage.name}</h2>
                                        <div className="flex items-center gap-4">
                                            <a href={`mailto:${selectedMessage.email}`} className="text-[11px] xl:text-xs font-semibold text-secondary hover:underline tracking-widest flex items-center gap-2 capitalize break-all sm:break-normal">
                                                <Mail className="w-4 h-4 shrink-0" /> <span className="truncate max-w-[200px] sm:max-w-none">{selectedMessage.email}</span>
                                            </a>
                                        </div>
                                    </div>
                                </div>
                                <div className="flex flex-wrap sm:flex-nowrap items-center gap-3 shrink-0 w-full sm:w-auto">
                                    <Button
                                        variant="outline"
                                        size="sm"
                                        onClick={() => handleStatusChange(selectedMessage.id, selectedMessage.status === 'archived' ? 'resolved' : 'archived')}
                                        className={`flex-1 sm:flex-none h-12 px-2 sm:px-6 gap-2 sm:gap-3 font-semibold text-[10px] sm:text-xs uppercase tracking-widest rounded-xl transition-all ${selectedMessage.status === 'archived' ? 'border-primary bg-primary text-white dark:text-slate-900 hover:bg-primary/90' : 'border-primary/10 text-foreground hover:bg-muted font-semibold'}`}
                                    >
                                        <Archive className="w-4 h-4 sm:w-5 sm:h-5 shrink-0" />
                                        <span className="truncate">{selectedMessage.status === 'archived' ? 'Restore Active' : 'Archive'}</span>
                                    </Button>
                                    <Button
                                        variant="outline"
                                        size="icon"
                                        onClick={() => handleDelete(selectedMessage.id)}
                                        className="h-12 w-12 rounded-xl border-rose-500/20 text-rose-500 hover:bg-rose-500/10 hover:text-rose-600 transition-all font-semibold shrink-0"
                                        title="Sever Record"
                                    >
                                        <Trash2 className="w-5 h-5" />
                                    </Button>
                                </div>
                            </CardHeader>

                            <ScrollArea className="flex-1">
                                <div className="p-8 space-y-8 max-w-4xl mx-auto w-full">
                                    {/* Action Header */}
                                    <div className="flex flex-wrap items-center justify-between gap-6 py-5 px-8 bg-primary/2 rounded-xl border border-primary/5 shadow-inner">
                                        <div className="flex items-center gap-8">
                                            <div className="flex items-center gap-3 text-xs font-semibold text-muted-foreground/60 uppercase tracking-widest">
                                                <Calendar className="w-5 h-5" />
                                                <span>{new Date(selectedMessage.createdAt || Date.now()).toLocaleString(undefined, { dateStyle: 'long', timeStyle: 'short' })}</span>
                                            </div>
                                            <div className="w-1.5 h-1.5 rounded-full bg-primary/20" />
                                            <span className="flex items-center gap-3 text-xs font-semibold uppercase tracking-widest text-muted-foreground/60">
                                                Status:
                                                <Badge variant="secondary" className="h-6 px-3 text-[10px] bg-primary/10 text-primary dark:text-primary dark:bg-primary/20 border-none shadow-sm font-semibold rounded-lg uppercase">{selectedMessage.status}</Badge>
                                            </span>
                                        </div>
                                    </div>

                                    {/* Message Body */}
                                    <div className="space-y-6">
                                        <div className="flex items-center gap-3 text-xs font-semibold text-muted-foreground/50 uppercase tracking-[0.3em] pl-4">
                                            <MessageSquare className="w-5 h-5" /> Transmission Payload
                                        </div>
                                        <Card className="border-primary/10 bg-muted/30 shadow-inner overflow-hidden rounded-xl">
                                            <CardContent className="p-10">
                                                <h3 className=" font-semibold text-foreground tracking-wider mb-8 pb-8 border-b border-primary/5 leading-snug uppercase">RE: {selectedMessage.subject || 'Editorial Inquiry'}</h3>
                                                <div className="text-sm font-medium text-foreground/80 leading-loose whitespace-pre-wrap selection:bg-primary/20 italic">
                                                    "{selectedMessage.message}"
                                                </div>
                                            </CardContent>
                                        </Card>
                                    </div>
                                </div>
                            </ScrollArea>

                            {/* Footer Actions */}
                            <div className="p-6 border-t border-primary/5 bg-primary/2 flex justify-end gap-4 rounded-b-4xl">
                                <Button asChild className="h-14 px-10 gap-3 font-semibold text-[9px] sm:text-[10px] xl:text-[11px] 2xl:text-xs uppercase tracking-[0.3em] shadow-xl shadow-primary/20 rounded-xl bg-primary text-white dark:text-slate-900 hover:scale-[1.02] transition-all cursor-pointer">
                                    <a href={`mailto:${selectedMessage.email}?subject=Re: ${selectedMessage.subject}`}>
                                        <Send className="w-5 h-5" /> Dispatch Journal Reply
                                    </a>
                                </Button>
                            </div>
                        </>
                    ) : (
                        <div className="flex-1 flex flex-col items-center justify-center p-20 text-center space-y-6">
                            <div className="w-24 h-24 rounded-xl bg-primary/3 border border-primary/5 flex items-center justify-center shadow-inner">
                                <Mail className="w-10 h-10 text-primary/20" />
                            </div>
                            <div className="space-y-2 max-w-sm">
                                <h3 className=" font-semibold text-muted-foreground/60 uppercase tracking-[0.3em]">Standby Directive</h3>
                                <p className="text-[10px] font-medium text-muted-foreground/40 tracking-widest leading-relaxed">Engage a communication node from the left registry to initialize the transmission matrix.</p>
                            </div>
                        </div>
                    )}
                </Card>
            </div>
        </main>
    );
}

import {
    FileStack,
    Activity,
    BookOpen,
    AlertCircle,
    TrendingUp,
    ArrowRight,
    ShieldCheck,
    FileText,
    Clock,
    ExternalLink,
    CreditCard,
    ClipboardList,
    Download
} from 'lucide-react';
import Link from 'next/link';
import { db } from '@/lib/db';
import * as schema from "@/db/schema";
import { eq, desc, sql, count } from "drizzle-orm";
import fs from 'fs';
import path from 'path';
import { performance } from 'perf_hooks';
import { getServerSession } from "next-auth/next";
import { authOptions } from "@/lib/auth";
import { getMySubmissions } from '@/actions/author-submissions';
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";

export const dynamic = 'force-dynamic';

export default async function EditorDashboard() {
    try {
        const session: any = await getServerSession(authOptions);
        const user = session?.user;
        const mySubmissions = await getMySubmissions();

        // 1. Data Fetching - Metrics & Stats
        const [totalSubmissions] = await db.select({ value: count() }).from(schema.submissions);
        const [underReview] = await db.select({ value: count() }).from(schema.submissions).where(eq(schema.submissions.status, 'under_review'));
        const [pendingPayments] = await db.select({ value: count() }).from(schema.payments).where(eq(schema.payments.status, 'pending'));

        const latestIssue = await db.query.volumesIssues.findFirst({
            where: eq(schema.volumesIssues.status, 'published'),
            orderBy: [desc(schema.volumesIssues.year), desc(schema.volumesIssues.volumeNumber)]
        });
        
        const currentIssue = latestIssue ? `${latestIssue.year} Edition` : '2026 Edition';

        const stats = [
            { label: 'Manuscript Queue', value: String(totalSubmissions.value), icon: <FileStack className="w-4 h-4" />, variant: 'primary' },
            { label: 'Under Review', value: String(underReview.value), icon: <ShieldCheck className="w-4 h-4" />, variant: 'blue' },
            { label: 'Pending APC', value: String(pendingPayments.value), icon: <CreditCard className="w-4 h-4" />, variant: 'emerald' },
            { label: 'Published Edition', value: currentIssue, icon: <BookOpen className="w-4 h-4" />, variant: 'amber' },
        ];

        // 2. Data Fetching - Recent Submissions (Relational Join)
        const recentSubmissionsRaw = await db.query.submissions.findMany({
            orderBy: [desc(schema.submissions.submittedAt)],
            limit: 5,
            with: {
                correspondingAuthor: {
                    with: {
                        profile: true
                    }
                },
                versions: {
                    orderBy: [desc(schema.submissionVersions.versionNumber)],
                    limit: 1
                }
            }
        });

        const recentSubmissions = recentSubmissionsRaw.map(sub => ({
            id: sub.id,
            paper_id: sub.paperId,
            title: sub.versions?.[0]?.title || "Untitled",
            author_name: sub.correspondingAuthor?.profile?.fullName || "Author",
            status: sub.status,
            submitted_at: sub.submittedAt
        }));

        // 3. Status Distribution
        const publishedResult = await db.select({ value: count() }).from(schema.submissions).where(eq(schema.submissions.status, 'published'));
        const allReviewsResult = await db.select({ value: count() }).from(schema.reviews);
        const completedReviewsResult = await db.select({ value: count() }).from(schema.reviewAssignments).where(eq(schema.reviewAssignments.status, 'completed'));

        const totalSubmissionsVal = Number(totalSubmissions?.value || 0);
        const publishedCountVal = Number(publishedResult[0]?.value || 0);
        const allReviewsVal = Number(allReviewsResult[0]?.value || 0);
        const completedReviewsVal = Number(completedReviewsResult[0]?.value || 0);

        const pubPercent = totalSubmissionsVal > 0 ? (publishedCountVal / totalSubmissionsVal) * 100 : 0;
        const revPercent = allReviewsVal > 0 ? (completedReviewsVal / allReviewsVal) * 100 : 0;
        const totalPayments = await db.select({ value: count() }).from(schema.payments);
        const totalPaymentsVal = Number(totalPayments[0]?.value || 0);

        // 4. Infrastructure/Health
        const startDb = performance.now();
        await db.execute(sql`SELECT 1`);
        const dbLatency = (performance.now() - startDb).toFixed(2);

        const getDirSize = (dirPath: string): number => {
            let size = 0;
            try {
                const files = fs.readdirSync(dirPath);
                for (const file of files) {
                    const filePath = path.join(dirPath, file);
                    const stats = fs.statSync(filePath);
                    if (stats.isDirectory()) {
                        size += getDirSize(filePath);
                    } else {
                        size += stats.size;
                    }
                }
            } catch (e) { }
            return size;
        };

        const uploadsPath = path.join(process.cwd(), 'public', 'uploads');
        const storageSizeBytes = getDirSize(uploadsPath);
        const storageMB = (storageSizeBytes / (1024 * 1024)).toFixed(1);
        const storageLimit = 500;
        const storagePercent = Math.min((Number(storageMB) / storageLimit) * 100, 100);

        return (
            <main className="space-y-6">
                <header className="flex flex-col sm:flex-row sm:items-end justify-between gap-6 py-8 2xl:py-16 border-b border-primary/5">
                    <div className="space-y-1 2xl:space-y-2">
                        <div className="flex items-center gap-2">
                            <Badge className="bg-primary/10 text-primary border-none text-[10px] 2xl:text-base font-semibold tracking-widest px-3 py-1 capitalize">Editorial hub</Badge>
                            <div className="w-2 h-2 2xl:w-4 2xl:h-4 rounded-full bg-emerald-500 animate-pulse" />
                            <span className="text-[10px] 2xl:text-base font-semibold text-muted-foreground capitalize tracking-widest">{new Date().toLocaleDateString('en-US', { month: 'long', year: 'numeric', day: 'numeric' })}</span>
                        </div>
                        <h1 className="font-serif text-2xl xl:text-3xl 2xl:text-4xl font-semibold text-foreground tracking-tight capitalize leading-none">Dashboard</h1>
                        <p className="text-[9px] xl:text-xs 2xl:text-sm font-medium text-muted-foreground border-l-2 border-primary/10 pl-4 capitalize tracking-wide">Managing journal lifecycle and content quality for {user?.fullName}.</p>
                    </div>
                </header>

                {/* Role Overview Banner (Restyled) */}
                <Card className="bg-primary/5 border-primary/10 overflow-hidden relative group rounded-xl shadow-inner mb-6">
                    <div className="absolute top-0 right-0 p-10 opacity-5 pointer-events-none transition-transform duration-700 group-hover:scale-110 rotate-12">
                        <ShieldCheck className="w-32 h-32 text-primary" />
                    </div>
                    <CardContent className="p-8 sm:p-10 2xl:p-20">
                        <div className="max-w-4xl 2xl:max-w-7xl space-y-4 2xl:space-y-8">
                            <Badge className="bg-primary text-white text-[9px] xl:text-xs 2xl:text-base font-semibold tracking-widest px-3 py-1 border-none shadow-sm rounded-lg capitalize">Editorial control</Badge>
                            <h2 className=" font-semibold text-foreground tracking-tight 2xl:text-3xl capitalize">Focus: pipeline throughput & integrity</h2>
                            <div className="flex items-center gap-2 bg-card/80 border border-primary/10 px-4 py-1.5 rounded-lg text-[9px] xl:text-xs 2xl:text-sm font-semibold text-primary/70 capitalize tracking-wide shadow-sm">
                                <div className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse" />
                                All Editorial Protocols Active
                            </div>
                        </div>
                    </CardContent>
                </Card>

                {/* Stats Grid */}
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 2xl:gap-6 transition-all duration-500">
                    {stats.map((stat) => (
                        <Card key={stat.label} className="border-border/40 shadow-sm bg-card transition-all hover:border-primary/20">
                            <CardContent className="p-6">
                                <div className="flex items-center justify-between mb-4">
                                    <div className={`w-10 h-10 2xl:w-16 2xl:h-16 rounded-lg 2xl:rounded-2xl flex items-center justify-center ${stat.variant === 'primary' ? 'bg-primary/10 text-primary' :
                                        stat.variant === 'blue' ? 'bg-blue-500/10 text-blue-600' :
                                            stat.variant === 'emerald' ? 'bg-emerald-500/10 text-emerald-600' :
                                                'bg-amber-500/10 text-amber-600'
                                        }`}>
                                        <div className="[&>svg]:w-4 [&>svg]:h-4 [&>svg]:2xl:w-8 [&>svg]:2xl:h-8">
                                            {stat.icon}
                                        </div>
                                    </div>
                                </div>
                                <div className="space-y-1 2xl:space-y-3">
                                    <p className="text-[9px] xl:text-xs font-semibold text-muted-foreground capitalize tracking-widest">{stat.label}</p>
                                    <h3 className=" font-semibold text-foreground transition-all duration-500 text-lg xl:text-xl 2xl:text-2xl">{stat.value}</h3>
                                </div>
                            </CardContent>
                        </Card>
                    ))}
                </div>

                <Tabs defaultValue="queue" className="space-y-4">
                    <TabsList className="bg-muted/50 p-1 2xl:p-2 w-full flex flex-wrap sm:inline-flex justify-start sm:justify-center h-auto gap-1 2xl:gap-3 rounded-xl 2xl:rounded-2xl">
                        <TabsTrigger value="queue" className="flex-1 sm:flex-none px-4 sm:px-8 py-2 text-[9px] xl:text-xs 2xl:text-sm font-semibold capitalize tracking-widest whitespace-nowrap rounded-lg">Editorial queue</TabsTrigger>
                        <TabsTrigger value="my-papers" className="flex-1 sm:flex-none px-4 sm:px-8 py-2 text-[9px] xl:text-xs 2xl:text-sm font-semibold capitalize tracking-widest whitespace-nowrap rounded-lg">My papers</TabsTrigger>
                        <TabsTrigger value="health" className="flex-1 sm:flex-none px-4 sm:px-8 py-2 text-[9px] xl:text-xs 2xl:text-sm font-semibold capitalize tracking-widest whitespace-nowrap rounded-lg">Sector status</TabsTrigger>
                    </TabsList>

                    <TabsContent value="queue" className="space-y-4">
                        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                            <div className="lg:col-span-2 space-y-4">
                                <Card className="border-border/40 shadow-sm bg-card">
                                    <CardHeader className="flex flex-row items-center justify-between space-y-0 p-6">
                                        <div className="space-y-1">
                                            <CardTitle className="text-sm sm:text-base lg:text-base xl:text-lg 2xl:text-xl font-semibold uppercase tracking-wider flex items-center gap-2">
                                                Active Assignments
                                            </CardTitle>
                                        </div>
                                        <Button asChild variant="ghost" size="sm" className="h-8 group text-primary hover:bg-primary/20 cursor-pointer">
                                            <Link href="/editor/submissions" className="flex items-center gap-2 text-[9px] sm:text-[10px] xl:text-[11px] 2xl:text-xs font-semibold uppercase tracking-wider cursor-pointer">
                                                Manage Pipeline <ArrowRight className="w-3 h-3 transition-transform group-hover:translate-x-1" />
                                            </Link>
                                        </Button>
                                    </CardHeader>
                                    <CardContent className="p-0">
                                        <div className="divide-y divide-border/30">
                                            {recentSubmissions.map((sub: any) => (
                                                <Link
                                                    href={`/editor/submissions/${sub.id}`}
                                                    key={sub.paper_id}
                                                    className="flex items-center justify-between p-5 hover:bg-muted/30 transition-all group"
                                                >
                                                    <div className="flex items-center gap-4 min-w-0">
                                                        <div className="w-12 h-10 rounded bg-muted flex flex-col items-center justify-center font-mono text-[10px] text-muted-foreground border border-border shrink-0">
                                                            <span>ID</span>
                                                            <span className="font-semibold text-foreground">{sub.paper_id.split('-').pop()}</span>
                                                        </div>
                                                        <div className="min-w-0">
                                                            <h4 className=" font-semibold text-foreground truncate group-hover:text-primary transition-colors 2xl:text-lg">{sub.title}</h4>
                                                            <p className="text-[10px] 2xl:text-base text-muted-foreground uppercase font-medium">By {sub.author_name} • {new Date(sub.submitted_at).toLocaleDateString()}</p>
                                                        </div>
                                                    </div>
                                                    <Badge className={`border-none text-[9px] sm:text-[10px] xl:text-[11px] 2xl:text-xs font-semibold uppercase py-0.5 px-2 ${sub.status === 'published' ? 'bg-emerald-500/10 text-emerald-600' : 'bg-primary/10 text-primary'}`}>
                                                        {sub.status.replace('_', ' ')}
                                                    </Badge>
                                                </Link>
                                            ))}
                                            {recentSubmissions.length === 0 && (
                                                <div className="p-12 text-center text-xs text-muted-foreground italic font-medium">No active records in this segment</div>
                                            )}
                                        </div>
                                    </CardContent>
                                </Card>

                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    <Card className="p-6 border-border/40 bg-card">
