                            >
                                <SendHorizonal className="w-4 h-4 relative z-20" />
                                <span className="relative z-20">Submit Manuscript</span>
                            </Link>
                        </div>
                    </motion.div>
                </>
            )}
        </AnimatePresence>,
        document.body
    );
}

