'use client';

import Link from 'next/link';
import { ChevronRight } from 'lucide-react';
import { motion, animate } from 'framer-motion';
import { useRef, useEffect } from 'react';

interface PageHeaderProps {
    title: string;
    description?: string;
    breadcrumbs: { name: string; href: string }[];
    scrollOnComplete?: boolean;
}

export default function PageHeader({ title, description, breadcrumbs, scrollOnComplete = true }: PageHeaderProps) {
    const sectionRef = useRef<HTMLElement>(null);
    const animationRef = useRef<any>(null);

    useEffect(() => {
        const stopAnimation = () => {
            if (animationRef.current) {
                animationRef.current.stop();
                animationRef.current = null;
            }
        };

        window.addEventListener('wheel', stopAnimation, { passive: true });
        window.addEventListener('touchmove', stopAnimation, { passive: true });
        window.addEventListener('pointerdown', stopAnimation, { passive: true });

        return () => {
            window.removeEventListener('wheel', stopAnimation);
            window.removeEventListener('touchmove', stopAnimation);
            window.removeEventListener('pointerdown', stopAnimation);
            stopAnimation();
        };
    }, []);

    const handleAnimationComplete = () => {
        if (scrollOnComplete && sectionRef.current) {
            const sectionBottom =
                sectionRef.current.getBoundingClientRect().bottom + window.scrollY - 80;

            animationRef.current = animate(window.scrollY, sectionBottom, {
                duration: 1.2,
                ease: [0.32, 0.72, 0, 1],
                onUpdate: (latest) => window.scrollTo(0, latest),
            });
        }
    };


    return (
        <section ref={sectionRef} className="relative py-10 sm:py-14 bg-gradient-to-br from-primary via-primary/95 to-accent border-b border-white/5 overflow-hidden">
            {/* Background Decorative Elements */}
            <div className="absolute inset-0 opacity-10 bg-[radial-gradient(circle_at_2px_2px,white_1px,transparent_0)] [background-size:32px_32px]" />
            <div className="absolute -top-24 -right-24 w-[500px] h-[500px] bg-secondary/20 rounded-full blur-[100px] animate-pulse" />
            <div className="absolute -bottom-24 -left-24 w-[400px] h-[400px] bg-accent/20 rounded-full blur-[100px]" />

            <div className="container-responsive relative z-10">
                    <ol className="flex items-center gap-2 list-none p-0">
                        {breadcrumbs.map((crumb, idx) => {
                            const isLast = idx === breadcrumbs.length - 1;
                            return (
                                <motion.li 
                                    key={idx} 
                                    initial={{ opacity: 0, x: -20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    transition={{ duration: 0.6, delay: idx * 0.1, ease: "easeOut" }}
                                    className="flex items-center gap-2"
                                >
                                    <Link
                                        href={crumb.href}
                                        aria-current={isLast ? "page" : undefined}
                                        className={`text-[9px] sm:text-[10px] xl:text-[11px] 2xl:text-xs font-bold tracking-[0.2em] transition-all duration-300 ${isLast ? "text-white" : "text-white/50 hover:text-white"}`}
                                    >
                                        {crumb.name}
                                    </Link>
                                    {!isLast && (
                                        <ChevronRight className="w-3 h-3 text-secondary" />
                                    )}
                                </motion.li>
                            );
                        })}
                    </ol>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 items-end">
                    <motion.div
                        initial={{ opacity: 0, y: 30 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ duration: 0.8, ease: [0.16, 1, 0.3, 1] }}
                        onAnimationComplete={handleAnimationComplete}
                    >
                        <h1 className=" font-bold text-white mb-6 leading-none  tracking-widest">
                            {title}
                        </h1>
                        {description && (
                            <motion.p
                                initial={{ opacity: 0 }}
                                animate={{ opacity: 0.7 }}
                                transition={{ delay: 0.6, duration: 1 }}
                                className="max-w-xl 2xl:max-w-4xl text-xs sm:text-sm lg:text-base 2xl:text-xl text-white/80 font-medium border-l-[3px] border-secondary/50 pl-6 leading-relaxed"
                            >
                                {description}
                            </motion.p>
                        )}
                    </motion.div>

                    {/* VIP Decorative Card or Metric (Optional, adds to the "eye catching" feel) */}
                    <motion.div
                        initial={{ opacity: 0, scale: 0.8 }}
                        animate={{ opacity: 1, scale: 1 }}
                        transition={{ delay: 0.4, duration: 0.8 }}
                        className="hidden lg:flex justify-end"
                    >

                    </motion.div>
                </div>
            </div>
        </section>
    );
}

"use client";

import { useState } from "react";
import { requestResubmissionWithComments } from "@/actions/submissions";
import {
    Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { AlertCircle, CheckCircle, Loader2, RotateCcw } from "lucide-react";
import { useRouter } from "next/navigation";

interface Props {
    submissionId: number;
    paperId: string;
    paperTitle: string;
    requestedBy: string;
}

export function RequestResubmissionModal({ submissionId, paperId, paperTitle, requestedBy }: Props) {
    const router = useRouter();
    const [open, setOpen] = useState(false);
    const [comments, setComments] = useState("");
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [done, setDone] = useState(false);

    async function handleSubmit() {
        if (comments.trim().length < 20) {
            setError("Please provide meaningful feedback (at least 20 characters).");
            return;
        }
        setError(null);
        setLoading(true);
        const result = await requestResubmissionWithComments(submissionId, comments, requestedBy);
        setLoading(false);
        if (result.error) {
            setError(result.error);
        } else {
            setDone(true);
            setTimeout(() => {
                setOpen(false);
                setDone(false);
                setComments("");
                router.refresh();
            }, 2000);
        }
    }

    return (
        <>
            <Button
                onClick={() => setOpen(true)}
                variant="outline"
                size="sm"
                className="h-9 text-xs font-bold uppercase rounded-xl border-orange-300 text-orange-700 hover:bg-orange-50 dark:border-orange-500/30 dark:text-orange-400 dark:hover:bg-orange-500/10 transition-all"
            >
                <RotateCcw className="w-3.5 h-3.5 mr-2" /> Request Resubmission
            </Button>

            <Dialog open={open} onOpenChange={setOpen}>
                <DialogContent className="max-w-lg rounded-2xl">
                    <DialogHeader>
                        <DialogTitle className="font-black uppercase tracking-widest text-foreground">Request Revision</DialogTitle>
                        <DialogDescription className="text-xs text-muted-foreground">
                            Your feedback will be emailed to the author with a link to their Author Portal.
                        </DialogDescription>
                    </DialogHeader>

                    {done ? (
                        <div className="py-10 flex flex-col items-center gap-3 text-center">
                            <CheckCircle className="w-10 h-10 text-emerald-500" />
                            <p className="font-bold text-foreground uppercase tracking-wider text-sm">Revision Requested</p>
                            <p className="text-xs text-muted-foreground">Author has been notified via email.</p>
                        </div>
                    ) : (
                        <>
                            <div className="space-y-4 py-2">
                                <div className="p-3 rounded-xl bg-muted/30 border border-border/50 text-xs space-y-1">
                                    <p className="font-bold text-foreground">{paperTitle}</p>
                                    <Badge variant="outline" className="text-[9px] font-mono">{paperId}</Badge>
                                </div>

                                <div className="space-y-2">
                                    <Label className="text-xs font-bold uppercase tracking-widest">
                                        Reviewer Comments / Required Changes <span className="text-rose-500">*</span>
                                    </Label>
                                    <Textarea
                                        value={comments}
                                        onChange={(e) => setComments(e.target.value)}
                                        placeholder="Describe the required revisions, specific sections to address, formatting issues, missing references, etc."
                                        className="min-h-[150px] text-sm resize-none rounded-xl border-border/60 focus:border-primary/40"
                                    />
                                    <p className="text-[10px] text-muted-foreground">{comments.length} characters (min. 20)</p>
                                </div>

                                {error && (
                                    <div className="flex items-center gap-2 px-4 py-3 rounded-xl bg-rose-50 dark:bg-rose-500/10 border border-rose-200 dark:border-rose-500/20 text-rose-600 text-xs font-medium">
                                        <AlertCircle className="w-3.5 h-3.5 shrink-0" />
                                        {error}
                                    </div>
                                )}

                                <div className="flex items-start gap-2 p-3 rounded-xl bg-amber-50 dark:bg-amber-500/10 border border-amber-200 dark:border-amber-500/20 text-amber-700 dark:text-amber-400 text-[10px]">
                                    <AlertCircle className="w-3.5 h-3.5 shrink-0 mt-0.5" />
                                    The author will have <strong>15 days</strong> to resubmit. If they don't act, their account will be auto-deactivated.
                                </div>
                            </div>

                            <DialogFooter className="gap-2">
                                <Button variant="ghost" onClick={() => setOpen(false)} className="rounded-xl font-bold uppercase text-xs">
                                    Cancel
                                </Button>
                                <Button
                                    onClick={handleSubmit}
                                    disabled={loading}
                                    className="bg-orange-500 hover:bg-orange-600 text-white font-bold uppercase text-xs rounded-xl"
                                >
                                    {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : "Send Request"}
                                </Button>
                            </DialogFooter>
                        </>
                    )}
                </DialogContent>
            </Dialog>
        </>
    );
}

"use client"

import { useState, useRef, useEffect } from "react"
import { Pencil, Check, X, Loader2 } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { cn } from "@/lib/utils"

interface InlineEditFieldProps {
    label: string
    value: string
    onSave: (value: string) => Promise<void>
    readOnly?: boolean
    type?: "text" | "url"
    placeholder?: string
    icon?: React.ReactNode
    className?: string
}

export function InlineEditField({
    label,
    value,
    onSave,
    readOnly = false,
    type = "text",
    placeholder,
    icon,
    className
}: InlineEditFieldProps) {
    const [isEditing, setIsEditing] = useState(false)
    const [currentValue, setCurrentValue] = useState(value)
    const [isLoading, setIsLoading] = useState(false)
    const [error, setError] = useState<string | null>(null)
    const inputRef = useRef<HTMLInputElement>(null)

    useEffect(() => {
        setCurrentValue(value)
    }, [value])

    useEffect(() => {
        if (isEditing) {
            inputRef.current?.focus()
        }
    }, [isEditing])

    const handleSave = async () => {
        if (currentValue === value) {
            setIsEditing(false)
            return
        }
        setIsLoading(true)
        setError(null)
        try {
            await onSave(currentValue)
            setIsEditing(false)
        } catch (e: any) {
            setError(e.message || "Failed to save")
        } finally {
            setIsLoading(false)
        }
    }

    const handleCancel = () => {
        setCurrentValue(value)
        setIsEditing(false)
        setError(null)
    }

    return (
        <div className={cn("space-y-1.5 py-2 group/field", className)}>
            <label className="text-[10px] font-black uppercase tracking-widest text-muted-foreground/60 block px-1">
                {label}
            </label>

            <div className="relative min-h-12 flex items-center">
                {isEditing ? (
                    <div className="flex w-full gap-2 items-center animate-in fade-in slide-in-from-left-2 duration-200">
                        <div className="relative flex-1">
                            {icon && (
                                <div className="absolute left-3 top-1/2 -translate-y-1/2 opacity-40">
                                    {icon}
                                </div>
                            )}
                            <Input
                                ref={inputRef}
                                value={currentValue}
                                onChange={(e) => setCurrentValue(e.target.value)}
                                onKeyDown={(e) => {
                                    if (e.key === "Enter") handleSave()
                                    if (e.key === "Escape") handleCancel()
                                }}
                                placeholder={placeholder}
                                disabled={isLoading}
                                className={cn(
                                    "h-12 bg-background/50 border-primary/20 rounded-xl font-bold transition-all focus:border-primary focus:ring-1 focus:ring-primary/20",
                                    icon && "pl-10"
                                )}
                            />
                        </div>
                        <div className="flex gap-1">
                            <Button
                                size="icon"
                                variant="ghost"
                                onClick={handleSave}
                                disabled={isLoading}
                                className="h-10 w-10 text-emerald-500 hover:text-emerald-600 hover:bg-emerald-500/10 rounded-xl"
                            >
                                {isLoading ? <Loader2 className="w-4 h-4 animate-spin" /> : <Check className="w-5 h-5" />}
                            </Button>
                            <Button
                                size="icon"
                                variant="ghost"
                                onClick={handleCancel}
                                disabled={isLoading}
                                className="h-10 w-10 text-rose-500 hover:text-rose-600 hover:bg-rose-500/10 rounded-xl"
                            >
                                <X className="w-5 h-5" />
                            </Button>
                        </div>
                    </div>
                ) : (
                    <div className="flex w-full justify-between items-center group transition-all">
                        <div className="flex items-center gap-3 px-1 overflow-hidden">
                            {icon && <div className="opacity-40 shrink-0">{icon}</div>}
                            <span className={cn(
                                "font-serif text-lg 2xl:text-xl font-bold truncate transition-colors",
                                !value && "text-muted-foreground italic font-sans text-base opacity-40"
                            )}>
                                {value || placeholder || "Not set"}
                            </span>
                        </div>
                        
                        {!readOnly && (
                            <Button
                                size="icon"
                                variant="ghost"
                                onClick={() => setIsEditing(true)}
                                className="h-10 w-10 opacity-0 group-hover/field:opacity-100 focus:opacity-100 transition-opacity rounded-xl text-primary hover:bg-primary/5"
                                aria-label={`Edit ${label}`}
                            >
                                <Pencil className="w-4 h-4" />
                            </Button>
                        )}
                    </div>
                )}
            </div>

            {error && (
                <p className="text-[10px] text-rose-500 font-bold uppercase transition-all px-1">
                    {error}
                </p>
            )}
        </div>
    )
}

