                        <div className="flex flex-wrap items-center gap-10 2xl:gap-20 pt-4">
                            <div className="flex items-center gap-5">
                                <div className="w-14 h-14 2xl:w-24 2xl:h-24 rounded-2xl 2xl:rounded-[2rem] bg-primary/5 flex items-center justify-center border border-primary/5 text-secondary shadow-inner group-hover:scale-110 transition-transform duration-500" aria-label="Lead Author Icon">
                                    <User className="w-6 h-6 2xl:w-12 2xl:h-12" />
                                </div>
                                <div className="space-y-1">
                                    <p className="text-[10px] 2xl:text-xl font-black text-primary/30 tracking-[0.4em] m-0 uppercase leading-none">Lead Principal</p>
                                    <p className="font-black text-primary text-base 2xl:text-4xl m-0 tracking-tight">{paper.author_name}</p>
                                </div>
                            </div>

                            {paper.affiliation && (
                                <div className="hidden sm:flex items-center gap-5 border-l border-primary/5 pl-10 2xl:pl-20">
                                    <div className="w-14 h-14 2xl:w-24 2xl:h-24 rounded-2xl 2xl:rounded-[2rem] bg-primary/5 flex items-center justify-center border border-primary/5 text-primary/20 shadow-inner" aria-label="Affiliation Icon">
                                        <Globe className="w-6 h-6 2xl:w-12 2xl:h-12" />
                                    </div>
                                    <div className="space-y-1">
                                        <p className="text-[10px] 2xl:text-xl font-black text-primary/30 tracking-[0.4em] m-0 uppercase leading-none">Institution</p>
                                        <p className="text-primary/60 font-bold text-sm 2xl:text-3xl truncate max-w-xs xl:max-w-xl m-0 tracking-tight uppercase opacity-60">{paper.affiliation}</p>
                                    </div>
                                </div>
                            )}
                        </div>
                    </div>

                    {/* Actions - High Contrast */}
                    <div className="flex flex-col sm:flex-row items-center gap-6 pt-10 border-t border-primary/5">
                        <Button asChild className="h-16 2xl:h-24 px-10 2xl:px-20 bg-primary text-white font-black text-[10px] 2xl:text-2xl tracking-[0.3em] shadow-2xl shadow-primary/20 rounded-2xl 2xl:rounded-[2.5rem] hover:scale-[1.03] transition-all w-full sm:w-auto uppercase">
                            <Link href={`${basePath}/${paper.id}`} className="flex items-center gap-4">
                                <Eye className="w-5 h-5 2xl:w-10 2xl:h-10" /> Inspect Details
                            </Link>
                        </Button>

                        {paper.file_path && (
                            <Button asChild variant="outline" className="h-16 2xl:h-24 px-10 2xl:px-20 font-black text-[10px] 2xl:text-2xl tracking-[0.3em] border-primary/10 text-primary hover:bg-secondary hover:text-white hover:border-secondary rounded-2xl 2xl:rounded-[2.5rem] transition-all w-full sm:w-auto uppercase group/dl">
                                <a href={paper.file_path} download className="flex items-center gap-4">
                                    <Download className="w-5 h-5 2xl:w-10 2xl:h-10 group-hover/dl:animate-bounce" /> Get Tech Report
                                </a>
                            </Button>
                        )}
                    </div>
                </div>
            </CardContent>
        </Card>
    );
}

'use client';

import {
    Download,
    User,
    BookOpen,
    Mail,
    Building2,
    Hash,
    ArrowLeft,
    FileText,
    Eye
} from "lucide-react";
import Link from "next/link";
import CitationSection from "./CitationSection";

interface PaperDetailClientProps {
    paper: any;
    id: string;
    mode?: 'current' | 'archive';
}

export default function PaperDetailClient({ paper, id, mode = 'archive' }: PaperDetailClientProps) {
    const isRetracted = paper.status === 'retracted';

    return (
        <div className="container-responsive -mt-10">
            {isRetracted && (
                <div className="mb-12 bg-red-50 border-2 border-red-200 p-8 rounded-[2.5rem] flex flex-col md:flex-row items-center gap-6 shadow-xl shadow-red-900/5 animate-pulse">
                    <div className="w-16 h-16 bg-red-600 rounded-2xl flex items-center justify-center flex-shrink-0 rotate-3">
                        <FileText className="w-8 h-8 text-white" />
                    </div>
                    <div className="flex-1 text-center md:text-left">
                        <h3 className="font-serif font-black text-red-900 text-xl md:text-2xl mb-1 uppercase tracking-tighter">Manuscript Retracted</h3>
                        <p className="text-red-700 font-bold text-sm leading-relaxed max-w-2xl">
                            This article has been formally retracted due to editorial policy violations or significant technical inaccuracies. 
                            Please refer to the official retraction notice for detailed reasoning.
                        </p>
                    </div>
                    {paper.retraction_notice_url && (
                        <a 
                            href={paper.retraction_notice_url} 
                            className="bg-red-900 text-white px-8 py-4 rounded-xl font-black text-[10px] tracking-[0.2em] hover:bg-red-800 transition-colors shadow-lg shadow-red-900/20"
                        >
                            VIEW NOTICE
                        </a>
                    )}
                </div>
            )}

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
                {/* Main Article Content */}
                <div className="lg:col-span-2 space-y-12">
                    {/* Title & Core Meta */}
                    <div className="bg-white p-10 md:p-14 rounded-[3rem] border border-gray-100 shadow-xl shadow-blue-900/5 relative overflow-hidden">
                        <div className="absolute top-0 right-0 w-64 h-64 bg-primary/5 rounded-full -mr-32 -mt-32 blur-3xl opacity-50" />

                        <div className="relative z-10 space-y-8">
                            <div className="flex flex-wrap items-center gap-3">
                                <span className="bg-primary/5 text-primary text-[10px] font-black px-4 py-2 rounded-full  tracking-[0.2em] border border-primary/10">Research Article</span>
                                {paper.volume_number && (
                                    <span className="flex items-center gap-2 bg-secondary/5 text-secondary text-[10px] font-black px-4 py-2 rounded-full  tracking-[0.2em] border border-secondary/10">
                                        <BookOpen className="w-3 h-3" /> Volume {paper.volume_number}, Issue {paper.issue_number}
                                    </span>
                                )}
                                <span className="bg-gray-50 text-gray-600 text-[10px] font-black px-4 py-2 rounded-full  tracking-[0.2em] border border-gray-200">
                                    Published: {new Date(paper.updated_at).toLocaleDateString(undefined, { year: 'numeric', month: 'long', day: 'numeric' })}
                                </span>
                            </div>

                            <h1 className=" font-serif font-black text-gray-900 leading-[1.15]">
                                {paper.title}
                            </h1>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pt-8 border-t border-gray-100/80">
                                <div className="flex items-start gap-4">
                                    <div className="w-12 h-12 rounded-2xl bg-blue-50 flex items-center justify-center border border-blue-100 flex-shrink-0">
                                        <User className="w-6 h-6 text-primary" />
                                    </div>
                                    <div>
                                        <p className="text-[10px] font-black text-gray-600 tracking-widest mb-1">Corresponding Author</p>
                                        <h4 className=" font-bold text-gray-900">{paper.author_name}</h4>
                                        <p className="text-xs text-primary/80 font-bold flex items-center gap-1.5 mt-1">
                                            <Mail className="w-3 h-3" /> {paper.author_email}
                                        </p>
                                    </div>
                                </div>
                                <div className="flex items-start gap-4">
                                    <div className="w-12 h-12 rounded-2xl bg-emerald-50 flex items-center justify-center border border-emerald-100 flex-shrink-0">
                                        <Building2 className="w-6 h-6 text-emerald-600" />
                                    </div>
                                    <div>
                                        <p className="text-[10px] font-black text-gray-600 tracking-widest mb-1">Affiliation</p>
                                        <h4 className=" font-bold text-gray-900 leading-snug">{paper.affiliation}</h4>
                                    </div>
                                </div>
                            </div>

                            {/* Co-Authors List */}
                            {paper.co_authors && (
                                <div className="pt-8 border-t border-gray-100/80 space-y-6">
                                    <h4 className="text-[10px] font-black text-gray-600 tracking-widest uppercase">Contributing Co-Authors</h4>
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                        {(() => {
                                            try {
                                                const coAuthors = JSON.parse(paper.co_authors);
                                                if (!Array.isArray(coAuthors)) return null;
                                                return coAuthors.map((author: any, idx: number) => (
                                                    <div key={idx} className="flex items-start gap-4 group/coauthor">
                                                        <div className="w-10 h-10 rounded-xl bg-gray-50 flex items-center justify-center border border-gray-200 flex-shrink-0 group-hover/coauthor:bg-primary/5 group-hover/coauthor:border-primary/10 transition-colors">
                                                            <User className="w-5 h-5 text-gray-500 group-hover/coauthor:text-primary transition-colors" />
                                                        </div>
                                                        <div className="space-y-1">
                                                            <h5 className=" font-bold text-gray-900 leading-none">{author.name}</h5>
                                                            <p className="text-[10px] font-bold text-primary/80 uppercase tracking-wider">{author.designation}</p>
                                                            <p className="text-[11px] text-gray-700 font-medium leading-relaxed">{author.institution}</p>
                                                        </div>
                                                    </div>
                                                ));
                                            } catch (e) {
                                                console.error("Failed to parse co-authors", e);
                                                return null;
                                            }
                                        })()}
                                    </div>
                                </div>
                            )}
                        </div>
                    </div>

                    {/* Abstract Section */}
                    <div className="bg-gray-50/50 p-10 md:p-14 rounded-[3rem] border border-gray-100 relative group">
                        <h2 className=" font-serif font-black text-gray-900 mb-8 flex items-center gap-3">
                            <FileText className="w-6 h-6 text-primary opacity-50" /> Abstract
                        </h2>
                        <p className="text-gray-800 leading-[1.8] text-justify font-medium indent-8">
                            {paper.abstract}
                        </p>

                        {paper.keywords && (
                            <div className="mt-12 pt-8 border-t border-gray-200/50">
                                <div className="flex items-center gap-2 text-[10px] font-black text-gray-600 tracking-widest mb-4">
                                    <Hash className="w-3 h-3" /> Keywords
                                </div>
                                <div className="flex flex-wrap gap-2">
                                    {paper.keywords.split(',').map((kw: string, i: number) => (
                                        <span key={i} className="bg-white px-4 py-2 rounded-xl text-[10px] font-bold text-gray-700 border border-gray-300 tracking-widest shadow-sm">
                                            {kw.trim()}
                                        </span>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>

                    {/* PDF Viewer Section */}
                    <div className="space-y-6">
                        <div className="flex items-center justify-between px-6">
                            <h2 className=" font-serif font-black text-gray-900">Manuscript Viewer</h2>
                            <a
                                href={paper.file_path}
                                download
                                className="flex items-center gap-2 text-primary font-black text-[10px]  tracking-widest hover:underline"
                            >
                                <Download className="w-4 h-4" /> Download Full Paper (PDF)
                            </a>
                        </div>
                        <div className="w-full h-[800px] bg-gray-100 rounded-[2.5rem] border-4 border-white shadow-2xl overflow-hidden relative group " >
                            <div className="absolute inset-0 bg-gray-900/5 items-center justify-center flex z-0">
                                <div className="text-center space-y-4">
                                    <div className="w-16 h-16 border-4 border-primary border-t-transparent rounded-full animate-spin mx-auto" />
                                    <p className="text-xs font-black text-gray-600 tracking-widest">Initialising Digital Reader</p>
                                </div>
                            </div>
                            <iframe
                                src={`${paper.file_path}#toolbar=0&view=FitH`}
                                className="w-full h-full relative z-10 border-none"
                                title="Manuscript Viewer"
                            />
                        </div>
                    </div>
                </div>

                {/* Sidebar Utilities */}
                <div className="space-y-8">
                    <div className="flex flex-col gap-4 px-4 ">
                        <a
                            href={paper.file_path}
                            target="_blank"
                            className="w-full flex items-center justify-center gap-3 bg-primary text-white py-5 rounded-2xl font-black text-[10px] sm:text-xs tracking-[0.2em] shadow-lg shadow-primary/20 hover:shadow-primary/30 transition-all hover:-translate-y-1 z-10"
                        >
                            <Eye className="w-4 h-4" /> Full Screen View
                        </a>
                    </div>
                    
                    {/* Citation Widget (Client Component) */}
                    <CitationSection paper={paper} />

                    <div className="flex flex-col gap-4 px-4">
                        <Link
                            href={mode === 'current' ? '/current-issue' : '/archives'}
                            className="flex items-center justify-center gap-2 text-gray-600 hover:text-primary transition-all font-black text-[10px] tracking-[0.2em]"
                        >
                            <ArrowLeft className="w-4 h-4" /> Back to {mode === 'current' ? 'Current Issue' : 'Full Archives'}
                        </Link>
                    </div>
                </div>
            </div>
        </div>
    );
}

"use client";

import { Send, CheckCircle, Loader2 } from 'lucide-react';
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { contactSchema, type ContactFormData } from "@/lib/validations/contact";
import { useContactMutation } from '@/hooks/queries/usePublicMutations';
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import {
    Form,
    FormControl,
    FormField,
    FormItem,
    FormLabel,
    FormMessage,
} from "@/components/ui/form";

export default function ContactForm() {
    const contactMutation = useContactMutation();

    const form = useForm<ContactFormData>({
        resolver: zodResolver(contactSchema),
        defaultValues: {
            name: "",
            email: "",
            subject: "",
            message: "",
        },
    });

    async function onSubmit(values: ContactFormData) {
        const formData = new FormData();
        Object.entries(values).forEach(([key, value]) => {
            formData.append(key, value);
        });
        contactMutation.mutate(formData);
    }

    if (contactMutation.isSuccess) {
        return (
            <div className="flex flex-col items-center justify-center p-8 sm:p-12 text-center space-y-4 sm:space-y-6 animate-in fade-in zoom-in duration-500 bg-white rounded-3xl border border-primary/5 shadow-sm">
                <div className="w-16 h-16 sm:w-20 sm:h-20 bg-emerald-50 text-emerald-500 rounded-2xl flex items-center justify-center shadow-inner border border-emerald-100">
                    <CheckCircle className="w-8 h-8 sm:w-10 sm:h-10" />
                </div>
                <div className="space-y-2">
                    <h3 className=" font-black text-primary tracking-widerer">Message <span className="text-emerald-600">Transmitted</span></h3>
                    <p className="text-primary/60 font-medium max-w-xs mx-auto text-xs sm:text-sm leading-relaxed">Our editorial team will get back to you within 24-48 hours via email.</p>
                </div>
                <button 
                  type="button" 
                  onClick={() => {
                    contactMutation.reset();
                    form.reset();
                  }} 
                  className="rounded-xl border border-primary/20 text-primary hover:bg-primary/5 font-black uppercase text-xs tracking-widest mt-4 px-6 py-3 transition-all"
                >
                  Send Another Message
                </button>
            </div>
        );
    }

    return (
        <div className="space-y-6 sm:space-y-8">
            <div>
                <h3 className=" font-black text-primary tracking-wider">Direct Inquiry Form</h3>
                <p className="text-primary/60 text-xs font-medium mt-1">Fill out the form below and we'll get back to you shortly.</p>
            </div>

            <Form {...form}>
                <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-5 sm:space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 sm:gap-6">
                        <FormField
                            control={form.control}
                            name="name"
                            render={({ field }) => (
                                <FormItem className="space-y-2 text-left">
                                    <FormLabel className="text-xs sm:text-sm text-primary/70 uppercase tracking-widest pl-1">Full Name</FormLabel>
                                    <FormControl>
                                        <Input {...field} className="h-12 bg-white border-slate-200 rounded-xl text-primary focus-visible:ring-primary/20 shadow-sm px-4" placeholder="Author Name" />
                                    </FormControl>
                                    <FormMessage className="text-[10px] font-bold text-rose-500 px-1" />
                                </FormItem>
                            )}
                        />
                        <FormField
                            control={form.control}
                            name="email"
                            render={({ field }) => (
                                <FormItem className="space-y-2 text-left">
                                    <FormLabel className="text-xs sm:text-sm text-primary/70 uppercase tracking-widest pl-1">Email Address</FormLabel>
                                    <FormControl>
                                        <Input type="email" {...field} className="h-12 bg-white border-slate-200 rounded-xl text-primary focus-visible:ring-primary/20 shadow-sm px-4" placeholder="researcher@university.edu" />
                                    </FormControl>
                                    <FormMessage className="text-[10px] font-bold text-rose-500 px-1" />
                                </FormItem>
                            )}
                        />
                    </div>
                    <FormField
                        control={form.control}
                        name="subject"
                        render={({ field }) => (
                            <FormItem className="space-y-2 text-left">
                                <FormLabel className="text-xs sm:text-sm text-primary/70 uppercase tracking-widest pl-1">Subject</FormLabel>
                                <FormControl>
                                    <Input {...field} className="h-12 bg-white border-slate-200 rounded-xl text-primary focus-visible:ring-primary/20 shadow-sm px-4" placeholder="Status Inquiry for Paper ID: IJITEST-X" />
                                </FormControl>
                                <FormMessage className="text-[10px] font-bold text-rose-500 px-1" />
                            </FormItem>
                        )}
                    />
                    <FormField
                        control={form.control}
                        name="message"
                        render={({ field }) => (
                            <FormItem className="space-y-2 text-left">
                                <FormLabel className="text-xs sm:text-sm text-primary/70 uppercase tracking-widest pl-1">Message Content</FormLabel>
                                <FormControl>
                                    <Textarea {...field} rows={5} className="bg-white border-slate-200 rounded-xl text-primary focus-visible:ring-primary/20 shadow-sm p-4 resize-none" placeholder="Provide details of your inquiry here..." />
                                </FormControl>
                                <FormMessage className="text-[10px] font-bold text-rose-500 px-1" />
                            </FormItem>
                        )}
                    />

                    <Button
                        type="submit"
                        disabled={contactMutation.isPending}
                        className="w-full h-12 sm:h-14 bg-primary text-white rounded-xl font-black text-sm sm:text-xs tracking-widest sm:tracking-widest shadow-lg shadow-primary/20 hover:scale-[1.01] active:scale-[0.99] transition-all"
                    >
                        {contactMutation.isPending ? (
                            <div className="text-lg flex items-center justify-center gap-2">
                                Transmitting <Loader2 className="w-4 h-4 ml-2 animate-spin" />
                            </div>
                        ) : (
                            <div className="text-lg flex items-center justify-center gap-2">
                                Submit <Send className="w-4 h-4 ml-2" />
                            </div>
                        )}
                    </Button>

                    {contactMutation.isError && (
                        <p className="text-secondary text-center font-bold text-xs uppercase tracking-wider">Failed to transmit. Please try again.</p>
                    )}
                </form>
            </Form>
        </div>
    );
}

"use client";
import { motion } from 'framer-motion';
import { BookOpen, History, ChevronRight } from 'lucide-react';
import { memo } from 'react';

const disciplines = [
    "All Engineering Disciplines",
    "Science & Applied Sciences",
    "Technology & Innovation",
    "Computer Science and Information Technology",
    "AI, Artificial Intelligence, Machine Learning, and Data Science",
    "Electronics & Communication Engineering",
    "Mechanical & Civil Engineering",
    "Internet of Things (IoT), Robotics, and Automation",
    "Renewable Energy and Sustainable Technologies",
    "Management Studies, Business Administration, and Technology Management"
];

function AimAndScope({ journalShortName }: { journalShortName?: string }) {
    const shortName = journalShortName || "IJITEST";

    return (
        <div className="space-y-12">
            {/* Aim & Scope */}
            <motion.section
                initial={{ opacity: 0, y: 20 }}
                whileInView={{ opacity: 1, y: 0 }}
                viewport={{ once: true }}
                transition={{ duration: 0.8 }}
                className="space-y-8"
                aria-labelledby="aim-scope-heading"
            >
                <div className="flex items-center gap-5">
                    <div className="p-4 bg-primary/5 rounded-[2rem] text-primary border border-primary/10 shadow-vip" aria-hidden="true">
                        <BookOpen className="w-7 h-7" />
                    </div>
                    <h2>Call for Papers</h2>
                </div>

                <div className="space-y-10">
                    <p className="text-primary/80 font-medium max-w-3xl">
                        {shortName} covers all major fields of Engineering Disciplines and Modern Technology. Our scope includes, but is not limited to:
                    </p>

                    <motion.ul
                        className="grid grid-cols-1 md:grid-cols-2 gap-4 list-none p-0"
                        initial="hidden"
                        whileInView="visible"
                        viewport={{ once: true, margin: "-50px" }}
                        variants={{
                            hidden: {},
                            visible: {
                                transition: {
                                    staggerChildren: 0.1
                                }
                            }
                        }}
                    >
                        {disciplines.map((item, i) => (
                            <motion.li
                                key={i}
                                variants={{
                                    hidden: { opacity: 0, x: -20, scale: 0.95 },
                                    visible: { opacity: 1, x: 0, scale: 1, transition: { type: "spring", stiffness: 100 } }
                                }}
                                whileHover={{ scale: 1.02 }}
                                className="flex items-center justify-between p-4 bg-white rounded-2xl border border-primary/5 shadow-sm hover:shadow-vip-hover hover:border-secondary/20 transition-all duration-300 group"
                            >
                                <div className="flex items-center gap-4 text-left">
                                    <div className="w-2 h-2 rounded-full bg-secondary group-hover:scale-150 transition-transform group-hover:bg-primary" aria-hidden="true" />
                                    <span className="text-sm font-semibold tracking-[0.2em] text-primary/90 group-hover:text-primary transition-colors cursor-pointer group-hover:text-red-600 hover:font-bold">{item}</span>
                                </div>
                                <ChevronRight className="w-4 h-4 text-primary/20 group-hover:text-secondary group-hover:translate-x-1 transition-all" aria-hidden="true" />
                            </motion.li>
                        ))}
                    </motion.ul>

                    <div className="grid grid-cols-1 gap-4">
                        <article className="p-6 bg-gradient-to-br from-primary/5 to-transparent border border-primary/10 rounded-[2rem] shadow-vip hover:shadow-vip-hover hover:border-secondary/20 hover:border-2 cursor-pointer transition-all duration-300 group">
                            <h3 className="text-primary mb-3 flex items-center gap-2 tracking-widest uppercase">
                                <span className="w-2 h-2 bg-secondary rounded-full" aria-hidden="true" />
                                Mission Priority
                            </h3>
                            <p className="text-primary/70 font-medium">
                                "Interdisciplinary research merging engineering with managerial sciences is highly prioritized."
                            </p>
                        </article>

                        <article className="p-6 bg-gradient-to-br from-secondary/5 to-transparent border border-secondary/10 rounded-[2rem] shadow-vip hover:shadow-vip-hover hover:border-secondary/20 hover:border-2 cursor-pointer transition-all duration-300 group">
                            <p className="text-sm sm:text-base text-primary/70 font-medium leading-relaxed">
                                We particularly welcome interdisciplinary work combining engineering with management, sustainability, and data-driven innovation, especially with direct industrial or societal impact.
                            </p>
                        </article>
                    </div>
                </div>
            </motion.section>

            {/* Publication Process */}
            <section className="bg-primary p-10 rounded-[3rem] text-white overflow-hidden relative shadow-vip border border-white/5 group/proc" aria-labelledby="publication-heading">
                <div className="absolute top-0 right-0 w-80 h-80 bg-secondary opacity-20 rounded-full blur-[100px] -translate-y-1/2 translate-x-1/2 animate-blob pointer-events-none" />
                <div className="absolute -bottom-20 -left-20 w-60 h-60 bg-accent opacity-20 rounded-full blur-[80px] animate-blob pointer-events-none" style={{ '--delay': '2s' } as React.CSSProperties} />

                <div className="relative z-10 flex flex-col md:flex-row items-center gap-12">
                    <div className="w-28 h-28 bg-white/10 backdrop-blur-md rounded-[2rem] flex items-center justify-center shrink-0 border border-white/20 group-hover/proc:rotate-6 group-hover/proc:animate-bounce transition-all duration-500" aria-hidden="true">
                        <History className="w-14 h-14 text-secondary" />
                    </div>
                    <div className="space-y-6">
                        <h2 id="publication-heading" className="text-white">Publication Process</h2>
                        <p className="text-white/80 font-medium m-0">
