"use client";

import { Newspaper, Loader2 } from 'lucide-react';
import { memo, useMemo } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { motion } from 'framer-motion';
import { useLatestIssue } from '@/hooks/queries/usePublic';

function AnnouncementsWidget() {
    const { data: dbIssue, isLoading } = useLatestIssue();

    const currentStatus = useMemo(() => {
        if (dbIssue) {
            return {
                volume: dbIssue.volumeNumber,
                issue: dbIssue.issueNumber,
                date: `${dbIssue.monthRange} ${dbIssue.year}`
            };
        }

        return null;
    }, [dbIssue]);

    if (!currentStatus) return null;

    return (
        <motion.div
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true, margin: "-50px" }}
            transition={{ duration: 0.5, delay: 0.1 }}
        >
            <Card className="border-border/50 shadow-md overflow-hidden">
                <CardHeader className="p-5 pb-0 2xl:p-10 2xl:pb-0">
                    <div className="flex items-center gap-2">
                        <Newspaper className="w-6 h-6 2xl:w-8 2xl:h-8 text-secondary" />
                        <CardTitle className="m-0">Announcements</CardTitle>
                    </div>
                </CardHeader>
                <CardContent className="p-5 pt-4 2xl:p-10 2xl:pt-8 space-y-4 text-justify">
                    {isLoading ? (
                        <div className="p-8 flex items-center justify-center">
                            <Loader2 className="w-6 h-6 animate-spin text-primary/20" />
                        </div>
                    ) : (
                        <div className="p-3 2xl:p-6 bg-slate-50 rounded-xl 2xl:rounded-2xl border border-slate-100 group hover:border-primary/20 transition-colors">
                            <Badge variant="outline" className="text-[12px] h-auto py-1 font-black text-primary border-primary/20 bg-primary/5 mb-4 flex items-center gap-1.5 w-fit">
                                <span className="relative flex h-1.5 w-1.5">
                                    <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75"></span>
                                    <span className="relative inline-flex rounded-full h-1.5 w-1.5 bg-red-500"></span>
                                </span>
                                Current Issue
                            </Badge>
                            <div className="space-y-2">
                                <p className="font-bold text-slate-700 m-0">
                                    Volume {currentStatus.volume}, Issue {currentStatus.issue} ({currentStatus.date}) is now published.
                                </p>
                                <a href="/archives" className="text-sm font-bold text-secondary flex items-center gap-1 hover:text-primary transition-colors">
                                    Open Articles
                                </a>
                            </div>
                        </div>
                    )}
                </CardContent>
            </Card>
        </motion.div>
    );
}

export default memo(AnnouncementsWidget);

'use client'

import { useState } from 'react';
import { Button } from "@/components/ui/button";
import { FileUp, FileCheck, Loader2, Download, RefreshCw, X } from "lucide-react";
import { toast } from "sonner";
import { uploadManuscriptPdf } from "@/actions/submissions";

export default function AdminPdfUpload({ submissionId, currentUrl }: { submissionId: number, currentUrl?: string | null }) {
    const [showUpload, setShowUpload] = useState(!currentUrl);
    const [isUploading, setIsUploading] = useState(false);

    async function handleUpload(formData: FormData) {
        setIsUploading(true);
        try {
            const result = await uploadManuscriptPdf(submissionId, formData);
            if (result.success) {
                toast.success('Manuscript synchronized successfully');
                setShowUpload(false);
                window.location.reload();
            } else {
                toast.error(result.error);
            }
        } catch (error) {
            toast.error('Failed to synchronize manuscript');
        } finally {
            setIsUploading(false);
        }
    }

    if (!showUpload && currentUrl) {
        return (
            <div className="space-y-4">
                <div className="flex flex-col gap-3">
                    <Button 
                        asChild 
                        variant="outline" 
                        className="group w-full h-14 gap-3 border-emerald-500/20 bg-emerald-500/5 text-emerald-600 font-black text-xs tracking-widest rounded-xl hover:bg-emerald-500 hover:text-white dark:hover:text-black transition-all cursor-pointer shadow-sm shadow-emerald-500/5"
                    >
                        <a href={currentUrl} download className="flex items-center justify-center w-full">
                            <Download className="w-5 h-5 group-hover:scale-110 transition-transform" />
                            <span>Download Active Asset</span>
                        </a>
                    </Button>
                    <Button
                        onClick={() => setShowUpload(true)}
                        variant="ghost"
                        className="w-full h-11 gap-3 text-muted-foreground hover:text-primary font-black text-[10px] tracking-widest rounded-xl hover:bg-primary/5 transition-all cursor-pointer border border-transparent hover:border-primary/10"
                    >
                        <RefreshCw className="w-4 h-4" />
                        <span>Update Manuscript PDF</span>
                    </Button>
                </div>
            </div>
        );
    }

    return (
        <form action={handleUpload} className="space-y-4">
            <div className="space-y-3">
                <div className="flex items-center justify-between px-1">
                    <label className="text-[10px] font-black text-muted-foreground uppercase tracking-[0.2em] opacity-60">Upload PDF Manuscript</label>
                    {currentUrl && (
                        <button
                            type="button"
                            onClick={() => setShowUpload(false)}
                            className="flex items-center gap-1 text-[10px] font-black text-rose-500 uppercase tracking-widest hover:text-rose-600 transition-colors"
                        >
                            <X className="w-3 h-3" /> Cancel
                        </button>
                    )}
                </div>

                <div className={`relative group border-2 border-dashed rounded-xl p-8 transition-all duration-300 flex flex-col items-center justify-center gap-4 ${isUploading ? 'bg-primary/5 border-primary/20 cursor-wait' : 'bg-muted/30 border-primary/10 hover:bg-primary/3 hover:border-primary/30 cursor-pointer'}`}>
                    <input
                        title="pdfFile"
                        name="pdfFile"
                        type="file"
                        accept=".pdf"
                        required
                        className="absolute inset-0 opacity-0 cursor-pointer z-10 disabled:cursor-wait"
                        disabled={isUploading}
                    />
                    
                    {isUploading ? (
                        <div className="flex flex-col items-center gap-4 animate-pulse">
                            <div className="w-12 h-12 rounded-full border-4 border-primary/10 border-t-primary animate-spin" />
                            <p className="text-[10px] font-black text-primary uppercase tracking-[0.3em]">Synchronizing Archive...</p>
                        </div>
                    ) : (
                        <>
                            <div className="w-14 h-14 rounded-2xl bg-primary/5 flex items-center justify-center group-hover:bg-primary/10 transition-colors">
                                <FileUp className="w-7 h-7 text-primary opacity-60 group-hover:opacity-100 group-hover:scale-110 transition-all" />
                            </div>
                            <div className="text-center space-y-1">
                                <p className="text-[11px] font-black text-primary uppercase tracking-widest">Select Secure PDF</p>
                                <p className="text-[9px] font-bold text-muted-foreground uppercase tracking-wider opacity-40">Manuscript formatting enforced</p>
                            </div>
                        </>
                    )}
                </div>
            </div>

            <Button
                type="submit"
                disabled={isUploading}
                className="w-full h-12 gap-3 bg-primary text-white dark:text-black font-black text-xs tracking-widest rounded-xl transition-all shadow-xl shadow-primary/20 hover:scale-[1.02] active:scale-[0.98] disabled:opacity-50 disabled:scale-100 cursor-pointer"
            >
                {isUploading ? (
                    <Loader2 className="w-4 h-4 animate-spin" />
                ) : (
                    <FileCheck className="w-4 h-4" />
                )}
                <span>Finalize Submission Asset</span>
            </Button>
        </form>
    );
}

"use client";

import { Trash2, Loader2, AlertTriangle, XCircle } from "lucide-react";
import { deleteSubmission } from "@/actions/submissions";
import { useState } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/button";
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
    AlertDialogTrigger,
} from "@/components/ui/alert-dialog";

interface DeleteSubmissionButtonProps {
    submissionId: number;
    status?: string;
    variant?: "icon" | "full";
}

export default function DeleteSubmissionButton({ submissionId, status, variant = "icon" }: DeleteSubmissionButtonProps) {
    const [loading, setLoading] = useState(false);
    const router = useRouter();
    const [open, setOpen] = useState(false);
    const [errorOpen, setErrorOpen] = useState(false);
    const [errorMessage, setErrorMessage] = useState("");

    const isRestricted = status === 'paid' || status === 'published';

    async function handleDelete() {
        if (isRestricted) {
            setErrorMessage("This submission is marked as paid or published and cannot be deleted from the active registry.");
            setErrorOpen(true);
            return;
        }

        setLoading(true);
        try {
            const res = await deleteSubmission(submissionId);
            if (res.success) {
                if (variant === "full") {
                    router.push("/admin/submissions");
                } else {
                    router.refresh();
                }
            } else {
                setErrorMessage(res.error || "Failed to terminate the submission node.");
                setErrorOpen(true);
            }
        } catch (error) {
            setErrorMessage("An architectural error occurred during node termination.");
            setErrorOpen(true);
        } finally {
            setLoading(false);
            setOpen(false);
        }
    }

    const trigger = variant === "full" ? (
        <Button
            variant="outline"
            disabled={loading || isRestricted}
            className="w-full h-14 gap-3 border-red-500/10 text-red-400 font-black text-xs  tracking-[0.2em] rounded-2xl hover:bg-red-500/5 hover:text-red-600 transition-all  shadow-inner cursor-pointer"
        >
            {loading ? (
                <Loader2 className="w-5 h-5 animate-spin" />
            ) : (
                <Trash2 className="w-5 h-5" />
            )}
            {isRestricted ? 'Termination Restricted' : 'Terminate Submission'}
        </Button>
    ) : (
        <Button
            variant="ghost"
            size="icon"
            disabled={loading || isRestricted}
            className="w-12 h-12 bg-red-500/5 text-red-400 rounded-xl hover:bg-red-500/10 hover:text-red-600 transition-all disabled:opacity-50 shadow-inner cursor-pointer"
            title={isRestricted ? "Termination Restricted" : "Terminate Node"}
        >
            {loading ? (
                <Loader2 className="w-5 h-5 animate-spin" />
            ) : (
                <Trash2 className="w-5 h-5" />
            )}
        </Button>
    );

    return (
        <>
            <AlertDialog open={open} onOpenChange={setOpen}>
                <AlertDialogTrigger asChild>
                    {trigger}
                </AlertDialogTrigger>
                <AlertDialogContent className="rounded-[2.5rem] p-8 bg-white border-red-500/10 shadow-2xl">
                    <AlertDialogHeader className="space-y-4">
                        <div className="w-16 h-16 rounded-2xl bg-red-500/5 border border-red-500/10 flex items-center justify-center text-red-500 shadow-inner mb-2">
                            <AlertTriangle className="w-8 h-8" />
                        </div>
                        <AlertDialogTitle className="text-2xl font-black text-red-600 tracking-widerer ">Critical Termination Protocol</AlertDialogTitle>
                        <AlertDialogDescription className="text-xs font-medium text-red-900/40 leading-relaxed  tracking-widest ">
                            DANGER: This action will permanently erase this manuscript node and all associated technical dossiers from the global server. This operation is irreversible.
                        </AlertDialogDescription>
                    </AlertDialogHeader>
                    <AlertDialogFooter className="pt-6 gap-4">
                        <AlertDialogCancel className="h-14 px-8 rounded-2xl font-black text-[10px]  tracking-widest border-primary/10 text-primary/40 hover:bg-primary/5 cursor-pointer">
                            Abort Protocol
                        </AlertDialogCancel>
                        <AlertDialogAction
                            onClick={handleDelete}
                            className="h-14 px-8 rounded-2xl bg-red-600 text-white font-black text-[10px]  tracking-widest hover:bg-red-700 shadow-xl shadow-red-600/20 cursor-pointer"
                        >
                            Authorize Termination
                        </AlertDialogAction>
                    </AlertDialogFooter>
                </AlertDialogContent>
            </AlertDialog>

            <AlertDialog open={errorOpen} onOpenChange={setErrorOpen}>
                <AlertDialogContent className="rounded-[2.5rem] p-8 bg-white border-primary/5 shadow-2xl">
                    <AlertDialogHeader className="space-y-4">
                        <div className="w-16 h-16 rounded-2xl bg-amber-500/5 border border-amber-500/10 flex items-center justify-center text-amber-500 shadow-inner mb-2">
                            <XCircle className="w-8 h-8" />
                        </div>
                        <AlertDialogTitle className="text-2xl font-black text-primary tracking-widerer ">Access Restricted</AlertDialogTitle>
                        <AlertDialogDescription className="text-xs font-medium text-primary/40 leading-relaxed  tracking-widest ">
                            {errorMessage}
                        </AlertDialogDescription>
                    </AlertDialogHeader>
                    <AlertDialogFooter className="pt-6">
                        <Button onClick={() => setErrorOpen(false)} className="w-full h-14 font-black text-[10px]  tracking-widest shadow-xl shadow-primary/20  rounded-2xl cursor-pointer">
                            Acknowledge
                        </Button>
                    </AlertDialogFooter>
                </AlertDialogContent>
            </AlertDialog>
        </>
    );
}

'use client'

import { useState } from 'react'
import { Plus, Globe, Loader2, Layers } from 'lucide-react'
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { toast } from 'sonner'
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
    DialogFooter
} from "@/components/ui/dialog"
import {
    useVolumesIssues,
    useCreateVolumeIssue,
    useAssignPaperToIssue
} from '@/hooks/queries/usePublications'

interface PublicationAssignmentProps {
    submissionId: number;
    currentIssueId?: number | null;
}

export default function PublicationAssignment({ submissionId, currentIssueId }: PublicationAssignmentProps) {
    const { data: volumes = [], isLoading: loading } = useVolumesIssues();
    const createMutation = useCreateVolumeIssue();
    const assignMutation = useAssignPaperToIssue();

    const [showCreateModal, setShowCreateModal] = useState(false);
    const [selectedIssueId, setSelectedIssueId] = useState<string>(currentIssueId?.toString() || "");
    const [startPage, setStartPage] = useState<string>("");
    const [endPage, setEndPage] = useState<string>("");
    const [isSubmitting, setIsSubmitting] = useState(false);

    async function handleQuickCreate(formData: FormData) {
        setIsSubmitting(true);
        try {
            toast.promise(
                createMutation.mutateAsync(formData).then((res) => {
                    if (!res.success) throw new Error(res.error || "Failed to initialize cycle");
                    return res;
                }),
                {
                    loading: 'Initializing publication cycle...',
                    success: () => {
                        setShowCreateModal(false);
                        return 'Publication cycle initialized';
                    },
                    error: (err) => err.message
                }
            );
        } finally {
            setIsSubmitting(false);
        }
    }

    async function handleAssign() {
        if (!selectedIssueId) {
            toast.error("Please select a target issue node");
            return;
        }

        toast.promise(
            assignMutation.mutateAsync({
                submissionId,
                issueId: parseInt(selectedIssueId),
                startPage: startPage ? parseInt(startPage) : undefined,
                endPage: endPage ? parseInt(endPage) : undefined
            }).then((res) => {
                if (!res.success) throw new Error(res.error || "Failed to assign paper to issue");
                return res;
            }),
            {
                loading: 'Committing manuscript to archive...',
                success: 'Manuscript committed to archive',
                error: (err) => err.message
            }
        );
    }

    if (loading) return (
        <div className="h-11 bg-primary/5 rounded-xl animate-pulse flex items-center justify-center">
            <Loader2 className="w-4 h-4 text-primary/20 animate-spin" />
        </div>
    );

    return (
        <div className="space-y-4 pt-4 border-t border-emerald-500/10">
            <div className="space-y-4">
                <div className="space-y-2">
                    <div className="flex items-center justify-between px-1">
                        <label className="text-[9px] font-black text-muted-foreground tracking-widest leading-none">Volume and Issue</label>
                        <Dialog open={showCreateModal} onOpenChange={setShowCreateModal}>
                            <DialogTrigger asChild>
                                <button className="text-[9px] font-black text-emerald-600 hover:text-emerald-700 tracking-widest flex items-center gap-1 transition-colors cursor-pointer">
                                    <Plus className="w-2.5 h-2.5" /> Add new
                                </button>
                            </DialogTrigger>
                            <DialogContent className="sm:max-w-md rounded-xl p-8 bg-card border-primary/5 shadow-2xl overflow-hidden">
                                <div className="absolute top-0 left-0 w-full h-2 bg-emerald-500/10" />
                                <DialogHeader className="space-y-2">
                                    <DialogTitle className="text-2xl font-black text-foreground tracking-wider">Quick Terminal</DialogTitle>
                                    <DialogDescription className="text-xs font-semibold text-muted-foreground tracking-wider leading-relaxed">
                                        Instantly define a new publication node for immediate manuscript archival.
                                    </DialogDescription>
                                </DialogHeader>
                                <form action={handleQuickCreate} className="space-y-5 mt-4">
                                    <div className="grid grid-cols-2 gap-4">
                                        <div className="space-y-2">
                                            <Label className="text-[9px] font-black text-primary/60 tracking-widest uppercase">Volume</Label>
                                            <Input
                                                name="volume"
                                                type="number"
                                                required
                                                className="h-12 bg-primary/5 border-none font-bold text-sm rounded-xl px-4"
                                                placeholder="e.g. 1"
                                            />
                                        </div>
                                        <div className="space-y-2">
                                            <Label className="text-[9px] font-black text-primary/60 tracking-widest uppercase">Issue</Label>
                                            <Input
                                                name="issue"
                                                type="number"
                                                required
                                                className="h-12 bg-primary/5 border-none font-bold text-sm rounded-xl px-4"
                                                placeholder="e.g. 1"
                                            />
                                        </div>
                                    </div>
                                    <div className="space-y-2">
                                        <Label className="text-[9px] font-black text-primary/60 tracking-widest uppercase">Year</Label>
                                        <Input
                                            name="year"
                                            type="number"
                                            required
                                            defaultValue={new Date().getFullYear()}
                                            className="h-12 bg-primary/5 border-none font-black text-sm rounded-xl px-4"
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <Label className="text-[9px] font-black text-primary/60 tracking-widest uppercase">Month Range</Label>
                                        <Input
                                            name="monthRange"
                                            type="text"
                                            required
                                            placeholder="e.g. Jan - Mar"
                                            className="h-12 bg-primary/5 border-none font-bold text-sm rounded-xl px-4"
                                        />
                                    </div>
                                    <DialogFooter className="pt-2">
                                        <Button disabled={isSubmitting} type="submit" className="w-full h-12 bg-emerald-600 text-white font-black text-[10px] tracking-widest rounded-xl shadow-lg shadow-emerald-600/10 cursor-pointer">
                                            {isSubmitting ? <Loader2 className="w-4 h-4 animate-spin" /> : 'Create'}
                                        </Button>
                                    </DialogFooter>
                                </form>
                            </DialogContent>
                        </Dialog>
                    </div>
                    <div className="relative">
                        <select
                            title="issueId"
                            value={selectedIssueId}
                            onChange={(e) => setSelectedIssueId(e.target.value)}
                            className="w-full h-11 bg-background border border-emerald-500/20 text-[11px] font-black tracking-widest rounded-xl px-4 appearance-none outline-none focus:ring-4 focus:ring-emerald-500/5 transition-all text-emerald-900 cursor-pointer"
                        >
                            <option value="">Select Target Issue...</option>
                            {volumes.map((vi: any) => (
                                <option key={vi.id} value={vi.id}>
                                    VOL {vi.volume_number} ISSUE {vi.issue_number} ({vi.year})
                                </option>
                            ))}
                        </select>
                        <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none opacity-40">
                            <Layers className="w-4 h-4 text-emerald-600" />
                        </div>
                    </div>
                </div>

                <div className="grid grid-cols-2 gap-3">
                    <div className="space-y-2">
                        <label className="text-[9px] font-black text-muted-foreground tracking-widest leading-none uppercase">Start Page</label>
                        <Input
                            type="number"
                            placeholder="e.g. 4"
                            value={startPage}
                            onChange={(e) => setStartPage(e.target.value)}
                            className="h-10 bg-background border-emerald-500/10 font-bold text-xs rounded-lg"
                        />
                    </div>
                    <div className="space-y-2">
                        <label className="text-[9px] font-black text-muted-foreground tracking-widest leading-none uppercase">End Page</label>
                        <Input
                            type="number"
                            placeholder="e.g. 8"
                            value={endPage}
                            onChange={(e) => setEndPage(e.target.value)}
                            className="h-10 bg-background border-emerald-500/10 font-bold text-xs rounded-lg"
                        />
                    </div>
                </div>
            </div>

            <Button
                onClick={handleAssign}
                disabled={assignMutation.isPending || !selectedIssueId}
                className="w-full h-12 bg-emerald-600 hover:bg-emerald-700 text-white font-black text-[11px] tracking-widest rounded-xl shadow-xl shadow-emerald-600/20 cursor-pointer transition-all active:scale-[0.98]"
            >
                {assignMutation.isPending ? (
                    <Loader2 className="w-4 h-4 animate-spin mr-2" />
                ) : (
                    <Globe className="w-4 h-4 mr-2" />
                )}
                {assignMutation.isPending ? 'INDEXING...' : 'Commit to Archive'}
            </Button>
        </div>
    );
}

"use client";

import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Loader2, CreditCard } from "lucide-react";
import { createRazorpayOrder, verifyRazorpayPayment } from "@/actions/razorpay-actions";
import { useRouter } from "next/navigation";
import { toast } from "sonner";

interface RazorpayPaymentProps {
    submissionId: number;
    paperId: string;
}

declare global {
    interface Window {
        Razorpay: any;
    }
}

export default function RazorpayPayment({ submissionId, paperId }: RazorpayPaymentProps) {
    const [loading, setLoading] = useState(false);
    const router = useRouter();

    const handlePayment = async () => {
        setLoading(true);
        try {
            const result = await createRazorpayOrder(submissionId, paperId);

            if (!result.success) {
                toast.error("Order Creation Failed", {
                    description: result.error
                });
                setLoading(false);
                return;
            }

            const { order } = result;

            const options = {
                key: order.key,
                amount: order.amount,
                currency: order.currency,
                name: "IJITEST APC Payment",
                description: `Payment for Manuscript ID: ${paperId}`,
                order_id: order.id,
                handler: async function (response: any) {
                    setLoading(true);
                    const verifyData = {
                        razorpay_order_id: response.razorpay_order_id,
                        razorpay_payment_id: response.razorpay_payment_id,
                        razorpay_signature: response.razorpay_signature,
                        submissionId: submissionId,
                    };

                    const verification = await verifyRazorpayPayment(verifyData);

                    if (verification.success) {
                        toast.success("Payment Verified", {
                            description: "Your paper status has been updated successfully."
                        });
                        router.refresh();
                    } else {
                        toast.error("Verification Refused", {
                            description: verification.error
                        });
                    }
                    setLoading(false);
                },
                prefill: {
                    name: "", // Can be passed from props if available
                    email: "",
                },
                theme: {
                    color: "#6d0202",
                },
                modal: {
                    ondismiss: function () {
                        setLoading(false);
                    }
                }
            };

            const rzp = new window.Razorpay(options);
            rzp.on('payment.failed', function (response: any) {
                toast.error("Payment Interrupted", {
                    description: response.error.description
                });
                setLoading(false);
            });
            rzp.open();
        } catch (error) {
            console.error("Payment Error:", error);
            toast.error("System Malfunction", {
                description: "An unexpected error occurred while initiating protocol."
            });
            setLoading(false);
        }
    };

    return (
        <Button
            onClick={handlePayment}
            disabled={loading}
            className="w-full h-14 bg-emerald-600 hover:bg-emerald-700 text-white font-black text-xs  tracking-[0.2em] rounded-2xl shadow-lg shadow-emerald-200 transition-all hover:scale-[1.02] active:scale-[0.98] flex items-center justify-center gap-3"
        >
            {loading ? (
                <>Processing <Loader2 className="w-5 h-5 animate-spin" /></>
            ) : (
                <>
                    <CreditCard className="w-5 h-5" />
                    Complete APC Payment (INR)
                </>
            )}
        </Button>
    );
}

'use client';

import React, { useState, useMemo } from 'react';
import {
    User,
    Calendar,
    MessageSquare,
    MoreVertical,
    FileText,
    Eye,
    Download
} from 'lucide-react';
import Link from 'next/link';
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table";
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
    Tooltip,
    TooltipContent,
    TooltipProvider,
    TooltipTrigger,
} from "@/components/ui/tooltip";
import { Separator } from '@/components/ui/separator';
import { motion } from 'framer-motion';
import SubmissionSearch from './SubmissionSearch';
import DeleteSubmissionButton from './DeleteSubmissionButton';

interface SubmissionContainerProps {
    submissions: any[];
    currentStatus: string;
    role: 'admin' | 'editor';
}

export default function SubmissionContainer({ submissions, currentStatus, role }: SubmissionContainerProps) {
    const [filterQuery, setFilterQuery] = useState('');

    const filteredSubmissions = useMemo(() => {
        if (!filterQuery) return submissions;
        const q = filterQuery.toLowerCase();
        return submissions.filter(sub =>
            sub.paper_id.toLowerCase().includes(q) ||
            sub.title.toLowerCase().includes(q) ||
            sub.author_name.toLowerCase().includes(q)
        );
    }, [submissions, filterQuery]);

    const getStatusVariant = (status: string) => {
        switch (status) {
            case 'submitted': return 'bg-blue-500/10 text-blue-700 border border-blue-200/50 dark:border-blue-500/20 shadow-sm';
            case 'under_review': return 'bg-amber-500/10 text-amber-700 border border-amber-200/50 dark:border-amber-500/20 shadow-sm';
            case 'accepted': return 'bg-purple-500/10 text-purple-700 border border-purple-200/50 dark:border-purple-500/20 shadow-sm';
            case 'rejected': return 'bg-rose-500/10 text-rose-700 border border-rose-200/50 dark:border-rose-500/20 shadow-sm';
            case 'retracted': return 'bg-red-600/10 text-red-600 border border-red-200/50 dark:border-red-500/20 shadow-sm';
            case 'paid': return 'bg-emerald-500/10 text-emerald-700 border border-emerald-200/50 dark:border-emerald-500/20 shadow-sm';
            case 'published': return 'bg-cyan-500/10 text-cyan-700 border border-cyan-200/50 dark:border-cyan-500/20 shadow-sm';
            default: return 'bg-muted text-muted-foreground border-none';
        }
    };

    return (
        <div className="flex flex-col">
            {/* Search & Stats Header */}
            <div className="p-8 border-b border-primary/5 space-y-6 bg-primary/1">
                <div className="flex flex-col md:flex-row gap-6 items-stretch md:items-center justify-between ">
                    <div className="flex-1">
                        <SubmissionSearch 
                            placeholder="Search by ID, Title or Author..." 
                            onLocalFilter={setFilterQuery}
                        />
                    </div>
                    <div className="flex items-center gap-6 px-8 py-4 bg-white/50 backdrop-blur-md rounded-2xl border border-primary/10 shrink-0 shadow-sm transition-all hover:border-primary/20 self-start md:self-auto group">
                        <div className="flex flex-col items-end">
                            <span className="text-[10px] font-black text-primary/30 tracking-widest uppercase">Registry Yield</span>
                            <span className="text-xl font-black text-primary/80 tracking-tighter">
                                {filteredSubmissions.length} <span className="text-primary/20 mx-1">/</span> {submissions.length}
                            </span>
                        </div>
                        <div className="w-10 h-10 rounded-xl bg-primary/5 flex items-center justify-center group-hover:rotate-12 transition-transform">
                            <FileText className="w-5 h-5 text-primary/40" />
                        </div>
                    </div>
                </div>
            </div>

            {/* Mobile Card View */}
            <div className="md:hidden divide-y divide-primary/5">
                {filteredSubmissions.map((sub: any) => (
                    <motion.div 
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        key={sub.id} 
                        className="p-8 space-y-6 bg-card active:bg-primary/2 transition-colors relative"
                    >
                        <div className="flex justify-between items-start gap-4">
                            <div className="space-y-3 flex-1">
                                <div className="flex flex-wrap items-center gap-2">
                                    <span className="font-mono font-black text-[10px] bg-primary/5 px-2.5 py-1 rounded-lg border border-primary/10 text-primary/60 shadow-inner">
                                        {sub.paper_id}
                                    </span>
                                    <Badge className={`h-6 px-3 text-[9px] font-black tracking-[0.2em] shadow-sm rounded-lg uppercase ${getStatusVariant(sub.status)}`}>
                                        {sub.status.replace('_', ' ')}
                                    </Badge>
                                    {sub.status === 'under_review' && sub.completed_reviews > 0 && (
                                        <Badge variant="outline" className="h-6 px-2 text-[9px] font-black text-emerald-600 bg-emerald-500/5 border-emerald-500/20">
                                            {sub.completed_reviews} REVIEWS
                                        </Badge>
                                    )}
                                </div>
                                <h4 className="font-serif font-black text-foreground text-lg leading-tight tracking-tight">
                                    {sub.title}
                                </h4>
                            </div>
                            <DropdownMenu>
                                <DropdownMenuTrigger asChild>
                                    <Button variant="ghost" size="icon" className="h-12 w-12 text-primary/30 hover:text-primary rounded-2xl -mr-3 bg-primary/5">
                                        <MoreVertical className="w-6 h-6" />
                                    </Button>
                                </DropdownMenuTrigger>
                                <DropdownMenuContent align="end" className="w-64 rounded-3xl p-3 shadow-2xl border-primary/5 bg-white/95 backdrop-blur-xl">
                                    <DropdownMenuItem asChild className="rounded-xl h-14 gap-4 px-5 focus:bg-primary/5 focus:text-primary transition-all">
                                        <Link href={`/${role}/submissions/${sub.id}`}>
                                            <div className="w-8 h-8 rounded-lg bg-primary/5 flex items-center justify-center">
                                                <Eye className="w-4 h-4 text-primary" />
                                            </div>
                                            <div className="flex flex-col">
                                                <span className="text-[10px] font-black tracking-widest uppercase">View Details</span>
                                                <span className="text-[9px] text-muted-foreground font-bold">Open Protocol Dashboard</span>
                                            </div>
                                        </Link>
                                    </DropdownMenuItem>
                                    <Separator className="my-3 bg-primary/5" />
                                    {role === 'admin' && sub.status !== 'published' && (
                                        <div className="px-1 py-1">
                                            <DeleteSubmissionButton submissionId={sub.id} status={sub.status} variant="full" />
                                        </div>
                                    )}
                                </DropdownMenuContent>
                            </DropdownMenu>
                        </div>

                        <div className="grid grid-cols-2 gap-4 pb-4">
                            <div className="space-y-1">
                                <span className="text-[10px] font-black text-primary/20 tracking-widest uppercase">Corresponding Author</span>
                                <p className="text-xs font-bold text-foreground flex items-center gap-2 truncate">
                                    <User className="w-3.5 h-3.5 opacity-30" /> {sub.author_name}
                                </p>
                            </div>
                            <div className="space-y-1 text-right">
                                <span className="text-[10px] font-black text-primary/20 tracking-widest uppercase">Registry Date</span>
                                <p className="text-xs font-bold text-foreground flex items-center gap-2 justify-end">
                                    {new Date(sub.submitted_at).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })}
                                </p>
                            </div>
                        </div>

                        <Button asChild variant="outline" className="w-full h-14 text-[10px] font-black uppercase tracking-[0.2em] rounded-2xl border-primary/10 hover:bg-primary/5 shadow-sm active:scale-[0.98] transition-all">
                            <Link href={`/${role}/submissions/${sub.id}`}>Examine Full Dossier</Link>
                        </Button>
                    </motion.div>
                ))}
            </div>

            {/* Desktop Table View */}
            <div className="hidden md:block overflow-visible px-4">
                <Table>
                    <TableHeader className="bg-primary/5 border-none">
                        <TableRow className="hover:bg-transparent border-none">
                            <TableHead className="h-16 px-8 text-[10px] font-black text-primary/40 tracking-[0.3em] uppercase w-48">Registry ID</TableHead>
                            <TableHead className="h-16 px-8 text-[10px] font-black text-primary/40 tracking-[0.3em] uppercase">Manuscript Dossier</TableHead>
                            <TableHead className="h-16 px-8 text-[10px] font-black text-primary/40 tracking-[0.3em] uppercase w-56 text-center">Protocol Status</TableHead>
                            <TableHead className="h-16 px-8 text-[10px] font-black text-primary/40 tracking-[0.3em] uppercase w-40 text-right">Operations</TableHead>
                        </TableRow>
                    </TableHeader>
                    <TableBody>
                        {filteredSubmissions.map((sub: any, idx) => (
                            <TableRow 
                                key={sub.id} 
                                className={`border-b border-primary/5 group transition-all duration-300 hover:shadow-2xl hover:shadow-primary/5 hover:bg-white relative z-[${100 - idx}]`}
                            >
                                <TableCell className="px-8 py-8">
                                    <span className="font-mono font-black text-[11px] bg-primary/5 px-3 py-2 rounded-xl border border-primary/10 text-primary/60 shadow-inner group-hover:bg-white transition-colors">
                                        {sub.paper_id}
                                    </span>
                                </TableCell>
                                <TableCell className="px-8 py-8">
                                    <div className="flex flex-col gap-2 max-w-2xl">
                                        <h4 className="font-serif font-black text-foreground text-xl leading-tight tracking-tight group-hover:text-primary transition-colors">
                                            {sub.title}
                                        </h4>
                                        <div className="flex items-center gap-8 text-[11px] font-bold text-muted-foreground tracking-widest uppercase">
                                            <span className="flex items-center gap-2 group-hover:text-foreground transition-colors">
                                                <User className="w-4 h-4 opacity-40 text-primary" /> {sub.author_name}
                                            </span>
                                            <span className="flex items-center gap-2 group-hover:text-foreground transition-colors">
                                                <Calendar className="w-4 h-4 opacity-40 text-primary" /> {new Date(sub.submitted_at).toLocaleDateString(undefined, { dateStyle: 'long' })}
                                            </span>
                                        </div>
                                    </div>
                                </TableCell>
                                <TableCell className="px-8 py-8">
                                    <div className="flex flex-col gap-2 items-center">
                                        <Badge className={`h-9 px-5 text-[10px] font-black tracking-[0.2em] shadow-sm rounded-xl uppercase transition-transform group-hover:scale-105 duration-500 ${getStatusVariant(sub.status)}`}>
                                            {sub.status.replace('_', ' ')}
                                        </Badge>
                                        {sub.status === 'under_review' && sub.completed_reviews > 0 && (
                                            <div className="flex items-center gap-2 text-[10px] font-black text-emerald-600 tracking-[0.2em] bg-emerald-500/5 px-3 py-1 rounded-full border border-emerald-500/10 uppercase animate-pulse">
                                                <MessageSquare className="w-3.5 h-3.5" />
                                                {sub.completed_reviews} PEER-REVIEWS
                                            </div>
                                        )}
                                    </div>
                                </TableCell>
                                <TableCell className="px-8 py-8 text-right">
                                    <div className="flex items-center justify-end gap-3">
                                        <TooltipProvider>
                                            <Tooltip>
                                                <TooltipTrigger asChild>
                                                    <Button asChild className="h-12 px-6 gap-3 bg-primary text-white dark:text-black font-black text-[10px] tracking-[0.2em] rounded-xl shadow-lg shadow-primary/20 hover:scale-[1.05] active:scale-[0.95] transition-all opacity-0 group-hover:opacity-100 translate-x-4 group-hover:translate-x-0 duration-500">
                                                        <Link href={`/${role}/submissions/${sub.id}`}>
                                                            Examine Dossier
                                                        </Link>
                                                    </Button>
                                                </TooltipTrigger>
                                                <TooltipContent className="bg-foreground text-background text-[10px] font-black tracking-widest border-none px-4 py-2 rounded-xl shadow-2xl">
                                                    Action Protocol
                                                </TooltipContent>
                                            </Tooltip>
                                        </TooltipProvider>

                                        <DropdownMenu>
                                            <DropdownMenuTrigger asChild>
                                                <Button variant="ghost" size="icon" className="h-12 w-12 text-primary/30 hover:text-primary rounded-xl transition-all hover:bg-primary/5 cursor-pointer">
                                                    <MoreVertical className="w-6 h-6" />
                                                </Button>
                                            </DropdownMenuTrigger>
                                            <DropdownMenuContent align="end" className="w-64 rounded-3xl p-3 shadow-2xl border-primary/5 bg-white/95 backdrop-blur-xl">
                                                <DropdownMenuItem asChild className="rounded-xl h-14 gap-4 px-5 focus:bg-primary/5 focus:text-primary transition-all">
                                                    <Link href={`/${role}/submissions/${sub.id}`}>
                                                        <FileText className="w-5 h-5 text-primary/40" />
                                                        <div className="flex flex-col">
                                                            <span className="text-xs font-black tracking-widest uppercase">Decision Protocol</span>
                                                            <span className="text-[9px] text-muted-foreground font-bold">Manage Manuscript Lifecycle</span>
                                                        </div>
                                                    </Link>
                                                </DropdownMenuItem>
                                                <Separator className="my-3 bg-primary/5" />
                                                {role === 'admin' && sub.status !== 'published' && (
                                                    <div className="px-1 py-1">
                                                        <DeleteSubmissionButton submissionId={sub.id} status={sub.status} variant="full" />
                                                    </div>
                                                )}
                                                {role === 'editor' && sub.file_path && (
                                                    <DropdownMenuItem asChild className="rounded-xl h-12 gap-4 group">
                                                        <a href={sub.file_path} download className="flex items-center gap-4">
                                                            <div className="w-8 h-8 rounded-lg bg-emerald-500/10 flex items-center justify-center group-hover:bg-emerald-500 transition-colors">
                                                                <Download className="w-4 h-4 text-emerald-600 group-hover:text-white transition-colors" />
                                                            </div>
                                                            <span className="text-xs font-black uppercase tracking-widest text-primary/60 group-hover:text-primary">Download MS</span>
                                                        </a>
                                                    </DropdownMenuItem>
                                                )}
                                            </DropdownMenuContent>
                                        </DropdownMenu>
                                    </div>
                                </TableCell>
                            </TableRow>
                        ))}
                    </TableBody>
                </Table>
            </div>
        </div>
    );
}

"use client";

import { useFieldArray, useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import { useState } from "react";
import {
    Loader2, Upload, CheckCircle2, FileText, User, Mail,
    ChevronRight, BookOpen, Tag, Plus, Trash2, Phone, Briefcase,
    School, Users, Shield, Check, ExternalLink, Download
} from "lucide-react";
import { toast } from "sonner";
import { Button } from "@/components/ui/button";
import {
    Form,
    FormControl,
    FormField,
    FormItem,
    FormLabel,
    FormMessage,
    FormDescription,
} from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Card, CardContent } from "@/components/ui/card";
import { useSubmissionMutation } from "@/hooks/queries/usePublicMutations";
import { useSettings } from "@/hooks/queries/useSettings";
import { Checkbox } from "@/components/ui/checkbox";
import { Badge } from "@/components/ui/badge";
import Link from "next/link";
import { motion, AnimatePresence } from "framer-motion";

const coAuthorSchema = z.object({
    name: z.string().min(2, "Name required"),
    email: z.string().email("Invalid email"),
    phone: z.string().regex(/^[0-9]+$/, "Numbers only"),
    designation: z.string().min(2, "Designation required"),
    institution: z.string().min(2, "Institution required"),
});

const formSchema = z.object({
    title: z.string().min(10, "Title must be at least 10 characters"),
    author_name: z.string().min(2, "Author name must be at least 2 characters"),
    author_email: z.string().email("Invalid email address"),
    author_phone: z.string().regex(/^[0-9]+$/, "Numbers only"),
    author_designation: z.string().min(2, "Designation required"),
    affiliation: z.string().min(5, "Affiliation must be at least 5 characters"),
    abstract: z.string().min(100, "Abstract must be at least 100 characters"),
    keywords: z.string().min(10, "Provide at least 5 keywords"),
    co_authors: z.array(coAuthorSchema).max(5, "Maximum 5 authors allowed").optional(),
    terms_accepted: z.boolean().refine(val => val === true, {
        message: "You must accept the terms and guidelines"
    }),
});

export default function SubmissionForm() {
    const [manuscriptFile, setManuscriptFile] = useState<File | null>(null);
    const [copyrightFile, setCopyrightFile] = useState<File | null>(null);
    const submissionMutation = useSubmissionMutation();
    const { data: settings = {} } = useSettings();

    const form = useForm<z.infer<typeof formSchema>>({
        resolver: zodResolver(formSchema),
        defaultValues: {
            title: "",
            author_name: "",
            author_email: "",
            author_phone: "",
            author_designation: "",
            affiliation: "",
            abstract: "",
            keywords: "",
            co_authors: [],
            terms_accepted: false,
        },
    });

    const { fields, append, remove } = useFieldArray({
        control: form.control,
        name: "co_authors" as const,
    });

    async function onSubmit(values: z.infer<typeof formSchema>) {
        if (!manuscriptFile) {
            toast.error("Manuscript Missing", {
                description: "Primary research document is required."
            });
            return;
        }
        if (!copyrightFile) {
            toast.error("Copyright Form Missing", {
                description: "The signed copyright agreement is mandatory."
            });
            return;
        }

        const formData = new FormData();
        Object.entries(values).forEach(([key, value]) => {
            if (key === "co_authors") {
                formData.append(key, JSON.stringify(value));
            } else if (key === "terms_accepted") {
                formData.append(key, value ? "on" : "off");
            } else {
                formData.append(key, value as string);
            }
        });
        
        formData.append("manuscript", manuscriptFile);
        formData.append("copyright_form", copyrightFile);

        submissionMutation.mutate(formData, {
            onSuccess: () => {
                toast.success("Form submitted check you mail", {
                    className: "bg-linear-to-r from-emerald-500 to-emerald-600 border-none text-white font-black px-6 py-4 rounded-2xl shadow-xl shadow-emerald-500/20",
                });
                form.reset();
                setManuscriptFile(null);
                setCopyrightFile(null);
            }
        });
    }

    if (submissionMutation.isSuccess) {
        return (
            <motion.div 
                initial={{ opacity: 0, scale: 0.95 }}
                animate={{ opacity: 1, scale: 1 }}
                className="flex flex-col items-center justify-center p-8 sm:p-12 text-center space-y-6 bg-white rounded-2xl border border-primary/5 shadow-2xl"
            >
                <div className="w-20 h-20 bg-emerald-50 text-emerald-500 rounded-2xl flex items-center justify-center shadow-inner border border-emerald-100 rotate-3">
                    <CheckCircle2 className="w-10 h-10" />
                </div>
                <div className="space-y-3">
                    <h2 className="text-2xl sm:text-3xl font-black text-primary tracking-tight">Submission <span className="text-emerald-600 underline decoration-emerald-100 underline-offset-8">Successful</span></h2>
                    <p className="text-slate-500 max-w-md mx-auto font-medium text-sm leading-relaxed">
                        Your manuscript has been successfully submitted to the peer-review queue. 
                        Submission ID: <span className="text-primary font-black">{(submissionMutation.data as any)?.paperId}</span>
                    </p>
                </div>
                <Button onClick={() => submissionMutation.reset()} variant="outline" className="h-12 px-8 rounded-xl border-primary/10 text-primary hover:bg-primary/5 font-black text-xs tracking-widest transition-all active:scale-95">
                    Submit Another Paper
                </Button>
            </motion.div>
        );
    }

    const onInvalid = () => {
        toast.error("Please fill missing forms", {
            className: "bg-linear-to-r from-rose-500 to-rose-600 border-none text-white font-black px-6 py-4 rounded-2xl shadow-xl shadow-rose-500/20",
        });
    };

    return (
        <Form {...form}>
            <form onSubmit={form.handleSubmit(onSubmit, onInvalid)} className="space-y-8 sm:space-y-12">
                
                {/* Core Metadata Section */}
                <div className="space-y-6 sm:space-y-8">
                    <FormField
                        control={form.control}
                        name="title"
                        render={({ field }) => (
                            <FormItem className="space-y-3">
                                <div className="flex items-center gap-3 ml-1">
                                    <div className="w-9 h-9 rounded-xl bg-primary/5 border border-primary/10 flex items-center justify-center text-primary shadow-sm">
                                        <FileText className="w-5 h-5" />
                                    </div>
                                    <FormLabel className="text-base 2xl:text-lg font-black text-primary tracking-tight">Paper / Manuscript Title</FormLabel>
                                </div>
                                <FormControl>
                                    <Input
                                        placeholder="Full title of your research paper..."
                                        {...field}
                                        value={field.value ?? ""}
                                        className="h-12 md:h-14 bg-white border-slate-200 rounded-xl font-bold text-primary focus-visible:ring-primary/20 shadow-sm px-5 text-base md:text-lg 2xl:text-xl placeholder:text-slate-500 placeholder:truncate"
                                    />
                            </FormControl>
                                <FormMessage className="text-[10px] 2xl:text-xs font-black tracking-widest text-secondary px-4" />
                            </FormItem>
                        )}
                    />

                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 lg:gap-8">
                        <FormField
                            control={form.control}
                            name="author_name"
                            render={({ field }) => (
                                <FormItem className="space-y-3">
                                    <div className="flex items-center gap-3 ml-1">
                                        <div className="w-9 h-9 rounded-xl bg-primary/5 border border-primary/10 flex items-center justify-center text-primary">
                                            <User className="w-4.5 h-4.5" />
                                        </div>
                                         <FormLabel className="text-xs 2xl:text-sm font-black text-primary tracking-widest">Lead Author Name</FormLabel>
                                    </div>
                                    <FormControl>
                                        <Input
                                            placeholder="Full Name"
                                            {...field}
                                            value={field.value ?? ""}
                                            className="h-12 2xl:h-14 2xl:text-lg bg-white border-slate-200 rounded-xl font-bold text-primary placeholder:text-slate-500 placeholder:truncate focus-visible:ring-primary/20 shadow-sm px-5 text-base"
                                        />
                                    </FormControl>
                                    <FormMessage className="text-[10px] 2xl:text-xs font-black text-secondary px-4" />
                                </FormItem>
                            )}
                        />
                        <FormField
                            control={form.control}
                            name="author_email"
                            render={({ field }) => (
                                <FormItem className="space-y-3">
                                    <div className="flex items-center gap-3 ml-1">
                                        <div className="w-9 h-9 rounded-xl bg-primary/5 border border-primary/10 flex items-center justify-center text-primary">
                                            <Mail className="w-4.5 h-4.5" />
                                        </div>
                                        <FormLabel className="text-xs 2xl:text-sm font-black text-primary tracking-widest">Email Address</FormLabel>
                                    </div>
                                    <FormControl>
                                        <Input
                                            type="email"
                                            placeholder="yourname@gmail.com"
                                            {...field}
                                            value={field.value ?? ""}
                                            className="h-12 2xl:h-14 2xl:text-lg bg-white border-slate-200 placeholder:text-slate-500 placeholder:truncate rounded-xl font-bold text-primary focus-visible:ring-primary/20 shadow-sm px-5 text-base"
                                        />
                                    </FormControl>
                                    <FormMessage className="text-[10px] 2xl:text-xs font-black text-secondary px-4" />
                                </FormItem>
                            )}
                        />
                        <FormField
                            control={form.control}
                            name="author_phone"
                            render={({ field }) => (
                                <FormItem className="space-y-3">
                                    <div className="flex items-center gap-3 ml-1">
                                        <div className="w-9 h-9 rounded-xl bg-primary/5 border border-primary/10 flex items-center justify-center text-primary">
                                            <Phone className="w-4.5 h-4.5" />
                                        </div>
                                        <FormLabel className="text-xs 2xl:text-sm font-black text-primary tracking-widest">Phone Number</FormLabel>
                                    </div>
                                    <FormControl>
                                        <Input
                                            type="tel"
                                            placeholder="Phone Number"
                                            {...field}
                                            value={field.value ?? ""}
                                            className="h-12 2xl:h-14 2xl:text-lg bg-white border-slate-200 placeholder:text-slate-500 placeholder:truncate rounded-xl font-bold text-primary focus-visible:ring-primary/20 shadow-sm px-5 text-base"
                                        />
                                    </FormControl>
                                    <FormMessage className="text-[10px] 2xl:text-xs font-black text-secondary px-4" />
                                </FormItem>
                            )}
                        />
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6 lg:gap-8">
                        <FormField
                            control={form.control}
                            name="author_designation"
                            render={({ field }) => (
                                <FormItem className="space-y-3">
                                    <div className="flex items-center gap-3 ml-1">
                                        <div className="w-9 h-9 rounded-xl bg-primary/5 border border-primary/10 flex items-center justify-center text-primary">
                                            <Briefcase className="w-4.5 h-4.5" />
                                        </div>
                                        <FormLabel className="text-xs 2xl:text-sm font-black text-primary tracking-widest">Designation</FormLabel>
                                    </div>
                                    <FormControl>
                                        <Input
                                            placeholder="e.g., Assistant Professor, Research Scholar"
                                            {...field}
                                            value={field.value ?? ""}
                                            className="h-12 2xl:h-14 2xl:text-lg bg-white border-slate-200 placeholder:text-slate-500 placeholder:truncate rounded-xl font-bold text-primary focus-visible:ring-primary/20 shadow-sm px-5 text-base"
                                        />
                                    </FormControl>
                                    <FormMessage className="text-[10px] 2xl:text-xs font-black text-secondary px-4" />
                                </FormItem>
                            )}
                        />

                        <FormField
                            control={form.control}
                            name="affiliation"
                            render={({ field }) => (
                                <FormItem className="space-y-3">
                                    <div className="flex items-center gap-3 ml-1">
                                        <div className="w-9 h-9 rounded-xl bg-primary/10 border border-primary/20 flex items-center justify-center text-primary shadow-inner">
                                            <School className="w-4.5 h-4.5" />
                                        </div>
                                        <FormLabel className="text-xs 2xl:text-sm font-black text-primary tracking-widest">Affiliation / College / Institute</FormLabel>
                                    </div>
                                    <FormControl>
                                        <Input
                                            placeholder="e.g., Department, University, City, Country"
                                            {...field}
                                            value={field.value ?? ""}
                                            className="h-12 2xl:h-14 2xl:text-lg bg-white border-slate-200 placeholder:text-slate-500 placeholder:truncate rounded-xl font-bold text-primary focus-visible:ring-primary/20 shadow-sm px-5 text-base"
                                        />
                                    </FormControl>
                                    <FormMessage className="text-[10px] 2xl:text-xs font-black text-secondary px-4" />
                                </FormItem>
                            )}
                        />
                    </div>

                    <FormField
                        control={form.control}
                        name="abstract"
                        render={({ field }) => (
                            <FormItem className="space-y-3">
                                <div className="flex items-center gap-3 ml-1">
                                    <div className="w-9 h-9 rounded-xl bg-amber-50 border border-amber-100 flex items-center justify-center text-amber-600 shadow-sm">
                                        <BookOpen className="w-4.5 h-4.5" />
                                    </div>
                                     <FormLabel className="text-xs 2xl:text-sm font-black text-primary tracking-widest">Abstract</FormLabel>
                                </div>
                                <FormControl>
                                    <Textarea
                                        placeholder="Summarize your research paper here..."
                                        className="bg-white border-slate-200 rounded-2xl font-medium placeholder:text-slate-500 placeholder:truncate text-primary focus-visible:ring-primary/20 shadow-sm p-5 resize-none min-h-[200px] text-base 2xl:text-lg leading-relaxed"
                                        {...field}
                                        value={field.value ?? ""}
                                    />
                                </FormControl>
                                <div className="flex justify-between items-center px-4">
                                    <FormDescription className="text-[10px] 2xl:text-xs font-black tracking-widest text-slate-500">Word Count: 100 - 500 Words</FormDescription>
                                    <span className="text-[10px] font-black text-amber-600/60 tracking-widest">{field.value.length} CHARS</span>
                                </div>
                                <FormMessage className="text-[10px] 2xl:text-xs font-black text-secondary px-4" />
                            </FormItem>
                        )}
                    />

                    <FormField
                        control={form.control}
                        name="keywords"
                        render={({ field }) => (
                            <FormItem className="space-y-3">
                                <div className="flex items-center gap-3 ml-1">
                                    <div className="w-9 h-9 rounded-xl bg-indigo-50 border border-indigo-100 flex items-center justify-center text-indigo-600 shadow-sm">
                                        <Tag className="w-4.5 h-4.5" />
                                    </div>
                                     <FormLabel className="text-xs 2xl:text-sm font-black text-primary tracking-widest">Keywords</FormLabel>
                                </div>
                                <FormControl>
                                    <Input
                                        placeholder="e.g., AI, Machine Learning, Metallurgy..."
                                        {...field}
                                        value={field.value ?? ""}
                                        className="h-12 2xl:h-14 2xl:text-lg bg-white border-slate-200 rounded-xl placeholder:text-slate-500 placeholder:truncate font-bold text-primary focus-visible:ring-primary/20 shadow-sm px-5 text-base"
                                    />
                                </FormControl>
                                <FormDescription className="text-[10px] 2xl:text-xs font-black tracking-widest text-slate-500 px-4">Provide at least 5 keywords separated by commas.</FormDescription>
                                <FormMessage className="text-[10px] 2xl:text-xs font-black text-secondary px-4" />
                            </FormItem>
                        )}
                    />
                </div>

                {/* Co-Authors - Visual Polish */}
                <div className="space-y-8 pt-12 border-t border-slate-100">
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-4">
                            <div className="w-12 h-12 rounded-[1.25rem] bg-slate-50 text-slate-400 flex items-center justify-center shadow-inner border border-slate-100">
                                <Users className="w-6 h-6" />
                            </div>
                            <h3 className="text-lg font-black text-primary tracking-tight">Co-Authors</h3>
                        </div>
                        <Button
                            type="button"
                            variant="outline"
                            onClick={() => append({ name: "", email: "", phone: "", designation: "", institution: "" })}
                            disabled={fields.length >= 5}
                            className="h-11 px-6 rounded-xl border-primary/10 text-primary font-black text-[10px] tracking-widest hover:bg-primary hover:text-white transition-all shadow-sm active:scale-95"
                        >
                            <Plus className="w-4 h-4 mr-2" />
                            Add Co-Author
                        </Button>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        <AnimatePresence>
                            {fields.map((field, index) => (
                                <motion.div
                                    key={field.id}
                                    initial={{ opacity: 0, y: 20 }}
                                    animate={{ opacity: 1, y: 0 }}
                                    exit={{ opacity: 0, scale: 0.95 }}
                                    transition={{ duration: 0.3 }}
                                >
                                    <Card className="group relative bg-slate-50/50 border-white shadow-xl rounded-2xl overflow-hidden transition-all hover:shadow-2xl hover:bg-white p-1">
                                        <Button
                                            type="button"
                                            variant="ghost"
                                            size="icon"
                                            onClick={() => remove(index)}
                                            className="absolute top-4 right-4 text-secondary hover:bg-secondary hover:scale-90 rounded-xl transition-all z-20"
                                        >
                                            <Trash2 className="w-4.5 h-4.5" />
                                        </Button>

                                        <CardContent className="p-6 sm:p-8 space-y-6">
                                            <div className="flex items-center gap-4">
                                                <div className="w-12 h-12 rounded-2xl bg-white shadow-md border border-slate-100 flex items-center justify-center text-primary font-black text-base">
                                                    {index + 1}
                                                </div>
                                                <div className="space-y-1">
                                                    <h4 className="font-black text-primary tracking-widest text-sm">Author Details</h4>
                                                    <p className="text-[10px] 2xl:text-xs font-bold text-slate-400">Enter co-author information</p>
                                                </div>
                                            </div>

                                            <div className="space-y-4">
                                                <FormField
                                                    control={form.control}
                                                    name={`co_authors.${index}.name`}
                                                    render={({ field }) => (
                                                        <FormItem>
                                                            <FormControl>
                                                                 <Input placeholder="Full Name" {...field} value={field.value ?? ""} className="h-11 2xl:h-14 2xl:text-base bg-white border-slate-100 rounded-xl font-bold shadow-sm px-5 placeholder:truncate" />
                                                            </FormControl>
                                                            <FormMessage />
                                                        </FormItem>
                                                    )}
                                                />
                                                <FormField
                                                    control={form.control}
                                                    name={`co_authors.${index}.email`}
                                                    render={({ field }) => (
                                                        <FormItem>
                                                            <FormControl>
                                                                <Input type="email" placeholder="E-Mail Address" {...field} value={field.value ?? ""} className="h-11 2xl:h-14 2xl:text-base bg-white border-slate-100 rounded-xl font-bold shadow-sm px-5 placeholder:truncate" />
                                                            </FormControl>
                                                            <FormMessage />
                                                        </FormItem>
                                                    )}
                                                />
                                                <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                                                    <FormField
                                                        control={form.control}
                                                        name={`co_authors.${index}.phone`}
                                                        render={({ field }) => (
                                                            <FormItem>
                                                                <FormControl>
                                                                    <Input type="tel" placeholder="Phone no" {...field} value={field.value ?? ""} className="h-11 2xl:h-14 2xl:text-base bg-white border-slate-100 rounded-xl font-bold shadow-sm px-5 placeholder:truncate" />
                                                                </FormControl>
                                                                <FormMessage />
                                                            </FormItem>
                                                        )}
                                                    />
                                                    <FormField
                                                        control={form.control}
                                                        name={`co_authors.${index}.designation`}
                                                        render={({ field }) => (
                                                            <FormItem>
                                                                <FormControl>
                                                                    <Input placeholder="Designation" {...field} value={field.value ?? ""} className="h-11 2xl:h-14 2xl:text-base bg-white border-slate-100 rounded-xl font-bold shadow-sm px-5 placeholder:truncate" />
                                                                </FormControl>
                                                                <FormMessage />
                                                            </FormItem>
                                                        )}
                                                    />
                                                </div>
                                                <FormField
                                                    control={form.control}
                                                    name={`co_authors.${index}.institution`}
                                                    render={({ field }) => (
                                                        <FormItem>
                                                            <FormControl>
                                                                <Input placeholder="Institution / Organization" {...field} value={field.value ?? ""} className="h-11 2xl:h-14 2xl:text-base bg-white border-slate-100 rounded-xl font-bold shadow-sm px-5 placeholder:truncate" />
                                                            </FormControl>
                                                            <FormMessage />
                                                        </FormItem>
                                                    )}
                                                />
                                            </div>
                                        </CardContent>
                                    </Card>
                                </motion.div>
                            ))}
                        </AnimatePresence>
                    </div>

                    {fields.length === 0 && (
                        <div className="py-12 border-2 border-dashed border-slate-100 rounded-2xl bg-slate-50/20 flex flex-col items-center justify-center text-center px-6 transition-all hover:bg-slate-50/40">
                             <div className="w-14 h-14 bg-white rounded-2xl flex items-center justify-center text-slate-200 mb-4 shadow-sm border border-slate-50">
                                <Users className="w-7 h-7" />
                            </div>
                            <h4 className="text-xs font-black text-slate-500 tracking-[0.2em] mb-1">Single Author Submission</h4>
                            <p className="text-xs text-slate-400 font-medium max-w-xs leading-relaxed">
                                You are submitting as a single author. You may add up to 5 additional authors above.
                            </p>
                        </div>
                    )}
                </div>

                {/* Upload Infrastructure - Dual Uploads */}
                <div className="pt-10 border-t border-slate-100">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8 lg:gap-12">
                        {/* Manuscript Upload */}
                        <div className="space-y-6">
                            <div className="flex items-center justify-between gap-4 ml-1">
                                <div className="flex items-center gap-4">
                                    <div className="w-12 h-12 rounded-[1.25rem] bg-blue-50 text-blue-600 flex items-center justify-center shadow-sm border border-blue-100">
                                        <FileText className="w-6 h-6" />
                                    </div>
                                    <div className="space-y-1">
                                        <FormLabel className="text-base 2xl:text-lg font-black text-primary tracking-tight"></FormLabel>
                                        <p className="text-[10px] 2xl:text-xs font-bold text-slate-400 tracking-widest">Upload your research paper file</p>
                                    </div>
                                </div>
                                {settings.template_url && (
                                    <Button asChild variant="ghost" size="sm" className="text-blue-600 font-black text-[9px] tracking-widest hover:bg-primary">
                                        <a href={settings.template_url} download>
                                            <Download className="w-3.5 h-3.5 mr-2" />
                                            Get Template
                                        </a>
                                    </Button>
                                )}
                            </div>
                            
                            <div className="relative group/upload">
                                <input
                                    type="file"
                                    onChange={(e) => setManuscriptFile(e.target.files?.[0] || null)}
                                    className="hidden"
                                    id="manuscript-upload"
                                    accept=".doc,.docx,.pdf"
                                />
                                <label
                                    htmlFor="manuscript-upload"
                                    className={`flex flex-col items-center justify-center w-full min-h-[250px] border-2 border-dashed rounded-2xl transition-all duration-700 cursor-pointer shadow-vip relative overflow-hidden bg-white ${manuscriptFile
                                        ? 'border-blue-400 bg-blue-50/10'
                                        : 'border-slate-200 hover:border-blue-300 hover:bg-blue-50/30'
                                        }`}
                                >
                                    {manuscriptFile ? (
                                        <div className="text-center px-8 relative z-10 animate-in fade-in zoom-in slide-in-from-bottom-4 duration-700">
                                            <div className="w-20 h-20 bg-blue-500 text-white rounded-3xl flex items-center justify-center mx-auto mb-6 shadow-2xl rotate-2 transition-transform hover:rotate-0">
                                                <Check className="w-10 h-10" />
                                            </div>
                                            <p className="text-xl font-black text-primary truncate max-w-[280px] mb-2">{manuscriptFile.name}</p>
                                            <p className="text-[10px] 2xl:text-xs font-black text-blue-600/60 tracking-[0.2em] mb-4">File Selected • Manuscript</p>
                                            <Badge variant="secondary" className="bg-blue-100 text-blue-700 hover:bg-blue-100 border-none px-4 py-2 rounded-xl text-[10px] font-black tracking-widest cursor-pointer">
                                                Change File
                                            </Badge>
                                        </div>
                                    ) : (
                                        <div className="text-center relative z-10 transition-all group-hover/upload:scale-110">
                                            <div className="w-20 h-20 bg-white border border-slate-100 rounded-3xl shadow-xl flex items-center justify-center mx-auto mb-8 transition-all duration-700 group-hover/upload:shadow-blue-500/10 group-hover/upload:-translate-y-2">
                                                <Upload className="w-8 h-8 text-blue-500" />
                                            </div>
                                            <p className="text-sm 2xl:text-base font-black tracking-[0.2em] text-primary mb-2">Upload Manuscript</p>
                                            <p className="text-[10px] 2xl:text-xs font-black text-slate-500 tracking-widest">Word (.docx) or PDF format</p>
                                        </div>
                                    )}
                                    <div className="absolute bottom-0 left-0 w-full h-1.5 bg-blue-500/10" />
                                </label>
                            </div>
                        </div>

                        {/* Copyright Upload */}
                        <div className="space-y-6">
                            <div className="flex items-center justify-between gap-4 ml-1">
                                <div className="flex items-center gap-4">
                                    <div className="w-12 h-12 rounded-[1.25rem] bg-indigo-50 text-indigo-600 flex items-center justify-center shadow-sm border border-indigo-100">
                                        <Shield className="w-6 h-6" />
                                    </div>
                                    <div className="space-y-1">
                                        <FormLabel className="text-base 2xl:text-lg font-black text-primary tracking-tight"></FormLabel>
                                        <p className="text-[10px] 2xl:text-xs font-bold text-slate-400 tracking-widest">Signed copyright agreement</p>
                                    </div>
                                </div>
                                {settings.copyright_url && (
                                    <Button asChild variant="ghost" size="sm" className="text-indigo-600 font-black text-[9px] tracking-widest hover:bg-primary">
                                        <a href={settings.copyright_url} download>
                                            <Download className="w-3.5 h-3.5 mr-2" />
                                            Download form
                                        </a>
                                    </Button>
                                )}
                            </div>
                            
                            <div className="relative group/upload">
                                <input
                                    type="file"
                                    onChange={(e) => setCopyrightFile(e.target.files?.[0] || null)}
                                    className="hidden"
                                    id="copyright-upload"
                                    accept=".doc,.docx,.pdf"
                                />
                                <label
                                    htmlFor="copyright-upload"
                                    className={`flex flex-col items-center justify-center w-full min-h-[250px] border-2 border-dashed rounded-2xl transition-all duration-700 cursor-pointer shadow-vip relative overflow-hidden bg-white ${copyrightFile
                                        ? 'border-indigo-400 bg-indigo-50/10'
                                        : 'border-slate-200 hover:border-indigo-300 hover:bg-indigo-50/30'
                                        }`}
                                >
                                    {copyrightFile ? (
                                        <div className="text-center px-8 relative z-10 animate-in fade-in zoom-in slide-in-from-bottom-4 duration-700">
                                            <div className="w-20 h-20 bg-indigo-500 text-white rounded-3xl flex items-center justify-center mx-auto mb-6 shadow-2xl -rotate-2 transition-transform hover:rotate-0">
                                                <Shield className="w-10 h-10" />
                                            </div>
                                            <p className="text-xl font-black text-primary truncate max-w-[280px] mb-2">{copyrightFile.name}</p>
                                            <p className="text-[10px] 2xl:text-xs font-black text-indigo-600/60 tracking-[0.2em] mb-4">File Selected • Copyright Form</p>
                                            <Badge variant="secondary" className="bg-indigo-100 text-indigo-700 hover:bg-indigo-100 border-none px-4 py-2 rounded-xl text-[10px] font-black tracking-widest cursor-pointer">
                                                Change File
                                            </Badge>
                                        </div>
                                    ) : (
                                        <div className="text-center relative z-10 transition-all group-hover/upload:scale-110">
                                            <div className="w-20 h-20 bg-white border border-slate-100 rounded-3xl shadow-xl flex items-center justify-center mx-auto mb-8 transition-all duration-700 group-hover/upload:shadow-indigo-500/10 group-hover/upload:-translate-y-2">
                                                <Upload className="w-8 h-8 text-indigo-500" />
                                            </div>
                                            <p className="text-sm 2xl:text-base font-black tracking-[0.2em] text-primary mb-2">Upload Copyright Form</p>
                                            <p className="text-[10px] 2xl:text-xs font-black text-slate-500 tracking-widest">Signed Word or PDF file</p>
                                        </div>
                                    )}
                                    <div className="absolute bottom-0 left-0 w-full h-1.5 bg-indigo-500/10" />
                                </label>
                            </div>
                        </div>
                    </div>
                </div>

                {/* Terms and Submission Control */}
                <div className="space-y-8 pt-10 border-t border-slate-100">
                    <FormField
                        control={form.control}
                        name="terms_accepted"
                        render={({ field }) => (
                            <FormItem className="flex flex-row items-center space-x-4 space-y-0 p-6 rounded-2xl bg-indigo-50/30 border border-indigo-100 shadow-inner group/terms transition-all hover:bg-indigo-50/50">
                                <FormControl>
                                    <Checkbox
                                        checked={!!field.value}
                                        onCheckedChange={field.onChange}
                                        className="w-6 h-6 rounded-lg border-2 border-indigo-200 data-[state=checked]:bg-indigo-600 data-[state=checked]:border-indigo-600 transition-all group-hover/terms:scale-110"
                                    />
                                </FormControl>
                                <div className="space-y-1.5 m-0!">
                                    <div className="flex flex-wrap items-center gap-x-2 gap-y-1">
                                        <span className="text-xs 2xl:text-sm font-black text-primary tracking-tight">I hereby verify that I have read the</span>
                                        <Link href="/guidelines" target="_blank" className="text-xs 2xl:text-sm font-black text-indigo-600 hover:text-indigo-800 underline decoration-indigo-200 underline-offset-4 group/link flex items-center gap-1 transition-all">
                                            Author Guidelines
                                            <ExternalLink className="w-3 h-3 group-hover/link:translate-x-0.5 transition-transform" />
                                        </Link>
                                        <span className="text-xs 2xl:text-sm font-black text-primary tracking-tight">and the</span>
                                        <Link href="/guidelines#terms" target="_blank" className="text-xs 2xl:text-sm font-black text-indigo-600 hover:text-indigo-800 underline decoration-indigo-200 underline-offset-4 group/link flex items-center gap-1 transition-all">
                                            Terms of Use.
                                            <ExternalLink className="w-3 h-3 group-hover/link:translate-x-0.5 transition-transform" />
                                        </Link>
                                    </div>
                                    <p className="text-[10px] 2xl:text-xs font-bold text-slate-500 tracking-widest">I confirm that I am submitting original work and following all guidelines.</p>
                                </div>
                                <FormMessage className="text-[10px] 2xl:text-xs font-black text-secondary px-4" />
                            </FormItem>
                        )}
                    />

                    <Button
                        type="submit"
                        disabled={submissionMutation.isPending}
                        className="w-full h-14 md:h-16 2xl:h-20 bg-primary text-white font-black text-xs sm:text-sm 2xl:text-base tracking-[0.2em] 2xl:tracking-[0.3em] rounded-xl md:rounded-2xl shadow-xl shadow-primary/20 transition-all duration-500 hover:scale-[1.01] hover:shadow-primary/30 active:scale-[0.99] group/submit relative overflow-hidden"
                    >
                        {submissionMutation.isPending ? (
                            <div className="flex items-center gap-4">
                                <Loader2 className="w-6 h-6 animate-spin" />
                                SUBMITTING MANUSCRIPT...
                            </div>
                        ) : (
                            <div className="flex items-center gap-4 relative z-10">
                                SUBMIT PAPER
                                <ChevronRight className="w-6 h-6 group-hover/submit:translate-x-2 transition-transform" />
                            </div>
                        )}
                        <div className="absolute inset-0 bg-white/10 opacity-0 group-hover/submit:opacity-100 transition-opacity" />
                    </Button>
                </div>
            </form>
        </Form>
    );
}

'use client';

import { useQuery } from '@tanstack/react-query';
import { getPublishedPapers, getLatestIssuePapers, getArchivePapers } from '@/actions/archives';
import { trackManuscript } from '@/actions/track';
import { getLatestPublishedIssue } from '@/actions/publications';
import { getEditorialBoard } from '@/actions/users';
import { type PublishedPaperUI, type UserWithProfile } from '@/db/types';

export const publicKeys = {
    all: ['public'] as const,
    archives: () => [...publicKeys.all, 'archives'] as const,
    currentIssue: () => [...publicKeys.all, 'current-issue-papers'] as const,
    archivePapers: () => [...publicKeys.all, 'archive-papers'] as const,
    latestIssue: () => [...publicKeys.all, 'latest-issue'] as const,
    editorialBoard: () => [...publicKeys.all, 'editorial-board'] as const,
    track: (paperId: string, email: string) => [...publicKeys.all, 'track', paperId, email] as const,
};

export function useEditorialBoard(initialData?: UserWithProfile[]) {
    return useQuery({
        queryKey: publicKeys.editorialBoard(),
        queryFn: () => getEditorialBoard(),
        select: (res) => res.success ? res.data : [],
