import fs from "fs/promises";
import path from "path";

/**
 * Safely deletes a file from the public directory.
 * @param relativePath The path relative to the public folder (e.g., "/uploads/submissions/file.pdf")
 */
export async function safeDeleteFile(relativePath: string | null | undefined) {
    if (!relativePath || !relativePath.startsWith('/')) return;

    try {
        const absolutePath = path.join(process.cwd(), "public", relativePath);

        // Check if file exists before trying to delete
        try {
            await fs.access(absolutePath);
            await fs.unlink(absolutePath);
            console.log(`Successfully deleted file: ${absolutePath}`);
        } catch (accessError: any) {
            if (accessError.code === 'ENOENT') {
                // File already doesn't exist, which is fine
                return;
            }
            throw accessError;
        }
    } catch (error) {
        console.error(`Error deleting file ${relativePath}:`, error);
    }
}

import nodemailer from 'nodemailer';


const transporter = nodemailer.createTransport({
    host: process.env.SMTP_HOST,
    port: parseInt(process.env.SMTP_PORT || '465'),
    secure: true, // true for 465, false for other ports
    auth: {
        user: process.env.SMTP_USER,
        pass: process.env.SMTP_PASS,
    },
});

interface SendEmailProps {
    to: string;
    subject: string;
    text?: string;
    html?: string;
}

export async function sendEmail({ to, subject, text, html }: SendEmailProps) {
    try {
        const info = await transporter.sendMail({
            from: `"${process.env.EMAIL_FROM_NAME || 'IJITEST Editor'}" <${process.env.EMAIL_FROM}>`,
            to,
            subject,
            text,
            html,
        });

        console.log("Message sent: %s", info.messageId);
        return { success: true, messageId: info.messageId };
    } catch (error: any) {
        console.error("--- SMTP Error Diagnosis ---");
        console.error("Host:", process.env.SMTP_HOST);
        console.error("User:", process.env.SMTP_USER);
        console.error("Error Code:", error?.code);
        console.error("SMTP Response:", error?.response);
        console.error("---------------------------");
        return { success: false, error: error instanceof Error ? error.message : String(error) };
    }
}

